        />
      )}
      {linkRefineRequest && linkRefineRequest.kind === 'excerpt' && linkPickerSource && (
        <LetterExcerptPickerScreen
          refineRequest={linkRefineRequest}
          sourceKey={linkPickerSource.key} sourceLabel={linkPickerSource.label}
          sourceStart={linkPickerSource.start} sourceEnd={linkPickerSource.end}
          sourceText={linkPickerSource.text}
          setHlTick={setHlTick}
          returnTargetInsteadOfLink={!!linkPickerMode}
          onClose={(result) => {
            if (linkPickerMode) {
              if (result && linkPickerOnPickRef.current) linkPickerOnPickRef.current(result);
              if (result) { closeLinkPicker(); } else { setLinkRefineRequest(null); }
              return;
            }
            setLinkRefineRequest(null);
            if (result) setLastLinkCreated(result);
          }}
        />
      )}
      {noteSheetTarget && (
        <NoteSheet
          // key forces a remount whenever the target group OR the edit-mode
          // intent changes — otherwise the internal `useState(startInEditMode ?
          // 'edit' : 'read')` captures the first prop value and never updates,
          // so opening a fresh note in edit mode after reading another note
          // would silently land in read mode.
          key={noteSheetTarget.groupId + ':' + (noteSheetTarget.startInEditMode ? 'edit' : 'read')}
          groupId={noteSheetTarget.groupId}
          startInEditMode={noteSheetTarget.startInEditMode}
          hlTick={hlTick} setHlTick={setHlTick} onClose={closeNoteSheet}
          onOpenNotebookPicker={(gid) => setNotebookPickerTarget(gid)}
        />
      )}
      {notebookPickerTarget && (
        <NotebookPickerSheet
          groupId={notebookPickerTarget}
          hlTick={hlTick} setHlTick={setHlTick}
          onClose={() => setNotebookPickerTarget(null)}
        />
      )}
      {multiNotePayload && (
        <MultiNotePopover
          payload={multiNotePayload}
          onClose={() => setMultiNotePayload(null)}
          onPick={(gid) => { setMultiNotePayload(null); setNoteSheetTarget({ groupId: gid, startInEditMode: false }); }}
        />
      )}
      {bookmarkPopoverPayload && (
        <BookmarkPopover
          // BookmarkPopover's signature is ({ bkmIds, x, y, onClose,
          // onNavigate, onDeleteDone }) — pass the unpacked payload, not a
          // `payload` prop. (Pre-2026-05-20 this render passed `payload` +
          // `onNavigateToSource`, which the component never read, so the
          // popover silently returned null. Fixed: real props now.)
          bkmIds={bookmarkPopoverPayload.bkmIds}
          x={bookmarkPopoverPayload.x}
          y={bookmarkPopoverPayload.y}
          onNavigate={(bkm) => {
            // Resolve the bookmark's source hlKey to an endpoint, then route
            // through navigateToLink so the back-pill is wired. Mirrors the
            // BookmarkCreateSheet "Open Source" path below.
            const endpoint = (typeof _bookmarkSourceEndpoint === 'function') ? _bookmarkSourceEndpoint(bkm.hlKey) : null;
            setBookmarkPopoverPayload(null);
            if (endpoint) navigateToLink(endpoint, { sourceLetterTitle: 'Bookmark' });
          }}
          onDeleteDone={() => setHlTick(t => t + 1)}
          onClose={() => setBookmarkPopoverPayload(null)}
        />
      )}
      {/* BookmarkCreateSheet — pre-commit form for new bookmarks. Opens
          from SelectionToolbar's Bookmark action and from the chapter-
          bookmark NavButton (both via window.__bookmarkCreate). Saving
          commits to BookmarkStore + bumps hlTick so the inline icon
          pulse fires on the source passage. */}
      {/* Journal inbound sheet — triggered by tapping the journal chip in
          letter/chapter nav (or anywhere else that calls __openJournalInbound). */}
      {inboundJournalPayload && typeof JournalInboundSheet !== 'undefined' && (
        <JournalInboundSheet
          refKey={inboundJournalPayload.refKey}
          resourceLabel={inboundJournalPayload.label}
          onClose={() => setInboundJournalPayload(null)}
          onOpenEntry={(entry) => {
            setInboundJournalPayload(null);
            if (entry && entry.id) goJournalViewer(entry.id);
          }}
        />
      )}

      {bookmarkCreatePending && (
        <BookmarkCreateSheet
          pending={bookmarkCreatePending}
          onCancel={() => setBookmarkCreatePending(null)}
          onConfirm={(bkm) => {
            if (!bkm || !bkm.hlKey) { setBookmarkCreatePending(null); return; }
            if (bkm.editId) {
              // EDIT mode — update existing record.
              BookmarkStore.update(bkm.editId, { label: bkm.label, thought: bkm.thought || '' });
            } else {
              // CREATE mode — insert new.
              BookmarkStore.add({
                id: (typeof bkmId === 'function') ? bkmId() : ('bkm_' + Date.now()),
                hlKey: bkm.hlKey,
                label: bkm.label,
                thought: bkm.thought || '',
                created: Date.now(),
                updated: Date.now()
              });
            }
            setBookmarkCreatePending(null);
            setHlTick(t => t + 1);
          }}
          onDelete={(editId) => {
            if (editId && typeof BookmarkStore !== 'undefined') BookmarkStore.remove(editId);
            setBookmarkCreatePending(null);
            setHlTick(t => t + 1);
          }}
          onOpen={(editId) => {
            if (!editId) return;
            const bkm = BookmarkStore.get(editId);
            if (!bkm) { setBookmarkCreatePending(null); return; }
            // Navigate to the bookmark's source. Mirror BookmarkPopover's nav path.
            const endpoint = (typeof _bookmarkSourceEndpoint === 'function') ? _bookmarkSourceEndpoint(bkm.hlKey) : null;
            setBookmarkCreatePending(null);
            if (endpoint) navigateToLink(endpoint, { sourceLetterTitle: 'Bookmark' });
          }}
        />
      )}
    </TabsContext.Provider>
  );

}

export { App };

/* ═══════════════════════════════════════════════════════════════════════
   useAndroidBack — the Android hardware/gesture back-navigation handler
   ═══════════════════════════════════════════════════════════════════════
   Global-scope module. Bundled into dist/bundle-b.js. The LAST P6 hook.

   Wires window.handleAndroidBack — the function Kotlin's MainActivity
   calls via evaluateJavascript() on every hardware-back / predictive-back
   gesture. It returns "true" (JS consumed the event) or "false" (let
   Android handle it — i.e. exit the app). It is also called by the
   in-app back affordance on Letter/WTLB views (onBack prop).

   ┌─ ROUTING TABLE — what back does, in priority order ───────────────────┐
   │  1. an open sheet (window.__closeSheet)   → close it                  │
   │  2. the Tabs Overview overlay             → close it                  │
   │  3. a LETTER_SCREEN_SET screen with a     → pop the tap-through stack, │
   │     non-empty fromLetter stack              restore the source        │
   │  4. settings / history / about            → goNavOrigin (about also   │
   │                                             marks vot-about-seen)     │
   │  5. notes/links/bookmarks/highlights-index → library                  │
   │     · journal-home                        → library                  │
   │     · journal-viewer                      → journal-home              │
   │     · journal-editor                      → goJournalViewer           │
   │  6. library                               → goHome                   │
   │  7. search                                → goSearchOrigin            │
   │  8. scripture-genre                       → goScripturesHome          │
   │  9. scriptures-home / volumes-home        → goHome                    │
   │ 10. matthew-ch / -idx, bible-study-* ,     → context-aware (fromSearch │
   │     bible-ch / -idx                          / fromStudies / fromWtlb │
   │                                              / single-chapter book …) │
   │ 11. a letter screen (COL_BY_LETTER_SC)    → fromMatthew / fromSearch  │
   │                                             / fromStudies / index     │
   │ 12. an index screen / garden-view         → goVolumesHome             │
   │ 13. anything else                         → "false" (Android exits)   │
   └───────────────────────────────────────────────────────────────────────┘

   OWNS:
     - window.handleAndroidBack    wired in a []-deps effect, with a
                                   `delete` cleanup (invariant 6).
     - 9 useRefMirror refs the handler reads at call time (screen, bookId,
       genreId, fromSearch, fromStudies, fromMatthewCh, studyId, fromWtlb,
       tabsOverviewOpen). They are created HERE from the value params —
       App() no longer carries the 8 that were handleAndroidBack-only;
       it keeps its own fromMatthewChRef (still used elsewhere) and this
       hook just makes a second, private mirror of the same value.

   DOES NOT OWN:
     - the nav-helper functions (goNavOrigin, goHome, goSearchOrigin,
       goScripturesHome, goStudiesHome, goVolumesHome, goJournalViewer) —
       App()-local glue that closes over many hook returns; received as
       params. This is why useAndroidBack has a deliberately WIDE param
       surface — it is the most-coupled handler in the app; a tidy
       narrow signature would be a lie.
     - cancelDwell (useReadingDwell), fromLetterRef + setFromLetterStack
       (useFromLetterStack), the nav setters (useTabs) — all params.
     - LETTER_SCREEN_SET / COL_BY_LETTER_SC / COL_BY_INDEX_SC / BOOKS /
       getStudyById — module globals, used by bare name.

   FIXED HERE — a pre-existing stale-closure bug, surfaced by the P6l
   recon and fixed in the immediate follow-up:
     `journalEntryId` was read by the handler directly from the param,
     captured by this hook's []-deps effect closure at mount — when
     journalEntryId is null. Back from `journal-editor` therefore ran
     goJournalViewer(null), which the `if (eid)` guard turned into a
     no-op. The bug predated P6l (the original App() effect had the
     same []-deps stale capture). Fix: journalEntryId is now mirrored
     via useRefMirror like the other 9 nav reads, and the handler reads
     journalEntryIdRef.current — fresh at every back-press.

   PARAMS — a deliberately WIDE bag (see DOES NOT OWN). Every key, by source:
     screen, bookId, genreId, studyId, fromSearch, fromStudies,
       fromMatthewCh, fromWtlb        — useTabs via tabField; mirrored here
                                        through useRefMirror for call-time
                                        reads (the []-deps effect closure
                                        would otherwise freeze them).
     tabsOverviewOpen                 — App()-local state; also mirrored.
     journalEntryId                   — App()-local useState; mirrored (the
                                        journalEntryIdRef fix — see above).
     fromLetterRef                    — useFromLetterStack (already a ref).
     setScreen, setBookId, setChapterNum, setLetterId, setStudyId,
       setStudyChapterId, setFromSearch, setFromStudies, setFromWtlb,
       setFromMatthewCh               — useTabs via tabField setters.
     setFromLetterStack               — useFromLetterStack.
     setTabsOverviewOpen              — App()-local state setter.
     cancelDwell                      — useReadingDwell.
     goNavOrigin, goHome, goSearchOrigin, goScripturesHome, goStudiesHome,
       goVolumesHome, goJournalViewer — App()-local nav-helper glue.

   RETURNS: nothing — pure side-effect hook.

   STORAGE: writes localStorage 'vot-about-seen' on back-from-about.

   WINDOW:
     handleAndroidBack — the Kotlin-callable back router; wired in a
       []-deps effect, cleanup `delete window.handleAndroidBack`.
     Reads but does NOT own: window.__closeSheet (calls it, then nulls it —
       owned by whichever sheet set it) and window.__pendingHighlight
       (writes `= null` — a one-shot data slot, not a handler bridge).
   ═══════════════════════════════════════════════════════════════════════ */

import { useRefMirror } from './use-ref-mirror.js';

export function useAndroidBack({
  screen, bookId, genreId, fromSearch, fromStudies, fromMatthewCh, studyId, fromWtlb,
  tabsOverviewOpen, journalEntryId, fromLetterRef,
  setScreen, setBookId, setChapterNum, setLetterId, setStudyId, setStudyChapterId,
  setFromLetterStack, setFromSearch, setFromStudies, setFromWtlb, setFromMatthewCh,
  setTabsOverviewOpen,
  cancelDwell, goNavOrigin, goHome, goSearchOrigin, goScripturesHome,
  goStudiesHome, goVolumesHome, goJournalViewer,
}) {
  // Call-time mirrors — handleAndroidBack reads the LATEST nav state when
  // the user presses back, not the value frozen into its []-deps closure.
  const screenRef = useRefMirror(screen);
  const bookIdRef = useRefMirror(bookId);
  const genreIdRef = useRefMirror(genreId);
  const fromSearchRef = useRefMirror(fromSearch);
  const fromStudiesRef = useRefMirror(fromStudies);
  const fromMatthewChRef = useRefMirror(fromMatthewCh);
  const studyIdRef = useRefMirror(studyId);
  const fromWtlbRef = useRefMirror(fromWtlb);
  const tabsOverviewOpenRef = useRefMirror(tabsOverviewOpen);
  const journalEntryIdRef = useRefMirror(journalEntryId);

  // All letter-style screens that can be a tap-through destination. When
  // the user entered via an in-app footnote link, Android back pops the
  // top of the fromLetter stack and returns to the source. Includes
  // bible-study-chapter so tap-throughs INTO a study unwind correctly.
  React.useEffect(() => {
    window.handleAndroidBack = () => {
      if (window.__closeSheet) {window.__closeSheet();window.__closeSheet = null;return "true";}
      if (tabsOverviewOpenRef.current) {
        setTabsOverviewOpen(false);
        return "true";
      }
      cancelDwell();
      const s = screenRef.current;
      const stack = fromLetterRef.current;
      if (LETTER_SCREEN_SET.has(s) && stack && stack.length > 0) {
        const fl = stack[stack.length - 1];
        setFromLetterStack((prev) => prev.slice(0, -1));
        window.__pendingHighlight = null;
        if (fl.sourceBookId !== undefined) setBookId(fl.sourceBookId);
        if (fl.sourceChapterNum !== undefined) setChapterNum(fl.sourceChapterNum);
        if (fl.sourceLetterId !== undefined) setLetterId(fl.sourceLetterId);
        if (fl.sourceStudyId !== undefined) setStudyId(fl.sourceStudyId);
        if (fl.sourceStudyChapterId !== undefined) setStudyChapterId(fl.sourceStudyChapterId);
        setScreen(fl.sourceScreen);
        return "true";
      }
      if (s === "settings") {goNavOrigin();return "true";} else
      if (s === "history") {goNavOrigin();return "true";} else
      if (s === "about") {try{localStorage.setItem('vot-about-seen','1');}catch(e){}goNavOrigin();return "true";} else
      if (s === "notes-index") {setScreen("library");return "true";} else
      if (s === "links-index") {setScreen("library");return "true";} else
      if (s === "bookmarks-index") {setScreen("library");return "true";} else
      if (s === "highlights-index") {setScreen("library");return "true";} else
      if (s === "journal-home") {setScreen("library");return "true";} else
      if (s === "journal-viewer") {setScreen("journal-home");return "true";} else
      if (s === "journal-editor") {goJournalViewer(journalEntryIdRef.current);return "true";} else
      if (s === "library") {goHome();return "true";} else
      if (s === "search") {goSearchOrigin();return "true";} else
      if (s === "scripture-genre") {goScripturesHome();return "true";} else
      if (s === "scriptures-home") {goHome();return "true";} else
      if (s === "volumes-home") {goHome();return "true";} else
      if (s === "matthew-ch") {if (fromSearchRef.current) {setFromSearch(false);setScreen("search");} else {setChapterNum(null);setScreen("matthew-idx");}return "true";} else
      if (s === "matthew-idx") {if (fromStudiesRef.current) {setFromStudies(false);goStudiesHome();} else {goHome();}return "true";} else
      if (s === "studies-home") {goHome();return "true";} else
      if (s === "bible-study-index") {goStudiesHome();return "true";} else
      if (s === "bible-study-chapter") {if (fromSearchRef.current) {setFromSearch(false);setScreen("search");return "true";}const cur = getStudyById(studyIdRef.current);if (cur && cur.chapters && cur.chapters.length > 1) {setStudyChapterId(null);setScreen("bible-study-index");} else {goStudiesHome();}return "true";} else
      if (s === "bible-ch") {if (fromWtlbRef.current) {const ret = fromWtlbRef.current;setFromWtlb(null);setScreen(ret);return "true";}if (fromSearchRef.current) {setFromSearch(false);setScreen("search");} else {const bid = bookIdRef.current;if (bid && BOOKS[bid]?.chapters.length === 1) {if (genreIdRef.current) {setScreen("scripture-genre");} else {goScripturesHome();}} else {setChapterNum(null);setScreen("bible-idx");}}return "true";} else
      if (s === "bible-idx") {if (genreIdRef.current) {setScreen("scripture-genre");} else {goScripturesHome();}return "true";} else
      // Letter screens: unified back via COLLECTIONS registry
      { const col = COL_BY_LETTER_SC.get(s);
      if (col) {
        if (fromMatthewChRef.current) {setFromMatthewCh(null);setScreen("matthew-ch");}
        else if (fromSearchRef.current) {setFromSearch(false);setScreen("search");}
        else if (fromStudiesRef.current) {setFromStudies(false);setScreen("bible-study-chapter");}
        else if (col.indexScreen) {setScreen(col.indexScreen);}
        else {goHome();}
        return "true";
      }}
      // Index screens + garden: all go back to volumes-home
      if (COL_BY_INDEX_SC.has(s) || s === "garden-view") {goVolumesHome();return "true";}
      return "false";
    };
    return () => {delete window.handleAndroidBack;};
  }, []);
}

/* ═══════════════════════════════════════════════════════════════════════
   useFromLetterStack — multi-level tap-through back-stack + "Back to …" pill
   ═══════════════════════════════════════════════════════════════════════
   Global-scope module. Bundled into dist/bundle-b.js.

   OWNS:
     - fromLetterStack state    Array<{ sourceScreen, sourceBookId,
                                  sourceChapterNum, sourceLetterId,
                                  sourceStudyId, sourceStudyChapterId,
                                  sourceLetterTitle, sourceVolumeLabel,
                                  destSnapshot }>  — a per-tab tabField,
                                  capped at 50 entries
     - fromLetterRef            useRefMirror of fromLetterStack — gives
                                  call-time (event-handler) reads of the
                                  current stack without a stale closure
     - pushFromLetter(entry)    append a source-context entry
     - tapThroughBack()         the "Back to …" pill handler — pops the
                                  top and restores its captured screen/IDs
     - the prune useEffect      a CONSISTENCY-ENFORCEMENT effect: when the
                                  user navigates away from a recorded
                                  destination, it evicts the now-stale top
                                  entry. Its only side effect is
                                  setFromLetterStack; it reads nav state
                                  purely to decide whether to mutate its
                                  OWN state. It guards an invariant
                                  intrinsic to what fromLetterStack means
                                  ("the top entry's destSnapshot must match
                                  the current location") — so it belongs
                                  with fromLetterStack, not in App(). It is
                                  NOT a composition-level sink (which would
                                  write to many subsystems); it writes to
                                  exactly one — its own state.
     - backHint                 the computed { title, volumeLabel } the
                                  pill renders, or null

   DOES NOT OWN:
     - _navToLinkRef / navigateToLink / the deferred `_navToLinkRef.current
       = …` assignment — those stay in App() (P6j). The dependency runs the
       OTHER way: that deferred body CALLS this hook's pushFromLetter.
     - openInAppLetter / goToLetterFromMatthew — App()-local tap-through
       builders; they call pushFromLetter but are not part of this cluster.
     - handleAndroidBack — reads fromLetterRef + calls setFromLetterStack,
       but stays in App() (P6l). setFromLetterStack is returned for it.
     - the __goHome window bridge — clears the stack via setFromLetterStack;
       stays in App(). setFromLetterStack is returned for it too.
     - the 6 navigation tabFields (screen/bookId/chapterNum/letterId/
       studyId/studyChapterId) — owned by the tabs block (P6k); received
       here as params (values for reads, setters for tapThroughBack's
       source-restore).

   PARAMS:
     tabField — the per-tab field accessor from App()'s tabs block; called
       as tabField('fromLetterStack') to get [state, setter] (the setter is
       identity-stable, cached per-key by App()).
     screen, bookId, chapterNum, letterId, studyId, studyChapterId — current
       navigation position; read by _destMatches / the prune effect deps /
       backHint.
     setScreen, setBookId, setChapterNum, setLetterId, setStudyId,
       setStudyChapterId — navigation setters; tapThroughBack calls them to
       restore the popped entry's captured source position.

   RETURNS: { fromLetterStack, setFromLetterStack, pushFromLetter,
              tapThroughBack, fromLetterRef, backHint }

   STORAGE: none directly. fromLetterStack is a tabField, so it rides along
            in the vot-state tab persistence (usePersistedState, P6k+1).

   WINDOW: none. The only window touch is `window.__pendingHighlight = null`
     inside tapThroughBack — a one-shot data-slot write consumed by
     LetterView, not a handler bridge. No cleanup needed.
   ═══════════════════════════════════════════════════════════════════════ */

import { useRefMirror } from './use-ref-mirror.js';

export function useFromLetterStack({
  tabField,
  screen, bookId, chapterNum, letterId, studyId, studyChapterId,
  setScreen, setBookId, setChapterNum, setLetterId, setStudyId, setStudyChapterId,
}) {
  // Multi-level tap-through back-stack — a per-tab tabField so each tab
  // unwinds its own A → B → C tap-through chain independently.
  const [fromLetterStack, setFromLetterStack] = tabField('fromLetterStack');
  // Mirror so call-time reads (tapThroughBack, App()'s handleAndroidBack)
  // always see the current stack — tabField setters run their updater fns
  // async, so a stale closure would pop the wrong entry.
  const fromLetterRef = useRefMirror(fromLetterStack);

  const pushFromLetter = (entry) => setFromLetterStack((prev) => { var next = [...prev, entry]; return next.length > 50 ? next.slice(-50) : next; });

  // Tap-through "Back to …" pill handler: pops the top of the from-letter
  // stack and restores the captured screen + IDs. tabField setters run
  // their updater fns ASYNC, so we read the current stack from its ref
  // (fromLetterRef) and call setFromLetterStack with a plain value.
  const tapThroughBack = () => {
    const stack = fromLetterRef.current;
    if (!stack || stack.length === 0) return;
    const popped = stack[stack.length - 1];
    setFromLetterStack(stack.slice(0, -1));
    window.__pendingHighlight = null;
    if (popped.sourceBookId !== undefined) setBookId(popped.sourceBookId);
    if (popped.sourceChapterNum !== undefined) setChapterNum(popped.sourceChapterNum);
    if (popped.sourceLetterId !== undefined) setLetterId(popped.sourceLetterId);
    if (popped.sourceStudyId !== undefined) setStudyId(popped.sourceStudyId);
    if (popped.sourceStudyChapterId !== undefined) setStudyChapterId(popped.sourceStudyChapterId);
    if (popped.sourceScreen) setScreen(popped.sourceScreen);
  };

  // destSnapshot uses BOTH null (push paths explicitly null out unused
  // fields) and undefined (legacy entries without a recorded field), and
  // both should mean "don't care about this field". Loose-equal nullish
  // check (`!= null`) catches both — strict `=== undefined` missed the
  // null case and matched against stale state, so the single-shot back
  // pill was being silently pruned in the primary cross-screen flow
  // (Notes index → Bible/Study → expected "Back to My Notes" pill).
  const _destMatches = (dest) => {
    if (!dest) return true;
    if (dest.screen !== screen) return false;
    if (dest.bookId != null && dest.bookId !== bookId) return false;
    if (dest.chapterNum != null && dest.chapterNum !== chapterNum) return false;
    if (dest.letterId != null && dest.letterId !== letterId) return false;
    if (dest.studyId != null && dest.studyId !== studyId) return false;
    if (dest.studyChapterId != null && dest.studyChapterId !== studyChapterId) return false;
    return true;
  };

  // Prune stale tap-through entries. When the user navigates away from a
  // recorded destination (next chapter, different book, etc.), pop the entry
  // so the pill doesn't reappear if they happen to land back on the dest
  // later, and so Android-back doesn't trigger a confusing jump.
  React.useEffect(() => {
    if (fromLetterStack.length === 0) return;
    const top = fromLetterStack[fromLetterStack.length - 1];
    if (!top.destSnapshot) return;
    if (!_destMatches(top.destSnapshot)) {
      setFromLetterStack((prev) => prev.slice(0, -1));
    }
  }, [screen, bookId, chapterNum, letterId, studyId, studyChapterId, fromLetterStack]);

  // Top-of-stack back-hint — shows above the hero on tap-through destinations
  // so the user knows where Android back will return.
  // If the entry has a destSnapshot (recorded at push time), the pill is
  // suppressed when the current state has diverged from that destination —
  // the pill is single-shot, not persistent. Legacy entries without a
  // destSnapshot show the pill unconditionally (preserves the existing
  // letter→letter tap-through multi-level back behavior).
  const backHint = fromLetterStack.length > 0 ?
  (() => {
    const top = fromLetterStack[fromLetterStack.length - 1];
    if (top.destSnapshot && !_destMatches(top.destSnapshot)) return null;
    return {
      title: top.sourceLetterTitle || "previous",
      volumeLabel: top.sourceVolumeLabel || null
    };
  })() :
  null;

  return {
    fromLetterStack, setFromLetterStack, pushFromLetter,
    tapThroughBack, fromLetterRef, backHint,
  };
}

/* ═══════════════════════════════════════════════════════════════════════
   useReadingDwell — dwell-timer mark-as-read tracking
   ═══════════════════════════════════════════════════════════════════════
   Global-scope module. Bundled into dist/bundle-b.js.

   OWNS:
     - activeReadKey state (init from initialActiveReadKey for cold-start
                            restore; persisted back to vot-state by
                            usePersistedState in App())
     - setActiveReadKeyRaw    (hook-internal; NOT returned)
     - dwellTimerRef          (hook-internal ref)
     - dwellAccRef            (hook-internal ref — accumulated dwell ms)
     - dwellStartRef          (hook-internal ref — last resume timestamp)
     - dwellKeyRef            (hook-internal ref — key being timed)
     - pendingReadCommitRef   (hook-internal ref — optional commit fn)
     - DWELL_MS()             (hook-internal; reads the dwellMs param)
     - commitDwellNow         (hook-internal plain arrow fn; identity
                               churn each render is intentional — the
                               __onDwellCommit bridge effect deps on it)
     - cancelDwell            (returned — also used by setActiveReadKey)
     - scheduleDwell          (hook-internal plain arrow fn)
     - pauseDwell             (hook-internal plain arrow fn)
     - setActiveReadKey       (returned — public setter; wraps
                               cancelDwell + scheduleDwell)
     - __onDwellCommit bridge effect (binds commitDwellNow onto window
                               so ScreenLayout's scroll/fit checks can
                               call it; dep [commitDwellNow] re-binds
                               every render — this is intentional)
     - visibilitychange effect (pauses dwell on hidden, resumes on
                               visible; dep [] — mounted once)

   DOES NOT OWN:
     - window.__onDwellCommit is the cross-module bridge: ScreenLayout.js
       (a Cluster D module) reads it directly. commitDwellNow is exposed
       only through that bridge, not through the hook's return value.
     - The per-volume mark-as-read writes (setLastReadForVol, markRead,
       etc.) remain in App() — they depend on App-local helpers and per-
       collection knowledge; this hook only owns the timing gate.

   PARAMS:
     dwellMs             — settings.dwellMs (useSettings) — number or
                           falsy. If falsy, defaults to 20000 ms (20 s).
     initialActiveReadKey — saved.activeReadKey from useSavedState (the
                           cold-start restore value). MUST be passed
                           explicitly so the hook initialises useState
                           with the persisted value. Passing null here
                           would silently break the reading-dot indicator
                           on relaunch.

   RETURNS: { activeReadKey, setActiveReadKey, cancelDwell }

   STORAGE:
     None directly. activeReadKey rides along in the vot-state JSON
     written by usePersistedState (P6k+1) via the returned value.

   WINDOW:
     __onDwellCommit — set to commitDwellNow so ScreenLayout (a Cluster D
       module) can call it directly. The binding effect's dep
       [commitDwellNow] re-binds it every render (see box below). Cleanup
       nulls it, GUARDED — only clears window.__onDwellCommit if it still
       points at this hook's function, so a re-bind from the next render
       is not clobbered.

   ┌─ STRUCTURAL — commitDwellNow MUST stay a plain function ──────────────┐
   │ commitDwellNow (and the other dwell arrows) MUST NOT be wrapped in    │
   │ React.useCallback. The __onDwellCommit bridge effect has dep          │
   │ [commitDwellNow] and relies on commitDwellNow's identity CHURNING     │
   │ every render to re-bind the window hook — so ScreenLayout always      │
   │ holds a fresh reference. A useCallback would freeze that and          │
   │ permanently stale-bind the bridge.                                    │
   └───────────────────────────────────────────────────────────────────────┘
   ═══════════════════════════════════════════════════════════════════════ */

export function useReadingDwell({ dwellMs, initialActiveReadKey }) {
  // ── State ──────────────────────────────────────────────────────────────
  const [activeReadKey, setActiveReadKeyRaw] = React.useState(initialActiveReadKey);

  // ── Refs ───────────────────────────────────────────────────────────────
  const dwellTimerRef = React.useRef(null);
  const dwellAccRef = React.useRef(0);
  const dwellStartRef = React.useRef(null);
  const dwellKeyRef = React.useRef(null);
  const pendingReadCommitRef = React.useRef(null);

  // ── DWELL_MS ───────────────────────────────────────────────────────────
  // Returns the effective dwell threshold in ms. Reads the dwellMs param.
  const DWELL_MS = () => dwellMs ? Number(dwellMs) : 20000;

  // ── Plain arrow functions ──────────────────────────────────────────────
  // Do NOT convert any of these to useCallback. commitDwellNow in
  // particular MUST be a plain function recreated each render — the
  // __onDwellCommit bridge effect's [commitDwellNow] dep relies on that
  // identity churn to re-bind the window hook each render.

  const commitDwellNow = () => {
    if (!dwellKeyRef.current) return;
    if (dwellTimerRef.current) {clearTimeout(dwellTimerRef.current);dwellTimerRef.current = null;}
    if (pendingReadCommitRef.current) {pendingReadCommitRef.current();pendingReadCommitRef.current = null;}
    setActiveReadKeyRaw(dwellKeyRef.current);
    dwellAccRef.current = 0;dwellStartRef.current = null;dwellKeyRef.current = null;
  };

  const cancelDwell = () => {
    if (dwellTimerRef.current) {clearTimeout(dwellTimerRef.current);dwellTimerRef.current = null;}
    dwellAccRef.current = 0;dwellStartRef.current = null;dwellKeyRef.current = null;
    pendingReadCommitRef.current = null;
  };

  const scheduleDwell = () => {
    if (!dwellKeyRef.current || dwellTimerRef.current) return;
    const remaining = DWELL_MS() - dwellAccRef.current;
    dwellStartRef.current = Date.now();
    dwellTimerRef.current = setTimeout(() => {
      if (pendingReadCommitRef.current) {pendingReadCommitRef.current();pendingReadCommitRef.current = null;}
      setActiveReadKeyRaw(dwellKeyRef.current);
      dwellTimerRef.current = null;dwellAccRef.current = 0;
      dwellStartRef.current = null;dwellKeyRef.current = null;
    }, remaining);
  };

  const pauseDwell = () => {
    if (!dwellTimerRef.current || !dwellStartRef.current) return;
    clearTimeout(dwellTimerRef.current);dwellTimerRef.current = null;
    dwellAccRef.current += Date.now() - dwellStartRef.current;
    dwellStartRef.current = null;
  };

  const setActiveReadKey = (key, commitFn) => {
    cancelDwell();
    dwellKeyRef.current = key;
    pendingReadCommitRef.current = commitFn || null;
    if (document.visibilityState === 'visible') scheduleDwell();
  };

  // ── __onDwellCommit bridge effect ──────────────────────────────────────
  // Expose the commit-now callback for ScreenLayout's scroll/fit checks.
  // dep [commitDwellNow]: identity churn each render intentionally
  // re-binds the bridge so ScreenLayout always holds a fresh reference.
  React.useEffect(() => {
    window.__onDwellCommit = commitDwellNow;
    return () => {if (window.__onDwellCommit === commitDwellNow) window.__onDwellCommit = null;};
  }, [commitDwellNow]);

  // ── visibilitychange effect ────────────────────────────────────────────
  // Pause dwell timer when the app is hidden; resume when visible again.
  React.useEffect(() => {
    const onVis = () => {if (document.visibilityState === 'hidden') pauseDwell();else scheduleDwell();};
    document.addEventListener('visibilitychange', onVis);
    return () => document.removeEventListener('visibilitychange', onVis);
  }, []);

  // ── Return ─────────────────────────────────────────────────────────────
  return { activeReadKey, setActiveReadKey, cancelDwell };
}

/* ═══════════════════════════════════════════════════════════════════════
   useSavedState — load + validate vot-state on mount
   ═══════════════════════════════════════════════════════════════════════
   Global-scope module. Bundled into dist/bundle-b.js.
   First mechanical hook extraction of P6 (App() decomposition).

   Reads localStorage['vot-state'] exactly once on mount (useMemo []),
   coerces stale screen values back to safe defaults, and hands the
   validated object to App() — which then distributes its fields
   (saved.theme, saved.tabs, saved.settings, saved.activeReadKey …) to
   useTabs / useSettings / useReadingDwell / App-local useState.

   OWNS:
     - the single-evaluation read + JSON.parse of localStorage['vot-state']
     - the parse-error fallback ({} on JSON.parse throw)

   DOES NOT OWN:
     - _validateTabState — the screen-coercion POLICY (13 rules that
       rewrite a no-longer-valid screen string to 'home' or its parent
       index). It is a pure EXPORTED helper colocated in this file, not a
       hook: useSavedState merely CALLS it — over the legacy top-level
       state AND each entry in s.tabs[] — so the same rules apply
       uniformly. Kept standalone so it can be unit-tested and reused
       independently of the hook.
     - the consumption / distribution of the returned object — App() owns
       which subsystem each field is routed to.

   PARAMS: none.

   RETURNS: the validated saved-state object (or {} on JSON.parse failure).

   STORAGE: reads localStorage['vot-state']; never writes — usePersistedState
            (P6k+1) owns the write side.

   WINDOW: none.

   Why a hook and not a plain function call?
     useMemo([]) gives a single-evaluation guarantee tied to the component
     lifecycle and documents intent ("read once on mount"). A plain
     function called during render would re-evaluate every render — same
     logical outcome, extra work.

   Test contract preserved exactly:
     - same screen-validation rules (no behavior change)
     - same parse-error fallback ({} on JSON.parse throw)
     - same single-pass evaluation (useMemo([]) → once per mount)
   ═══════════════════════════════════════════════════════════════════════ */

export function _validateTabState(s) {
  if ((s.screen === "matthew-ch" || s.screen === "bible-ch") && s.chapterNum == null) s.screen = "home";
  if (/^vot-(one|three|four|five|six|seven|timothy|flock|rebuke)-letter$/.test(s.screen) && !s.letterId) s.screen = "home";
  if (s.screen === "vot-letter" && !s.letterId) s.screen = "home";
  if (s.screen === "hm-letter" && !s.letterId) s.screen = "home";
  if (/^(wtlb-one-entry|wtlb-two-entry|blessed-entry|holy-days-entry)$/.test(s.screen) && !s.letterId) s.screen = "home";
  if (s.screen === "garden-view" && s.gardenPage == null) s.screen = "home";
  if (/^vot-(one|three|four|five|six|seven|timothy|flock|rebuke)-index$/.test(s.screen)) s.screen = "volumes-home";
  if ((s.screen === "matthew-idx" || s.screen === "bible-idx") && !s.bookId) s.screen = "home";
  if (s.screen === "search") s.screen = "home";
  if (s.screen === "scripture-genre" && !s.genreId) s.screen = "scriptures-home";
  if (s.screen === "bible-study-chapter" && (!s.studyId || !s.studyChapterId)) s.screen = "studies-home";
  if (s.screen === "bible-study-index" && !s.studyId) s.screen = "studies-home";
  // Journal screens require entryId which lives in local state (not tab
  // state), so they can't be reliably restored on reload. Bounce to hub.
  if (s.screen === "journal-viewer" || s.screen === "journal-editor") s.screen = "journal-home";
  return s;
}

export function useSavedState() {
  return React.useMemo(() => {
    try {
      const s = JSON.parse(localStorage.getItem("vot-state") || "{}");
      _validateTabState(s);
      if (Array.isArray(s.tabs)) s.tabs.forEach(_validateTabState);
      return s;
    } catch (e) { return {}; }
  }, []);
}

/* ═══════════════════════════════════════════════════════════════════════
   useScrollMemory — per-tab, per-screen scroll-position capture + restore
   ═══════════════════════════════════════════════════════════════════════
   Global-scope module. Bundled into dist/bundle-b.js.

   OWNS:
     - scrollKeyRef             (hook-internal; NOT returned)
     - flushScrollToActiveTab   (React.useCallback, dep [updateActiveTab])
                                 Writes { y, pct } into the active tab's
                                 scrollPositions map for the current screen.
     - Debounced scroll-listener effect (attaches to __scrollEl with 300 ms
                                 re-poll; fires flushScrollToActiveTab after
                                 120 ms idle).
     - Visibility/pagehide effect (flushes before OS kill or tab-switch).
     - Screen-change restore effect (updates scrollKeyRef; restores saved Y
                                 or scrolls to top when no saved position).

   DOES NOT OWN:
     - __scrollEl — window global set by the main scroll-container's ref
       callback in App(); read directly as a bare-name global (no import).
     - COL_BY_LETTER_SC — Map exported by scripture-resolution.js and
       exposed on window via _entry-b.js. Used in getScrollKey to derive
       the correct prefix for letter/WTLB/blessed/holy-days screens. Read
       directly as a bare-name global (no import).

   PARAMS:
     screen, bookId, chapterNum, letterId, studyId, studyChapterId
                     — current navigation state (useTabs via tabField);
                       used as effect deps and passed to getScrollKey.
     activeTab       — active-tab object (useTabs); scrollPositions are
                       read from here to restore scroll on screen change.
     activeTabIdx    — active tab index (useTabs); in the restore-effect
                       dep array so a tab switch also triggers restore.
     updateActiveTab — stable updater (useTabs); the sole dep of
                       flushScrollToActiveTab's useCallback.
     surpriseAnchor  — useTabs via tabField; if truthy the screen-change
                       effect skips restore (the anchor positions instead).
     tabsOverviewOpen — App()-local state; if truthy flushScrollToActiveTab
                       is a no-op (don't overwrite with the overview scroll).

   RETURNS: { flushScrollToActiveTab }

   STORAGE:
     None directly. Writes into activeTab.scrollPositions via
     updateActiveTab — those values ride along in the tabs array persisted
     to localStorage['vot-state'] by usePersistedState (P6k+1).

   WINDOW: none — wires no window.__* handler bridges. Reads the bare-name
     global __scrollEl and attaches scroll / visibilitychange / pagehide
     listeners (all balanced with removeEventListener in effect cleanup).

   ┌─ HARD INVARIANT — flushScrollToActiveTab identity stability ──────────┐
   │ flushScrollToActiveTab MUST be the direct return value of             │
   │ React.useCallback with dependency array [updateActiveTab]. Effects 1  │
   │ and 2 list it in their dep arrays and re-attach their listeners when  │
   │ its identity changes — identity stability is load-bearing.            │
   └───────────────────────────────────────────────────────────────────────┘
   ═══════════════════════════════════════════════════════════════════════ */

import { useRefMirror } from './use-ref-mirror.js';

// ── Module-private helper ──────────────────────────────────────────────────
// Derives a stable localStorage / scrollPositions key for the current
// screen. COL_BY_LETTER_SC is a bare-name window global (bundle-b.js).
function getScrollKey(scr, bid, cnum, lid, sid, scid) {
  if (scr === "matthew-ch" || scr === "bible-ch") return bid + '-' + cnum;
  if (scr === "bible-study-chapter") return 'study-' + (sid || '') + '-' + (scid || '');
  if (scr === "hm-letter") return 'entry-' + lid;
  var _sc = COL_BY_LETTER_SC.get(scr);
  if (_sc) {
    var pfx = _sc.kind === 'holy-days' ? 'holyday' : _sc.kind === 'letter' ? 'letter' : _sc.kind;
    return pfx + '-' + lid;
  }
  return scr;
}

export function useScrollMemory({
  screen, bookId, chapterNum, letterId, studyId, studyChapterId,
  activeTab,
  activeTabIdx,
  updateActiveTab,
  surpriseAnchor,
  tabsOverviewOpen,
}) {
  // ── Refs ───────────────────────────────────────────────────────────────
  const scrollKeyRef = React.useRef(getScrollKey(screen, bookId, chapterNum, letterId, studyId, studyChapterId));
  const tabsOverviewOpenRef = useRefMirror(tabsOverviewOpen);

  // ── Flush callback ─────────────────────────────────────────────────────
  // HARD INVARIANT: must be React.useCallback with dep array [updateActiveTab].
  const flushScrollToActiveTab = React.useCallback(() => {
    if (tabsOverviewOpenRef.current) return; // don't overwrite with overview scroll
    const key = scrollKeyRef.current;
    if (!key || !__scrollEl) return;
    const { scrollTop, scrollHeight, clientHeight } = __scrollEl;
    const max = Math.max(scrollHeight - clientHeight, 1);
    const pct = Math.max(0, Math.min(1, scrollTop / max));
    updateActiveTab((t) => ({
      scrollPositions: { ...(t.scrollPositions || {}), [key]: { y: scrollTop, pct } }
    }));
  }, [updateActiveTab]);

  // ── Effect 1: debounced scroll-listener attach ─────────────────────────
  // Re-polls every 300 ms in case __scrollEl hasn't mounted yet.
  React.useEffect(() => {
    let timeout;
    let currentEl = null;
    const onScroll = () => {
      clearTimeout(timeout);
      timeout = setTimeout(flushScrollToActiveTab, 120);
    };
    const attach = () => {
      if (__scrollEl !== currentEl) {
        if (currentEl) currentEl.removeEventListener("scroll", onScroll);
        currentEl = __scrollEl;
        if (currentEl) currentEl.addEventListener("scroll", onScroll, { passive: true });
      }
    };
    attach();
    const poll = setInterval(attach, 300);
    return () => {clearInterval(poll);if (currentEl) currentEl.removeEventListener("scroll", onScroll);clearTimeout(timeout);};
  }, [flushScrollToActiveTab]);

  // ── Effect 2: flush on page-hide / app-background ─────────────────────
  // Ensures position is preserved across OS kills and tab switches.
  React.useEffect(() => {
    const onVis = () => {if (document.visibilityState === 'hidden') flushScrollToActiveTab();};
    document.addEventListener('visibilitychange', onVis);
    window.addEventListener('pagehide', flushScrollToActiveTab);
    return () => {
      document.removeEventListener('visibilitychange', onVis);
      window.removeEventListener('pagehide', flushScrollToActiveTab);
    };
  }, [flushScrollToActiveTab]);

  // ── Effect 3: screen-change → update key + restore saved scroll ────────
  // ASYMMETRIC CLEANUP IS INTENTIONAL: the savedY branch returns a cleanup
  // to cancel the timer; the scroll-to-top branch uses a 0 ms setTimeout
  // with no cleanup return — this is deliberate (fires immediately, no
  // cleanup benefit). DO NOT add a cleanup return to the scroll-to-top
  // branch.
  React.useEffect(() => {
    const key = getScrollKey(screen, bookId, chapterNum, letterId, studyId, studyChapterId);
    scrollKeyRef.current = key;
    if (surpriseAnchor) return;

    const saved = activeTab && activeTab.scrollPositions && activeTab.scrollPositions[key];
    // Support both new { y, pct } shape and legacy plain number for backcompat
    const savedY = saved == null ? null :
    typeof saved === 'number' ? saved : typeof saved.y === 'number' ? saved.y : null;
    if (typeof savedY === 'number' && savedY > 0) {
      const timer = setTimeout(() => {if (__scrollEl) __scrollEl.scrollTop = savedY;}, 0);
      return () => clearTimeout(timer);
    }
    // Fresh screen / no saved position → top
    setTimeout(() => {if (__scrollEl) __scrollEl.scrollTop = 0;}, 0);
  }, [screen, bookId, chapterNum, letterId, studyId, studyChapterId, activeTabIdx]);

  // ── Return ─────────────────────────────────────────────────────────────
  return { flushScrollToActiveTab };
}

/* ═══════════════════════════════════════════════════════════════════════
   useSheetOrchestration — modal/sheet/overlay open-state + window bridges
   + auto-dismiss-on-navigation
   ═══════════════════════════════════════════════════════════════════════
   Global-scope module. Bundled into dist/bundle-b.js.

   OWNS:
     - annChip state             { x, y, hlKey, groupId } | null
     - linkSidebarKey state      hlKey | null
     - linkPickerSource state    { key, label, ... } | null
     - linkRefineRequest state   { kind, target, item } | null
     - lastLinkCreated state     most recently created link, for undo
     - linkPickerMode state      null | 'card' | 'excerpt'
     - linkPickerOnPickRef       useRef — callback for target-picker mode
     - noteSheetTarget state     { groupId, startInEditMode } | null
     - notebookPickerTarget state  groupId | null
     - multiNotePayload state    { groupIds, x, y } | null
     - bookmarkPopoverPayload state  { bkmIds, x, y, hlKey } | null
     - bookmarkCreatePending state   { hlKey, sourceLabel, excerpt,
                                       defaultLabel, ... } | null
     - inboundJournalPayload state   { refKey, label } | null
     - openLinkSidebar / closeLinkSidebar      (useCallback)
     - openLinkPicker / closeLinkPicker         (useCallback)
     - openLinkPickerForTarget                  (useCallback)
     - openNoteSheet / closeNoteSheet           (useCallback)
     - 10 window.__open* / __show* bridge effects (all with delete cleanup)
     - auto-dismiss effect (clears note/chip/multi/bookmark on nav change)

   DOES NOT OWN:
     - hlTick / setHlTick — stays in App(); setHlTick received as a param
       (closeLinkPicker calls setHlTick(t => t + 1) to re-trigger DOM apply)
     - _navToLinkRef + navigateToLink — P6j territory; not touched here
     - __bumpHlTick effect — belongs with hlTick in App()
     - visualViewport keyboard-height effect — owns no sheet state
     - apply-DOM effects (applyDOMHighlights, applyDOMLinks, etc.) — fenced
     - _allBooks, findEntryContext, JournalStore, JournalHelpers,
       BookmarkStore, _bookmarkSourceLabel — bare-name window globals from
       other bundles; accessed by bare name inside callbacks (no imports,
       no params)

   PARAMS:
     screen, letterId, bookId, chapterNum, studyId, studyChapterId —
       navigation position (useTabs via tabField) — deps of the
       auto-dismiss effect so floating overlays clear whenever the active
       reading position changes.
     setHlTick — App()-local useState setter; closeLinkPicker calls
       setHlTick(t => t + 1) to force the apply-DOM effects to re-run
       after the picker closes.

   RETURNS: {
     annChip, setAnnChip,
     linkSidebarKey, openLinkSidebar, closeLinkSidebar,
     linkPickerSource, openLinkPicker, openLinkPickerForTarget, closeLinkPicker,
     linkRefineRequest, setLinkRefineRequest,
     lastLinkCreated, setLastLinkCreated,
     linkPickerMode, linkPickerOnPickRef,
     noteSheetTarget, openNoteSheet, closeNoteSheet,
     notebookPickerTarget, setNotebookPickerTarget,
     multiNotePayload, setMultiNotePayload,
     bookmarkPopoverPayload, setBookmarkPopoverPayload,
     bookmarkCreatePending, setBookmarkCreatePending,
     inboundJournalPayload, setInboundJournalPayload,
   }

   STORAGE:
     None. All state is in-memory React state; nothing persisted to
     localStorage directly. The render tree consumes the returned values.

   WINDOW: 10 handler bridges, each wired in its own effect and torn down
     with `delete` in that effect's cleanup —
       __openLinkPicker          → openLinkPicker
       __openLinkPickerForTarget → openLinkPickerForTarget
       __openNote                → openNoteSheet
       __openLinkSidebar         → openLinkSidebar
       __showAnnChip             → inline setAnnChip(x,y,hlKey,groupId)
       __showMultiNote           → inline setMultiNotePayload(groupIds,x,y)
       __openBookmarkPopover     → inline setBookmarkPopoverPayload(...)
       __bookmarkCreate          → inline setBookmarkCreatePending(info)
       __openJournalInbound      → inline setInboundJournalPayload(...)
       __bookmarkEdit            → inline BookmarkStore lookup + setter
     Reads but does NOT own: window.__hideSelectionToolbar (called in the
     auto-dismiss effect — owned by SelectionToolbar).
   ═══════════════════════════════════════════════════════════════════════ */

export function useSheetOrchestration({
  screen, letterId, bookId, chapterNum, studyId, studyChapterId,
  setHlTick,
}) {
  // ── State slots ────────────────────────────────────────────────────────
  const [annChip, setAnnChip] = React.useState(null);                  // { x, y, hlKey, groupId } or null
  const [linkSidebarKey, setLinkSidebarKey] = React.useState(null);   // hlKey or null
  const [linkPickerSource, setLinkPickerSource] = React.useState(null); // { key, label } or null
  const [linkRefineRequest, setLinkRefineRequest] = React.useState(null); // { kind, target, item } or null
  const [lastLinkCreated, setLastLinkCreated] = React.useState(null); // most recently created link, for undo
  // Picker mode — when set, LinkPicker behaves as a target picker (no source,
  // no link persistence); the selected/refined target is handed back via
  // linkPickerOnPickRef.current. Used by Journal to drive the LinkPicker for
  // "Insert Card" (mode='card', no excerpt prompt) and "Insert Excerpt"
  // (mode='excerpt', always refine through verse/letter picker).
  const [linkPickerMode, setLinkPickerMode] = React.useState(null); // null | 'card' | 'excerpt'
  const linkPickerOnPickRef = React.useRef(null);
  const [noteSheetTarget, setNoteSheetTarget] = React.useState(null);  // { groupId, startInEditMode } or null
  const [notebookPickerTarget, setNotebookPickerTarget] = React.useState(null); // groupId or null
  const [multiNotePayload, setMultiNotePayload] = React.useState(null); // { groupIds, x, y } or null
  const [bookmarkPopoverPayload, setBookmarkPopoverPayload] = React.useState(null); // { bkmIds, x, y, hlKey } or null
  const [bookmarkCreatePending, setBookmarkCreatePending] = React.useState(null);   // { hlKey, sourceLabel, excerpt, defaultLabel } or null
  const [inboundJournalPayload, setInboundJournalPayload] = React.useState(null);

  // ── Opener / closer useCallbacks ───────────────────────────────────────
  const openLinkSidebar = React.useCallback((hlKey) => setLinkSidebarKey(hlKey), []);
  const closeLinkSidebar = React.useCallback(() => setLinkSidebarKey(null), []);
  const openLinkPicker = React.useCallback((selInfo) => {
    const hlKey = typeof selInfo === 'string' ? selInfo : selInfo.hlKey;
    if (!hlKey) return;
    const parts = hlKey.split(':');
    let label = hlKey;
    if (parts[0] === 'bible') {
      const b = _allBooks()[parts[1]];
      label = (b ? b.title : parts[1]) + ' ' + parts[2] + ':' + parts[3];
    } else if (parts[0] === 'study') {
      // study:bookId-chapter:verse  e.g. "study:matthew-4:7"
      const m = parts[1].match(/^(.+)-(\d+)$/);
      if (m) label = (m[1].charAt(0).toUpperCase() + m[1].slice(1)) + ' ' + m[2] + (parts[2] && parts[2] !== '0' ? ':' + parts[2] : '');
    } else if (parts[0] === 'letter' || parts[0] === 'wtlb' || parts[0] === 'blessed' || parts[0] === 'holy-days') {
      // Centralized lookup also covers Bible-Study chapters (whose source
      // hlKey shape is "letter:{chapterId}:N" because LetterView renders them).
      const ctx = findEntryContext(parts[1], parts[0]);
      if (ctx && ctx.title) label = ctx.title;
    } else if (parts[0] === 'journal') {
      // journal:<entryId>:<blockIdx>
      const eid = parts[1];
      const je = (typeof JournalStore !== 'undefined') ? JournalStore.get(eid) : null;
      if (je && typeof JournalHelpers !== 'undefined') {
        label = 'Journal · ' + (JournalHelpers.entryDisplayTitle(je) || 'Untitled');
      }
    }
    const src = typeof selInfo === 'string'
      ? { key: hlKey, label }
      : { key: hlKey, label, start: selInfo.start, end: selInfo.end, text: selInfo.text };
    setLinkPickerSource(src);
  }, []);
  const closeLinkPicker = React.useCallback(() => { setLinkPickerSource(null); setLinkRefineRequest(null); setLastLinkCreated(null); setLinkPickerMode(null); linkPickerOnPickRef.current = null; setHlTick(t => t + 1); }, []);
  // Picker mode — Journal calls this to open LinkPicker as a target picker.
  //   mode: 'card'    → return target after the first item is chosen (no
  //                     verse/excerpt prompt). Used for "Insert Card".
  //   mode: 'excerpt' → always run the verse/letter excerpt picker so the
  //                     user can pick a character-precise span. Used for
  //                     "Insert Excerpt".
  // onPick receives the chosen target endpoint (+ optional refinement data).
  const openLinkPickerForTarget = React.useCallback((mode, onPick) => {
    linkPickerOnPickRef.current = typeof onPick === 'function' ? onPick : null;
    // Use a sentinel source object so the render conditions ("source &&
    // !refine") still fire — but no real source key/label exists.
    setLinkPickerSource({ key: null, label: null, picker: true });
    setLinkPickerMode(mode || 'card');
    setLinkRefineRequest(null);
    setLastLinkCreated(null);
  }, []);
  const openNoteSheet = React.useCallback((groupId, startInEditMode) => {
    setNoteSheetTarget({ groupId, startInEditMode: !!startInEditMode });
    setAnnChip(null);
  }, []);
  const closeNoteSheet = React.useCallback(() => setNoteSheetTarget(null), []);

  // ── Window-bridge effects ──────────────────────────────────────────────
  // Expose openLinkPicker globally so the SelectionToolbar can invoke it
  // from anywhere (Bible/Letter/WTLB views), and so tests / hardware-back
  // handling can interact with it without prop-drilling.
  React.useEffect(() => {
    window.__openLinkPicker = openLinkPicker;
    window.__openLinkPickerForTarget = openLinkPickerForTarget;
    return () => {
      delete window.__openLinkPicker;
      delete window.__openLinkPickerForTarget;
    };
  }, [openLinkPicker, openLinkPickerForTarget]);
  React.useEffect(() => { window.__openNote = openNoteSheet; return () => { delete window.__openNote; }; }, [openNoteSheet]);
  // Apply DOM-based highlights + inline link icons to LetterView/WtlbEntryView
  // containers after React renders. HighlightableText handles BibleChapterView/
  // ChapterView. window.__openLinkSidebar is read by inline link icon clicks.
  React.useEffect(() => { window.__openLinkSidebar = openLinkSidebar; return () => { delete window.__openLinkSidebar; }; }, [openLinkSidebar]);
  React.useEffect(() => { window.__showAnnChip = (x, y, hlKey, groupId) => setAnnChip({ x, y, hlKey, groupId }); return () => { delete window.__showAnnChip; }; }, []);
  React.useEffect(() => { window.__showMultiNote = (groupIds, x, y) => setMultiNotePayload({ groupIds, x, y }); return () => { delete window.__showMultiNote; }; }, []);
  React.useEffect(() => { window.__openBookmarkPopover = (bkmIds, x, y, hlKey) => setBookmarkPopoverPayload({ bkmIds, x, y, hlKey }); return () => { delete window.__openBookmarkPopover; }; }, []);
  // Bridge for SelectionToolbar + ChapterBookmarkBtn to open the
  // pre-commit BookmarkCreateSheet instead of silently adding to the
  // store. `info` shape: { hlKey, sourceLabel, excerpt, defaultLabel }.
  React.useEffect(() => { window.__bookmarkCreate = (info) => setBookmarkCreatePending(info || null); return () => { delete window.__bookmarkCreate; }; }, []);
  // Journal inbound sheet bridge — opened from JournalChip in NavButtons.
  // payload: { refKey: 'letter:two/the-wide-path', label: 'The Wide Path' }
  React.useEffect(() => {
    window.__openJournalInbound = (refKey, label) => setInboundJournalPayload(refKey ? { refKey, label } : null);
    return () => { delete window.__openJournalInbound; };
  }, []);
  // Bridge for the inline bookmark icon (single-bookmark tap) and the
  // BookmarksScreen row's edit-from-action-sheet path to open the same
  // BookmarkCreateSheet in EDIT mode. Looks up the existing record and
  // builds the `pending` shape with editId + currentLabel/currentThought
  // populated so the sheet renders preloaded.
  React.useEffect(() => {
    window.__bookmarkEdit = (bkmId, opts) => {
      if (!bkmId || typeof BookmarkStore === 'undefined') return;
      const bkm = BookmarkStore.get(bkmId);
      if (!bkm) return;
      // Source label reuses the BookmarksScreen helper for consistency.
      const sourceLabel = (typeof _bookmarkSourceLabel === 'function')
        ? _bookmarkSourceLabel(bkm.hlKey)
        : '';
      // `atSource` lets callers signal that the user is already on the
      // bookmarked passage (set by the inline-icon tap in
      // dom-bookmarks.js). The sheet uses it to hide the "Open Source"
      // button, which would otherwise be a redundant no-op. Future
      // callers from a list surface (e.g. BookmarksScreen row's action
      // sheet) can omit it and the Open button is shown by default.
      setBookmarkCreatePending({
        editId: bkm.id,
        hlKey: bkm.hlKey,
        sourceLabel: sourceLabel,
        excerpt: '',
        defaultLabel: bkm.label || '',
        currentLabel: bkm.label || '',
        currentThought: bkm.thought || '',
        atSource: !!(opts && opts.atSource)
      });
    };
    return () => { delete window.__bookmarkEdit; };
  }, []);

  // ── Auto-dismiss effect ────────────────────────────────────────────────
  // Auto-dismiss floating overlays whenever the active screen, letter,
  // book, or study chapter changes. Without this the always-mounted
  // SelectionToolbar persists with a stale selInfo, and the
  // noteSheetTarget keeps the NoteSheet visible over an unrelated
  // page after the user navigates via letter arrows or hardware back.
  // Also clears the AnnotationActionChip and MultiNote popover for the
  // same reason. annChip + multiNote already had partial cleanup in
  // hlTick reset paths; this consolidates the policy in one place.
  React.useEffect(() => {
    if (typeof window.__hideSelectionToolbar === 'function') window.__hideSelectionToolbar();
    setNoteSheetTarget(null);
    setAnnChip(null);
    setMultiNotePayload(null);
    setBookmarkPopoverPayload(null);
  }, [screen, letterId, bookId, chapterNum, studyId, studyChapterId]);

  // ── Return ─────────────────────────────────────────────────────────────
  return {
    annChip, setAnnChip,
    linkSidebarKey, openLinkSidebar, closeLinkSidebar,
    linkPickerSource, openLinkPicker, openLinkPickerForTarget, closeLinkPicker,
    linkRefineRequest, setLinkRefineRequest,
    lastLinkCreated, setLastLinkCreated,
    linkPickerMode, linkPickerOnPickRef,
    noteSheetTarget, setNoteSheetTarget, openNoteSheet, closeNoteSheet,
    notebookPickerTarget, setNotebookPickerTarget,
    multiNotePayload, setMultiNotePayload,
    bookmarkPopoverPayload, setBookmarkPopoverPayload,
    bookmarkCreatePending, setBookmarkCreatePending,
    inboundJournalPayload, setInboundJournalPayload,
  };
}

/* ═══════════════════════════════════════════════════════════════════════
   useTabActions — tab open/close/switch operations (P6k Commit B)
   ═══════════════════════════════════════════════════════════════════════
   Global-scope module. Bundled into dist/bundle-b.js.

   The OPERATIONS on the tab state machine — the counterpart to useTabs
   (P6k Commit A), which owns the STATE. This is a LATE hook: it must be
   called after useReadingDwell (it needs cancelDwell) and useThumbnails
   (setTabThumbnails). useTabs runs near the top of App() to provide
   tabField; useTabActions runs ~480 lines later, once its cross-hook
   deps exist — which is why these operations are a separate hook, not
   part of useTabs. They receive their deps as plain params; no ref
   plumbing, no two-phase init.

   OWNS:
     - openNewTab / switchToTab / closeTab / closeOtherTabs /
       closeTabsToTheRight / closeAllTabs / deduplicateTabs
     - tabActionIdx        long-press target for TabActionSheet
     - disableTabsPromptOpen   the "disable tabs?" dialog gate (raised by
                                the closeTab 3-strike path)
     - clearAllStage       0/1/2 — the TabsOverview "Clear All Tabs"
                            three-tap confirm
     - lastTabCloseStrikes ref — 3-strike counter; the render resets it
                            on normal tab use, so the ref is RETURNED

   DOES NOT OWN:
     - tabs / activeTabIdx / setTabs / setActiveTabIdx — useTabs (Commit
       A); received here inside the `tabState` param.
     - DEFAULT_TAB — imported directly from use-tabs.js.
     - tabsOverviewOpen + goTabs — stay in App(). tabsOverviewOpen is
       consumed by useThumbnails (a param) which runs BEFORE this hook
       could be called, so it cannot live here; goTabs only touches
       App()-available values (tabsOverviewOpen, flushScrollToActiveTab,
       captureActiveTabThumbnail, settings.tabsEnabled) so it stays
       inline next to that state.
     - tabContentKey — module global from src/utils/tabs.js; bare name.

   PARAMS:
     tabState — the whole useTabs() return; tabs / activeTabIdx /
       setTabs / setActiveTabIdx are pulled from it.
     cancelDwell — useReadingDwell (P6f); switchToTab cancels an in-flight
       dwell timer BEFORE flipping tabs so a "90% read" commit can't land
       on the wrong (newly-active) tab.
     setTabThumbnails — useThumbnails (P6d); closeAllTabs clears them.

   RETURNS: { openNewTab, switchToTab, closeTab, closeOtherTabs,
              closeTabsToTheRight, closeAllTabs, deduplicateTabs,
              tabActionIdx, setTabActionIdx,
              disableTabsPromptOpen, setDisableTabsPromptOpen,
              clearAllStage, setClearAllStage, lastTabCloseStrikes }

   STORAGE: none.

   WINDOW: none.
   ═══════════════════════════════════════════════════════════════════════ */

import { DEFAULT_TAB } from './use-tabs.js';

const MAX_TABS = 999;

export function useTabActions({ tabState, cancelDwell, setTabThumbnails }) {
  const { tabs, activeTabIdx, setTabs, setActiveTabIdx } = tabState;

  const [tabActionIdx, setTabActionIdx] = React.useState(null); // long-press target
  const [disableTabsPromptOpen, setDisableTabsPromptOpen] = React.useState(false);
  const [clearAllStage, setClearAllStage] = React.useState(0); // 0 = idle, 1 = "Are You Sure?", 2 = confirmed
  const lastTabCloseStrikes = React.useRef(0); // 3-strike counter for last-tab close

  const openNewTab = React.useCallback(() => {
    setTabs((prev) => {
      if (prev.length >= MAX_TABS) return prev;
      const next = [...prev, { ...DEFAULT_TAB }];
      setActiveTabIdx(next.length - 1);
      return next;
    });
  }, []);
  const switchToTab = React.useCallback((idx) => {
    // Cancel any in-flight dwell timer BEFORE flipping tabs — otherwise
    // the previous tab's "read 90%, fire commit" timer would land on the
    // newly-active tab and mark the wrong letter as read.
    cancelDwell();
    setActiveTabIdx((prev) => {
      if (idx < 0) return 0;
      return Math.min(idx, tabs.length - 1);
    });
  }, [tabs.length]);
  const closeTab = React.useCallback((idx) => {
    setTabs((prev) => {
      if (prev.length <= 1) {
        // 3-strike: user keeps trying to close their last tab → offer to disable tabs entirely
        lastTabCloseStrikes.current += 1;
        if (lastTabCloseStrikes.current >= 3) {
          setDisableTabsPromptOpen(true);
          lastTabCloseStrikes.current = 0;
        }
        // Reset the last tab to home rather than actually closing it
        const reset = { ...DEFAULT_TAB };
        setActiveTabIdx(0);
        return [reset];
      }
      // Closing a non-last tab — reset the strike counter (user is using tabs normally)
      lastTabCloseStrikes.current = 0;
      const next = prev.filter((_, i) => i !== idx);
      // Keep activeTabIdx pointing at a valid tab
      setActiveTabIdx((prevIdx) => {
        if (idx < prevIdx) return prevIdx - 1; // shifted left
        if (idx === prevIdx) return Math.max(0, Math.min(prevIdx, next.length - 1));
        return prevIdx; // closed tab was to the right; idx unchanged
      });
      return next;
    });
  }, []);
  const closeOtherTabs = React.useCallback((keepIdx) => {
    setTabs((prev) => {
      if (prev.length <= 1) return prev;
      const kept = prev[keepIdx];
      if (!kept) return prev;
      setActiveTabIdx(0);
      return [kept];
    });
  }, []);
  const closeTabsToTheRight = React.useCallback((keepIdx) => {
    setTabs((prev) => {
      if (keepIdx >= prev.length - 1) return prev;
      setActiveTabIdx((cur) => Math.min(cur, keepIdx));
      return prev.slice(0, keepIdx + 1);
    });
  }, []);
  const closeAllTabs = React.useCallback(() => {
    setTabs([{ ...DEFAULT_TAB }]);
    setActiveTabIdx(0);
    setTabThumbnails({});
  }, []);
  // Merge duplicates: if two tabs have the same content signature, drop later duplicates
  const deduplicateTabs = React.useCallback(() => {
    setTabs((prev) => {
      if (prev.length <= 1) return prev;
      const seen = new Set();
      const keep = [];
      let activeStillInKept = false;
      let newActiveIdx = 0;
      prev.forEach((t, i) => {
        const k = tabContentKey(t);
        if (!seen.has(k)) {
          seen.add(k);
          if (i === activeTabIdx) {activeStillInKept = true;newActiveIdx = keep.length;}
          keep.push(t);
        } else if (i === activeTabIdx && !activeStillInKept) {
          // Active tab is a duplicate — point at the first kept instance
          let idx = keep.findIndex((x) => tabContentKey(x) === k);
          if (idx >= 0) newActiveIdx = idx;
        }
      });
      setActiveTabIdx(newActiveIdx);
      return keep;
    });
  }, [activeTabIdx]);

  return {
    openNewTab, switchToTab, closeTab, closeOtherTabs,
    closeTabsToTheRight, closeAllTabs, deduplicateTabs,
    tabActionIdx, setTabActionIdx,
    disableTabsPromptOpen, setDisableTabsPromptOpen,
    clearAllStage, setClearAllStage, lastTabCloseStrikes,
    MAX_TABS,  // re-exported for the TabsOverview render (the cap badge)
  };
}

/* ═══════════════════════════════════════════════════════════════════════
   useThumbnails — tab-card thumbnail capture, IDB persistence, and GC
   ═══════════════════════════════════════════════════════════════════════
   Global-scope module. Bundled into dist/bundle-b.js.

   OWNS:
     - tabThumbnails state (content-keyed JPEG data-URL map)
     - setTabThumbnails   (returned so App's closeAllTabs can clear it)
     - IDB load-on-mount  (idbReadAll — reads IndexedDB on first render)
     - GC effect          (debounced, removes stale keys no longer tied
                           to any open tab)
     - captureActiveTabThumbnail  (React.useCallback, stable on tabsEnabled)
     - scroll-stop capture effect (attaches to __scrollEl with polling)
     - aspect-ratio CSS var effect (sets --card-ar on resize)
     - capture-after-nav effect   (fires 350 ms after screen/tab change)

   DOES NOT OWN:
     - tabContentKey / idbReadAll / idbPut / idbDelete — global helpers
       in Cluster A (bundle-a.js); accessed as bare names via window.
     - __scrollEl — window global set by the main scroll container's ref
       callback in App(); read directly as a global (no import needed).
     - tabsOverviewOpenRef — callers pass tabsOverviewOpen as a param;
       an internal ref mirror provides the synchronous read inside the
       capture callback.

   PARAMS:
     tabs              — full tabs array (useTabs). For the GC live-key
                         set + tabsRef.
     activeTabIdx      — active tab index (useTabs). For activeTabIdxRef.
     activeTab         — active tab object (useTabs); screen/bookId/etc.
                         used as effect deps for the after-nav trigger.
     tabsEnabled       — settings.tabsEnabled (useSettings); gates capture
                         everywhere.
     tabsOverviewOpen  — boolean (App()-local state); suppresses capture
                         while the Tabs Overview overlay is up.

   RETURNS: { tabThumbnails, setTabThumbnails, captureActiveTabThumbnail }

   STORAGE:
     IndexedDB — written via idbPut(key, dataUrl); read via idbReadAll()
     on mount. Keys are content-signature strings produced by
     tabContentKey(tab) — survive tab-index shifts (close/reorder).

   WINDOW: none — no window.__* handler bridges wired. The native capture
     fast-path CALLS window.AndroidBridge.takeScreenshot() (a native
     method, absent on desktop → html2canvas fallback); that is a call,
     not a bridge this hook owns or must clean up.

   ┌─ HARD INVARIANT — captureActiveTabThumbnail identity stability ───────┐
   │ captureActiveTabThumbnail MUST be the direct return value of          │
   │ React.useCallback with dependency array [tabsEnabled]. The scroll-    │
   │ stop and after-nav effects list it in their dep arrays and re-attach  │
   │ their listeners when its identity changes — stability is load-bearing.│
   └───────────────────────────────────────────────────────────────────────┘
   ═══════════════════════════════════════════════════════════════════════ */

import { useRefMirror } from './use-ref-mirror.js';

export function useThumbnails({
  tabs,
  activeTabIdx,
  activeTab,
  tabsEnabled,
  tabsOverviewOpen,
}) {
  // ── State ──────────────────────────────────────────────────────────────
  const [tabThumbnails, setTabThumbnails] = React.useState({});

  // ── Load previously-saved thumbnails on mount ──────────────────────────
  React.useEffect(() => {
    let cancelled = false;
    idbReadAll().then((thumbs) => {
      if (cancelled) return;
      setTabThumbnails(thumbs || {});
    });
    return () => { cancelled = true; };
  }, []);

  // ── Garbage-collect stale thumbnails ───────────────────────────────────
  // Debounced so we don't thrash during rapid tab edits.
  const thumbGcTimerRef = React.useRef(null);
  React.useEffect(() => {
    clearTimeout(thumbGcTimerRef.current);
    thumbGcTimerRef.current = setTimeout(() => {
      const liveKeys = new Set(tabs.map((t) => tabContentKey(t)));
      const deadKeys = Object.keys(tabThumbnails).filter((k) => !liveKeys.has(k));
      if (deadKeys.length === 0) return;
      deadKeys.forEach((k) => idbDelete(k));
      setTabThumbnails((prev) => {
        const out = {};
        for (const k of Object.keys(prev)) if (liveKeys.has(k)) out[k] = prev[k];
        return out;
      });
    }, 2000);
    return () => clearTimeout(thumbGcTimerRef.current);
  }, [tabs, tabThumbnails]);

  // ── Refs ───────────────────────────────────────────────────────────────
  const activeTabIdxRef = useRefMirror(activeTabIdx);
  const tabsRef = useRefMirror(tabs);
  const tabsOverviewOpenRef = useRefMirror(tabsOverviewOpen);
  const captureInFlightRef = React.useRef(false);
  const thumbnailsRef = React.useRef({});

  // ── Capture callback ───────────────────────────────────────────────────
  // HARD INVARIANT: must be React.useCallback with dep array [tabsEnabled].
  const captureActiveTabThumbnail = React.useCallback(() => {
    if (!tabsEnabled) return;
    if (tabsOverviewOpenRef.current) return; // overview open → no point capturing
    if (captureInFlightRef.current) return;
    const tab = tabsRef.current[activeTabIdxRef.current];
    if (!tab) return;
    const key = tabContentKey(tab);

    // Measure nav height (in CSS px) so the native side can crop it
    const navEl = document.querySelector('.top-nav');
    const navHeightDp = navEl ? Math.round(navEl.getBoundingClientRect().height) : 0;

    const applyThumb = (dataUrl) => {
      if (!dataUrl) return;
      thumbnailsRef.current[key] = dataUrl;
      setTabThumbnails((prev) => ({ ...prev, [key]: dataUrl }));
      idbPut(key, dataUrl); // write-through to IndexedDB — survives app restart
    };

    // Hide floating UI chrome (sticky arrows, reading dot) for the duration
    // of the capture so the thumbnail shows pure content only.
    document.body.classList.add('capturing-thumb');
    // Force a synchronous layout so the visibility:hidden takes effect
    // before we hand control to the native bridge.
    void document.body.offsetHeight;

    // Native fast path — synchronous because WebView JS interfaces run on
    // a worker thread; blocking here on the UI thread for ~50ms does not
    // deadlock. Synchronous is important: callers (like goTabs) need the
    // thumbnail captured BEFORE the overlay mounts and covers the screen.
    if (window.AndroidBridge && typeof window.AndroidBridge.takeScreenshot === 'function') {
      captureInFlightRef.current = true;
      try {
        const dataUrl = window.AndroidBridge.takeScreenshot(navHeightDp, 1440, 90);
        applyThumb(dataUrl);
      } catch (e) {}
      captureInFlightRef.current = false;
      document.body.classList.remove('capturing-thumb');
      return;
    }

    // html2canvas fallback (dev browser / no bridge)
    if (typeof html2canvas !== 'function') return;
    captureInFlightRef.current = true;
    const bg = document.body.classList.contains('light') ? '#f7f2e8' : '#07070e';
    try {
      html2canvas(document.body, {
        backgroundColor: bg,
        scale: Math.min(window.devicePixelRatio || 1, 2),
        useCORS: true, logging: false, allowTaint: false, imageTimeout: 2000,
        ignoreElements: (el) => el.classList && (
          el.classList.contains('tabs-overview-layer') ||
          el.classList.contains('top-nav') ||
          el.classList.contains('back-hint-row') ||
          el.classList.contains('chapter-nav-sticky') ||
          el.classList.contains('reading-dot-global') ||
          el.classList.contains('surprise-fab') ||
          el.classList.contains('mode-toggle-wrap'))
      }).then((canvas) => {
        const MAX_DIM = 1440;
        const w = canvas.width, h = canvas.height;
        const scale = Math.min(MAX_DIM / w, MAX_DIM / h, 1);
        let out = canvas;
        if (scale < 1) {
          const c2 = document.createElement('canvas');
          c2.width = Math.round(w * scale); c2.height = Math.round(h * scale);
          const ctx = c2.getContext('2d');
          ctx.imageSmoothingEnabled = true; ctx.imageSmoothingQuality = 'high';
          ctx.drawImage(canvas, 0, 0, c2.width, c2.height);
          out = c2;
        }
        applyThumb(out.toDataURL('image/jpeg', 0.90));
      }).catch(() => {}).finally(() => {
        captureInFlightRef.current = false;
        document.body.classList.remove('capturing-thumb');
      });
    } catch (e) {
      captureInFlightRef.current = false;
      document.body.classList.remove('capturing-thumb');
    }
  }, [tabsEnabled]);

  // ── Scroll-stop capture effect ─────────────────────────────────────────
  // Keep tab thumbnails fresh: capture on scroll-stop (300ms idle).
  React.useEffect(() => {
    let scrollTimer = null;
    let currentEl = null;
    const onScroll = () => {
      clearTimeout(scrollTimer);
      scrollTimer = setTimeout(captureActiveTabThumbnail, 300);
    };
    const attach = () => {
      if (__scrollEl !== currentEl) {
        if (currentEl) currentEl.removeEventListener("scroll", onScroll);
        currentEl = __scrollEl;
        if (currentEl) currentEl.addEventListener("scroll", onScroll, { passive: true });
      }
    };
    attach();
    const poll = setInterval(attach, 400);
    return () => {
      clearInterval(poll); clearTimeout(scrollTimer);
      if (currentEl) currentEl.removeEventListener("scroll", onScroll);
    };
  }, [captureActiveTabThumbnail]);

  // ── Aspect-ratio CSS var effect ────────────────────────────────────────
  // Keep tab-card aspect ratio in sync with the viewport so
  // thumbnails fill their cards without crop or distortion.
  React.useEffect(() => {
    const update = () => {
      const w = window.innerWidth || 1, h = window.innerHeight || 1;
      document.documentElement.style.setProperty('--card-ar', w + ' / ' + h);
    };
    update();
    window.addEventListener('resize', update);
    return () => window.removeEventListener('resize', update);
  }, []);

  // ── Capture-after-nav effect ───────────────────────────────────────────
  // Capture shortly after any screen/tab change.
  React.useEffect(() => {
    if (!tabsEnabled) return;
    if (tabsOverviewOpen) return;
    const timer = setTimeout(captureActiveTabThumbnail, 350);
    return () => clearTimeout(timer);
  }, [activeTab.screen, activeTab.bookId, activeTab.chapterNum, activeTab.letterId,
  activeTab.studyId, activeTab.studyChapterId, activeTab.genreId,
  activeTab.gardenPage, activeTabIdx, tabsEnabled, tabsOverviewOpen,
  captureActiveTabThumbnail]);

  // ── Return ─────────────────────────────────────────────────────────────
  return { tabThumbnails, setTabThumbnails, captureActiveTabThumbnail };
}

/* ═══════════════════════════════════════════════════════════════════════
   annotation-engine — Cluster C (esbuild bundle-c.js)
   ═══════════════════════════════════════════════════════════════════════
   ANNOTATION RENDERING ENGINE — highlights · underlines · notes

   Exposed:
     snapRangeToWords(text,start,end) → {start,end}
     HighlightableText(props)         → React component (Bible/study verses)
     findNoteIconInsertionPoint(mark) → insertion descriptor
     applyNoteIcons()                 → void (DOM mutation)
     applyActiveNoteState()           → void (DOM mutation)
     applyDOMHighlights()             → void (DOM mutation)
     StaticSubtree                    → React.Component (freeze wrapper)
   ═══════════════════════════════════════════════════════════════════════ */

/* Snap an annotation range to whole-word boundaries. */
export function snapRangeToWords(text, start, end) {
  if (!text || typeof text !== 'string') return { start, end };
  start = Math.max(0, Math.min(start, text.length));
  end = Math.max(0, Math.min(end, text.length));
  const isWord = (c) => !!c && /[\w’’-]/.test(c);
  while (start > 0 && isWord(text[start - 1]) && isWord(text[start])) start--;
  return { start, end };
}

/* Build the className for a mark based on annotation kind. */
function annMarkClass(ann, isFirst, isLast) {
  const kind = ann.kind || 'highlight';
  if (kind === 'note') {
    return 'hl-mark hl-note hl-' + ann.color +
      (isFirst ? ' first-segment' : '') +
      (isLast ? ' last-segment' : '');
  }
  if (kind === 'underline') return 'hl-mark hl-underline hl-' + ann.color;
  return 'hl-mark hl-' + ann.color;
}

/* HighlightableText renders text with overlap-aware nested marks via a
   sweep-line algorithm. Sorted boundaries → constant-active-set segments
   → inside-out <mark> nesting per segment using reduceRight (outer = i=0,
   inner = i=N-1; CSS cascade gives "more-specific overrides broader"). */
export function HighlightableText({ text, hlKey, hlTick }) {
  const annotations = React.useMemo(() => AnnotationStore.get(hlKey), [hlKey, hlTick]);
  if (!text) return null;
  if (!annotations || annotations.length === 0) {
    return <span data-hl-key={hlKey}>{text}</span>;
  }
  // Clamp ranges to text bounds and drop empties
  const valid = annotations
    .map(a => ({ ann: a, s: Math.max(0, Math.min(a.start, text.length)), e: Math.max(0, Math.min(a.end, text.length)) }))
    .filter(v => v.s < v.e);
  if (valid.length === 0) {
    return <span data-hl-key={hlKey}>{text}</span>;
  }
  // Build sweep boundaries
  const set = new Set([0, text.length]);
  valid.forEach(v => { set.add(v.s); set.add(v.e); });
  const positions = [...set].sort((x, y) => x - y);
  // Compute segments (each with the active annotations)
  const segments = [];
  for (let i = 0; i < positions.length - 1; i++) {
    const ss = positions[i], se = positions[i + 1];
    if (ss >= se) continue;
    const active = valid
      .filter(v => v.s <= ss && v.e >= se)
      .map(v => v.ann)
      .sort((a, b) => a.start - b.start || (a.id || '').localeCompare(b.id || ''));
    segments.push({ start: ss, end: se, active });
  }
  // Track first/last segment per group so the first-segment/last-segment
  // classes (used by tap routing helpers like applyNoteIcons) are accurate.
  const firstSegByGroup = new Map();
  const lastSegByGroup = new Map();
  segments.forEach((seg, idx) => {
    seg.active.forEach(a => {
      if (!firstSegByGroup.has(a.groupId)) firstSegByGroup.set(a.groupId, idx);
      lastSegByGroup.set(a.groupId, idx);
    });
  });
  // Mid-word boundary detection.
  const isWordChar = (c) => !!c && /[\w’'-]/.test(c);
  segments.forEach((seg, idx) => {
    if (idx < segments.length - 1) {
      const lastCh = text[seg.end - 1];
      const nextCh = text[seg.end];
      if (isWordChar(lastCh) && isWordChar(nextCh)) seg.noBreakAfter = true;
    }
  });
  return (
    <span data-hl-key={hlKey}>
      {segments.map((seg, segIdx) => {
        const segText = text.slice(seg.start, seg.end);
        if (seg.active.length === 0) {
          // Plain text — wrap in a span only if we need the no-break-after marker.
          if (seg.noBreakAfter) {
            return <span key={'p' + segIdx} data-no-break-after="1">{segText}</span>;
          }
          return <React.Fragment key={'p' + segIdx}>{segText}</React.Fragment>;
        }
        // Inside-out: reduceRight wraps innermost (i = active.length - 1)
        // first, working outward. Outer element (i = 0) is what React keys
        // off — gets the segment-level key; inner elements get composite keys.
        return seg.active.reduceRight((child, ann, i) => {
          const kind = ann.kind || 'highlight';
          const isFirst = firstSegByGroup.get(ann.groupId) === segIdx;
          const isLast = lastSegByGroup.get(ann.groupId) === segIdx;
          const isOutermost = i === 0;
          const props = {
            key: isOutermost ? 'm' + segIdx : 'm' + segIdx + '_' + i,
            className: annMarkClass(ann, isFirst, isLast),
            'data-hl-id': ann.id,
            'data-group-id': ann.groupId,
            'data-kind': kind,
          };
          if (isOutermost && seg.noBreakAfter) props['data-no-break-after'] = '1';
          return <mark {...props}>{child}</mark>;
        }, segText);
      })}
    </span>
  );
}

/* ═══════════════════════════════════════════════════════════════
   DOM-BASED HIGHLIGHT OVERLAY (unchanged — imperative DOM mutation)
═══════════════════════════════════════════════════════════════ */
export function findNoteIconInsertionPoint(mark) {
  const container = mark.closest('[data-hl-key]');
  if (!container) return { kind: 'afterMark' };
  const boundaryRx = /[\s.,;:!?)\]}”’—\-]/;
  const walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT, null, false);
  let pastMark = false;
  while (walker.nextNode()) {
    const tn = walker.currentNode;
    if (mark.contains(tn)) { pastMark = true; continue; }
    if (!pastMark) continue;
    const text = tn.nodeValue;
    if (text.length === 0) continue;
    if (boundaryRx.test(text[0])) return { kind: 'afterMark' };
    const m = text.match(boundaryRx);
    if (m) {
      const splitAt = m.index + 1;
      if (splitAt >= text.length) return { kind: 'afterMark' };
      const tail = tn.splitText(splitAt);
      return { kind: 'beforeNode', node: tail };
    }
  }
  return { kind: 'afterMark' };
}

/* Char offset from container start to position immediately AFTER a mark. */
function _markCharEnd(mark) {
  const container = mark.closest('[data-hl-key]');
  if (!container) return -1;
  try {
    const range = document.createRange();
    range.selectNodeContents(container);
    range.setEndAfter(mark);
    return range.toString().length;
  } catch (e) { return -1; }
}

export function applyNoteIcons() {
  document.querySelectorAll('.hl-note-icon').forEach(el => el.remove());
  const lastByGroup = new Map();
  document.querySelectorAll('mark.hl-note[data-group-id]').forEach(mark => {
    lastByGroup.set(mark.getAttribute('data-group-id'), mark);
  });
  const groupsByTarget = new Map();
  lastByGroup.forEach((mark, gid) => {
    const ip = findNoteIconInsertionPoint(mark);
    const container = mark.closest('[data-hl-key]');
    const hlKey = container ? container.getAttribute('data-hl-key') : '';
    const charEnd = _markCharEnd(mark);
    const key = hlKey + ':' + charEnd;
    if (!groupsByTarget.has(key)) groupsByTarget.set(key, []);
    groupsByTarget.get(key).push({ gid, mark, ip });
  });

  groupsByTarget.forEach(entries => {
    const primary = entries[0];
    const allGids = entries.map(e => e.gid);
    const container = primary.mark.closest('[data-hl-key]');
    const hlKey = container ? container.getAttribute('data-hl-key') : '';
    const colorClass = (primary.mark.className.match(/\bhl-(yellow|green|pink|red|orange|blue|purple|teal|brown|gray|cyan)\b/) || [])[0] || '';
    const icon = document.createElement('span');
    icon.className = 'hl-note-icon' + (colorClass ? ' ' + colorClass : '') + (entries.length > 1 ? ' hl-note-icon-badge' : '');
    icon.setAttribute('data-group-id', primary.gid);
    icon.setAttribute('data-group-ids', allGids.join(','));
    icon.setAttribute('data-hl-key', hlKey);
    if (entries.length > 1) icon.setAttribute('data-count', String(entries.length));
    icon.title = entries.length > 1 ? (entries.length + ' notes here') : 'Open note';
    icon.innerHTML = '<svg viewBox="0 0 24 24"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="8" y1="13" x2="16" y2="13"/><line x1="8" y1="17" x2="16" y2="17"/></svg>';
    var _openIcon = function(x, y) {
      if (entries.length > 1 && window.__showMultiNote) {
        window.__showMultiNote(allGids, x, y);
      } else if (window.__openNote) {
        window.__openNote(primary.gid);
      }
    };
    icon.addEventListener('click', function(e) {
      e.stopPropagation();
      _openIcon(e.clientX, e.clientY);
    });
    icon.addEventListener('touchend', function(e) {
      e.preventDefault();
      e.stopPropagation();
      var t = e.changedTouches && e.changedTouches[0];
      _openIcon(t ? t.clientX : 0, t ? t.clientY : 0);
    });
    const ip = primary.ip;
    const ipUsable = ip.kind === 'beforeNode' && ip.node && ip.node.parentNode
      && container && container.contains(ip.node);
    if (ipUsable) {
      const prev = ip.node.previousSibling;
      if (prev && prev.nodeType === 3 && / $/.test(prev.nodeValue)) {
        prev.nodeValue = prev.nodeValue.replace(/ $/, '');
        ip.node.nodeValue = ' ' + ip.node.nodeValue;
      }
      ip.node.parentNode.insertBefore(icon, ip.node);
    } else if (primary.mark.parentNode && primary.mark.nextSibling) {
      primary.mark.parentNode.insertBefore(icon, primary.mark.nextSibling);
    } else if (primary.mark.parentNode) {
      primary.mark.parentNode.appendChild(icon);
    }
  });
}

export function applyActiveNoteState() {
  document.querySelectorAll('.hl-note.is-active, .hl-note-icon.is-active')
    .forEach(el => el.classList.remove('is-active'));
  const gid = window.__activeNoteGroup;
  if (!gid) return;
  const safe = String(gid).replace(/"/g, '\\"');
  document.querySelectorAll('mark.hl-note[data-group-id="' + safe + '"], .hl-note-icon[data-group-id="' + safe + '"]')
    .forEach(el => el.classList.add('is-active'));
}

export function applyDOMHighlights() {
  document.querySelectorAll('[data-hl-key]').forEach(function(container) {
    if (container.querySelector('mark.hl-mark[data-hl-id]') || container.childElementCount === 0 && container.textContent && !container.querySelector('mark.hl-dom')) {
      if (!container.hasAttribute('data-hl-dom')) return;
    }
    if (!container.hasAttribute('data-hl-dom')) return;

    var hlKey = container.getAttribute('data-hl-key');
    var existing = container.querySelectorAll('mark.hl-dom');
    for (var i = 0; i < existing.length; i++) {
      var mark = existing[i];
      var parent = mark.parentNode;
      while (mark.firstChild) parent.insertBefore(mark.firstChild, mark);
      parent.removeChild(mark);
    }
    container.querySelectorAll('.hl-note-icon').forEach(function(el) { el.remove(); });
    container.normalize();

    var anns = AnnotationStore.get(hlKey);
    if (!anns.length) return;

    var sorted = anns.slice().sort(function(a, b) { return a.start - b.start; });
    var groupCounts = {};
    sorted.forEach(function(a) { groupCounts[a.groupId] = (groupCounts[a.groupId] || 0) + 1; });
    var groupSeen = {};

    for (var hi = 0; hi < sorted.length; hi++) {
      var ann = sorted[hi];
      var seenIdx = groupSeen[ann.groupId] || 0;
      var isFirst = seenIdx === 0;
      var isLast = seenIdx === groupCounts[ann.groupId] - 1;
      groupSeen[ann.groupId] = seenIdx + 1;
      var kind = ann.kind || 'highlight';

      var walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT, null, false);
      var textNodes = [];
      var charPos = 0;
      while (walker.nextNode()) {
        var node = walker.currentNode;
        textNodes.push({ node: node, start: charPos, end: charPos + node.length });
        charPos += node.length;
      }
      var lastMark = null;
      for (var ti = 0; ti < textNodes.length; ti++) {
        var tn = textNodes[ti];
        var overlapStart = Math.max(ann.start, tn.start);
        var overlapEnd = Math.min(ann.end, tn.end);
        if (overlapStart >= overlapEnd) continue;
        var localStart = overlapStart - tn.start;
        var localEnd = overlapEnd - tn.start;
        var tNode = tn.node;
        if (localEnd < tNode.length) tNode.splitText(localEnd);
        var midNode = localStart > 0 ? tNode.splitText(localStart) : tNode;
        var m = document.createElement('mark');
        var cls = 'hl-mark hl-dom hl-' + ann.color;
        if (kind === 'underline') cls += ' hl-underline';
        else if (kind === 'note') {
          cls += ' hl-note';
          if (isFirst && ti === textNodes.findIndex(function(x) { return Math.max(ann.start, x.start) < Math.min(ann.end, x.end); })) cls += ' first-segment';
        }
        m.className = cls;
        m.setAttribute('data-hl-id', ann.id);
        m.setAttribute('data-group-id', ann.groupId);
        m.setAttribute('data-kind', kind);
        midNode.parentNode.replaceChild(m, midNode);
        m.appendChild(midNode);
        lastMark = m;
      }
      if (kind === 'note' && lastMark) lastMark.classList.add('last-segment');
      if (lastMark) {
        var fullText = container.textContent;
        var lastCh = fullText.charAt(ann.end - 1);
        var nextCh = fullText.charAt(ann.end);
        if (lastCh && nextCh && /[\w’'-]/.test(lastCh) && /[\w’'-]/.test(nextCh)) {
          lastMark.setAttribute('data-no-break-after', '1');
        }
      }
    }
  });
}

/* StaticSubtree — renders its children exactly ONCE and then blocks React
   from ever reconciling them again (shouldComponentUpdate → false).
   See the original file comment for the full rationale (applyDOMHighlights
   splitText/replaceChild races with React reconciliation of the same
   subtree → NotFoundError on removeChild). */
export class StaticSubtree extends React.Component {
  shouldComponentUpdate() { return false; }
  render() { return this.props.children; }
}

/* ═══════════════════════════════════════════════════════════════
   DOM BOOKMARK ICONS — inline flag icon injection for [data-hl-dom] containers
   ═══════════════════════════════════════════════════════════════
   Global-scope module. Concatenates with index.html; no import/export.
   Depends on: BookmarkStore (defined in src/stores/bookmark-store.js).

   applyDOMBookmarks() is called from the post-render useEffect in App()
   after every hlTick change (same effect that calls applyDOMLinks).
   It:
     1. Removes any existing .inline-bookmark-icon elements
     2. Finds all bookmarks that touch each [data-hl-dom] container
     3. Inserts a small flag icon at the bookmarked text range endpoint

   Icon placement reuses the same slide-off rules as applyDOMLinks:
     1. Mid-word → slide forward to word boundary
     2. Closing punctuation → slide past (., ; : ! ? etc.)
     3. Adjacent skip elements (fn-ref, tap-ref, letter-link-ref,
        note-icon, verse-link-icon, inline-link-icon) → jump past

   Multiple bookmarks ending at the same offset merge into one icon
   with a count badge.

   CSS: .inline-bookmark-icon is defined in the main index.html CSS block.
   Tap opens the bookmark popover via window.__openBookmarkPopover(ids, x, y).
═══════════════════════════════════════════════════════════════ */

/* Window (ms) during which a freshly-created bookmark gets the .just-created
   class so its icon plays the creation-pulse animation. Re-renders of the
   same icon (after the window expires) drop the class. */
var BOOKMARK_PULSE_WINDOW_MS = 3000;

export function applyDOMBookmarks() {
  var nowMs = Date.now();
  document.querySelectorAll('[data-hl-key][data-hl-dom]').forEach(function(container) {
    var hlKey = container.getAttribute('data-hl-key');
    container.querySelectorAll('.inline-bookmark-icon').forEach(function(el) { el.remove(); });
    container.normalize();

    var bookmarks = BookmarkStore.getForKeyPrefix(hlKey);
    if (!bookmarks.length) return;

    // Build a quick lookup: bkm.id → bkm so we can check `.created` per icon.
    var bkmById = {};
    bookmarks.forEach(function(b) { bkmById[b.id] = b; });

    // Collect end positions, merging duplicates so multiple bookmarks at
    // the same offset share one icon.  We track the list of bookmark ids at
    // each position so the tap handler can surface all of them.
    var keyPrefix = hlKey + ':';
    var byEndPos = {}; // endPos → [bkmId, ...]
    bookmarks.forEach(function(bkm) {
      if (!bkm.hlKey) return;
      var k = bkm.hlKey;
      if (k !== hlKey && k.indexOf(keyPrefix) !== 0) return;

      var endPos = null;
      var m = k.match(/:(\d+)-(\d+)$/);
      if (m) {
        endPos = parseInt(m[2], 10);
      }
      // Bookmarks without a ":start-end" suffix land at end-of-block
      if (endPos == null) {
        if (!byEndPos[-1]) byEndPos[-1] = [];
        byEndPos[-1].push(bkm.id);
        return;
      }
      if (!byEndPos[endPos]) byEndPos[endPos] = [];
      byEndPos[endPos].push(bkm.id);
    });

    // Helper: does this group include any bookmark created within the
    // pulse window? Drives the .just-created class on the rendered icon.
    function anyJustCreated(bkmIds) {
      return bkmIds.some(function(id) {
        var b = bkmById[id];
        return b && b.created && (nowMs - b.created) < BOOKMARK_PULSE_WINDOW_MS;
      });
    }

    // End-of-block fallback (no ":start-end" in key)
    if (byEndPos[-1] && byEndPos[-1].length > 0) {
      var endBlockIcon = _buildBookmarkIcon(hlKey, byEndPos[-1]);
      if (anyJustCreated(byEndPos[-1])) endBlockIcon.classList.add('just-created');
      container.appendChild(endBlockIcon);
      delete byEndPos[-1];
    }

    if (Object.keys(byEndPos).length === 0) return;

    // Process highest position first so earlier insertions don't shift offsets.
    var positions = Object.keys(byEndPos).map(Number).sort(function(a, b) { return b - a; });
    positions.forEach(function(endPos) {
      _insertBookmarkIconAt(container, hlKey, endPos, byEndPos[endPos], anyJustCreated(byEndPos[endPos]));
    });
  });
}

/* Build the inline bookmark flag icon element.
   bkmIds is an array of bookmark IDs at this position. */
function _buildBookmarkIcon(hlKey, bkmIds) {
  var icon = document.createElement('span');
  icon.className = 'inline-bookmark-icon';
  if (bkmIds && bkmIds.length > 1) icon.className += ' inline-bookmark-icon-multi';
  icon.setAttribute('data-bkm-ids', (bkmIds || []).join(','));
  icon.setAttribute('data-hl-key', hlKey);
  var count = (bkmIds || []).length;
  icon.title = count === 1 ? 'Bookmark' : count + ' bookmarks';

  // Bookmark flag SVG. Note: explicit `fill="currentColor"` and
  // `stroke="currentColor"` ATTRIBUTES on the path (not just CSS) —
  // Android WebView (notably older Chromium-derived versions) does NOT
  // reliably inherit CSS `fill` from the parent <svg> through to child
  // <path> elements injected via innerHTML, leaving the path invisible
  // on device even though the preview works fine on desktop. Setting
  // the attributes directly is the safer cross-WebView path.
  icon.innerHTML = '<svg viewBox="0 0 24 24" fill="currentColor" stroke="currentColor"><path fill="currentColor" stroke="currentColor" stroke-width="1.5" stroke-linejoin="round" d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z"/></svg>';

  var openIcon = function(e) {
    e.preventDefault();
    e.stopPropagation();
    var ids = (icon.getAttribute('data-bkm-ids') || '').split(',').filter(Boolean);
    if (ids.length === 1) {
      // Single bookmark at this position — open the full create/edit
      // sheet so the user gets the same UI as creation: editable label
      // + thought + Delete. Consistent UX whether they're making a new
      // bookmark or revisiting an existing one.
      // atSource:true tells the sheet to suppress the "Open Source"
      // button — the user tapped the icon AT the source, so navigation
      // there would be a no-op.
      if (window.__bookmarkEdit) { window.__bookmarkEdit(ids[0], { atSource: true }); return; }
    }
    // Multi-bookmark or fallback: the popover still serves
    // disambiguation. Tapping a popover row routes onward to whatever
    // single-bookmark UI is wired (currently still the popover's own
    // Open/Delete actions — that's intentional for the rare overlap case).
    var rect = icon.getBoundingClientRect();
    var x = rect.left + rect.width / 2;
    var y = rect.bottom + 4;
    if (window.__openBookmarkPopover) {
      window.__openBookmarkPopover(ids, x, y, hlKey);
    }
  };
  icon.addEventListener('click', openIcon);
  icon.addEventListener('touchend', openIcon);
  return icon;
}

function _insertBookmarkIconAt(container, hlKey, endPos, bkmIds, justCreated) {
  var WORD = /[\w''\-]/;
  var CLOSE_PUNCT = /[.,;:!?)\]}"'…—]/;
  // Elements the icon must NOT land directly before — reuses the same
  // skip list as _insertLinkIconAt.
  var SKIP_RX = /\b(fn-ref|tap-ref|letter-link-ref|verse-link-icon|hl-note-icon|inline-link-icon|inline-bookmark-icon)\b/;

  function isSkip(el) {
    return el && el.nodeType === 1 && el.className && SKIP_RX.test(el.className);
  }
  function isPhraseChar(c) { return !!c && (WORD.test(c) || CLOSE_PUNCT.test(c)); }

  function nextInsertionPoint(node) {
    var cur = node;
    while (cur && cur !== container) {
      var sib = cur.nextSibling;
      if (sib === null) {
        cur = cur.parentElement;
        continue;
      }
      if (isSkip(sib)) {
        cur = sib;
        continue;
      }
      return sib;
    }
    return null;
  }

  // Gather all text nodes in document order.
  var textNodes = [];
  var w = document.createTreeWalker(container, NodeFilter.SHOW_TEXT, null, false);
  while (w.nextNode()) textNodes.push(w.currentNode);

  var charPos = 0, nodeIdx = -1, localOffset = 0;
  for (var i = 0; i < textNodes.length; i++) {
    var nodeEnd = charPos + textNodes[i].length;
    if (endPos > charPos && endPos <= nodeEnd) {
      nodeIdx = i;
      localOffset = endPos - charPos;
      break;
    }
    charPos = nodeEnd;
  }
  if (nodeIdx < 0) {
    var fallbackIcon = _buildBookmarkIcon(hlKey, bkmIds);
    if (justCreated) fallbackIcon.classList.add('just-created');
    container.appendChild(fallbackIcon);
    return;
  }

  // If endPos is inside a skip element, slide past it.
  var ancestor = textNodes[nodeIdx].parentElement;
  var skipAncestor = null;
  while (ancestor && ancestor !== container) {
    if (isSkip(ancestor)) skipAncestor = ancestor;
    ancestor = ancestor.parentElement;
  }
  if (skipAncestor) {
    var ref = nextInsertionPoint(skipAncestor);
    var icon = _buildBookmarkIcon(hlKey, bkmIds);
    if (justCreated) icon.classList.add('just-created');
    if (ref) ref.parentNode.insertBefore(icon, ref);
    else container.appendChild(icon);
    return;
  }

  var BLOCK_TAGS = /^(BR|P|DIV|H[1-6]|LI|BLOCKQUOTE|HR|UL|OL|TR|TD|TH|TABLE|SECTION|ARTICLE|HEADER|FOOTER|NAV|MAIN|FIGURE|FIGCAPTION|PRE|ADDRESS)$/;
  function hasBlockBetween(prev, next) {
    var bw = document.createTreeWalker(container, NodeFilter.SHOW_ALL, null, false);
    bw.currentNode = prev;
    var n;
    while ((n = bw.nextNode())) {
      if (n === next) return false;
      if (n.nodeType === 1 && BLOCK_TAGS.test(n.tagName)) return true;
    }
    return true;
  }

  // Slide forward through phrase characters, crossing inline boundaries.
  while (true) {
    var text = textNodes[nodeIdx].nodeValue;
    while (localOffset < text.length && isPhraseChar(text[localOffset])) {
      localOffset++;
    }
    if (localOffset < text.length) break;
    var nextNodeIdx = nodeIdx + 1;
    while (nextNodeIdx < textNodes.length) {
      var na = textNodes[nextNodeIdx].parentElement;
      var inSkip = false;
      while (na && na !== container) {
        if (isSkip(na)) { inSkip = true; break; }
        na = na.parentElement;
      }
      if (!inSkip) break;
      nextNodeIdx++;
    }
    if (nextNodeIdx >= textNodes.length) break;
    if (hasBlockBetween(textNodes[nodeIdx], textNodes[nextNodeIdx])) break;
    nodeIdx = nextNodeIdx;
    localOffset = 0;
  }

  var finalNode = textNodes[nodeIdx];
  var finalText = finalNode.nodeValue;
  var insertBeforeNode = null;
  if (localOffset >= finalText.length) {
    insertBeforeNode = nextInsertionPoint(finalNode);
  } else if (localOffset === 0) {
    insertBeforeNode = finalNode;
  } else {
    insertBeforeNode = finalNode.splitText(localOffset);
  }
  var iconEl = _buildBookmarkIcon(hlKey, bkmIds);
  if (justCreated) iconEl.classList.add('just-created');
  if (insertBeforeNode) {
    insertBeforeNode.parentNode.insertBefore(iconEl, insertBeforeNode);
  } else {
    container.appendChild(iconEl);
  }
}

/* ═══════════════════════════════════════════════════════════════════════
   dom-journal-chip — Cluster C (esbuild bundle-c.js)
   ═══════════════════════════════════════════════════════════════════════
   Defines JournalChip + the jrnRefKey helper functions. JournalChip is a
   normal React component; the helpers are pure refKey builders.
   ═══════════════════════════════════════════════════════════════════════ */

export function JournalChip({ refKey, hlTick, onClick, label }) {
  var useMemo = React.useMemo;
  // Hooks must be called unconditionally on every render — no early return
  // before useMemo, or React detects the changed hook count and throws.
  var ids = useMemo(function() {
    if (!refKey || typeof JournalIndexStore === 'undefined') return [];
    return JournalIndexStore.entriesReferencing(refKey);
  }, [refKey, hlTick]);
  if (!refKey || !ids || ids.length === 0) return null;

  return (
    <button
      className="nav-search-btn jrn-inbound-chip"
      onClick={function() { onClick && onClick(refKey, label); }}
      title={ids.length + ' journal ' + (ids.length === 1 ? 'entry' : 'entries')}
      aria-label="Journal entries"
    >
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round" style={{ color: 'var(--gold)' }}>
        <path d="M7 4h10a2 2 0 012 2v14l-7-3-7 3V6a2 2 0 012-2z" />
        <path d="M9 9h6M9 13h4" />
      </svg>
      <span className="jrn-inbound-chip-badge">{ids.length}</span>
    </button>
  );
}

/* Build the refKey for the current context — exposed for index.html
   wiring convenience. */
export function jrnRefKeyForLetter(volKey, letterId) {
  return (volKey && letterId) ? ('letter:' + volKey + '/' + letterId) : null;
}
export function jrnRefKeyForChapter(bookId, chapter) {
  return (bookId && chapter != null) ? ('chapter:' + bookId + ':' + chapter) : null;
}
export function jrnRefKeyForBookmark(bookmarkId) {
  return bookmarkId ? ('bookmark:' + bookmarkId) : null;
}

/* Resolve a letter refKey from the collection's display label (e.g.
   'Volume Two') and a letterId. */
export function jrnRefKeyForLetterByLabel(volumeLabel, letterId) {
  if (!volumeLabel || !letterId || typeof COLLECTIONS === 'undefined') return null;
  for (var i = 0; i < COLLECTIONS.length; i++) {
    if (COLLECTIONS[i].label === volumeLabel) {
      return 'letter:' + COLLECTIONS[i].volKey + '/' + letterId;
    }
  }
  return null;
}

/* ═══════════════════════════════════════════════════════════════
   DOM LINK ICONS — inline chain icon injection for [data-hl-dom] containers
   ═══════════════════════════════════════════════════════════════
   Global-scope module. Concatenates with index.html; no import/export.
   Depends on: LinkStore (defined in src/stores/link-store.js).

   applyDOMLinks() is called from the post-render useEffect in App()
   after every hlTick change. It:
     1. Removes any existing .inline-link-icon elements
     2. Finds all links that touch each [data-hl-dom] container
     3. Inserts a chain icon at (or near) each linked text range endpoint
     4. Applies visual distinction: source icons (user originated the link)
        render at --gold; target icons (destination of a link from elsewhere)
        render at --gold-dim.

   Icon placement logic ("slide-off" rules):
     1. Mid-word → slide forward to word boundary
     2. Closing punctuation → slide past (., ; : ! ? etc.)
     3. Adjacent skip elements (fn-ref, tap-ref, letter-link-ref, note-icon,
        verse-link-icon) → jump past to keep their tap targets clear

   CSS: .inline-link-icon and .inline-link-icon-source are defined in
   the main index.html CSS block (part of the const CSS template literal).
═══════════════════════════════════════════════════════════════ */

/* Inject inline chain icons at the end of each linked text range inside
   [data-hl-dom] containers. Re-runs on every hlTick. Click → onLinkOpen(blockKey)
   which opens the sidebar showing all links touching that block. */
/* Inline link icons — placed at (or as close as possible to) the END
   of each linked text range. The icon "slides off" three kinds of bad
   placement so it never interrupts content:

     1. Mid-word — slide forward to the end of the current word.
        (Defensive: snapRangeToWords already aligns starts on word
        boundaries, but the parallel-session change to snapRangeToWords
        deliberately leaves END exactly where the user released — so
        the user can intentionally end mid-word but the icon shouldn't.)
     2. Closing punctuation — slide past `.,;:!?)...` and friends so
        the icon reads as belonging to the word, not splitting the
        punctuation off ("word."[icon] instead of "word"[icon]".").
     3. Adjacent fn-ref / scripture-ref / letter-link / note-icon /
        verse-link-icon — slide PAST these inline elements so the
        icon never lands directly before one (where, on Android, the
        icon would block the tap target — the original bug that drove
        the parallel session to end-of-paragraph placement).

   Multiple links ending at the same offset merge into one icon with
   a `title` count; tapping any icon opens the link sidebar for the
   block, which lists every link touching it.

   CSS: `.inline-link-icon` no longer sets `user-select: none` — the
   span is empty (SVG paths can't be selected anyway), and dropping
   the `none` lets drag-selection pass across the icon on Android
   without breaking. */
export function applyDOMLinks() {
  document.querySelectorAll('[data-hl-key][data-hl-dom]').forEach(function(container) {
    var hlKey = container.getAttribute('data-hl-key');
    container.querySelectorAll('.inline-link-icon').forEach(function(el) { el.remove(); });
    container.normalize();

    var links = LinkStore.getForKeyPrefix(hlKey);
    if (!links.length) return;

    // Collect end positions for endpoints attached to this container
    // (either the block itself or a more-specific subkey), merging
    // duplicates so two links ending at the same offset become one
    // icon with count=2.
    //
    // End position can live in two places depending on how the endpoint
    // was built:
    //   (a) A `:N-M` suffix on the key — used by target endpoints that
    //       went through verse-picker / excerpt-picker refinement
    //       (e.g. "letter:foo:2:42-87" or "bible:genesis:1:1").
    //   (b) Separate `start`/`end` fields on the endpoint object — used
    //       by SOURCE endpoints, which carry the user's selection range
    //       but keep the key bare (e.g. key="letter:workers:1",
    //       start=42, end=87, text="...sentence...").
    //
    // Without the (b) fallback, the icon for the source side of an
    // excerpt-to-excerpt link couldn't find its position and slid all
    // the way to end-of-paragraph — the regression the user reported.
    var keyPrefix = hlKey + ':';
    // byEndPos tracks { count, anySource } per character offset.
    // anySource=true means at least one link has THIS container as its origin
    // (source side) — icon renders at full gold. False means container is
    // only ever a destination (target side) — renders dimmer (gold-dim).
    var byEndPos = {};
    links.forEach(function(link) {
      // isSourceHere = the source endpoint belongs to this container
      var srcKey = link.source ? link.source.key : null;
      var isSourceHere = srcKey && (srcKey === hlKey || srcKey.indexOf(keyPrefix) === 0);

      [link.source, link.target].forEach(function(ep) {
        if (!ep || !ep.key) return;
        if (ep.key !== hlKey && ep.key.indexOf(keyPrefix) !== 0) return;
        var endPos = null;
        var m = ep.key.match(/:(\d+)-(\d+)$/);
        if (m) {
          endPos = parseInt(m[2], 10);
        } else if (typeof ep.end === 'number') {
          endPos = ep.end;
        }
        if (endPos == null) return;
        var prev = byEndPos[endPos] || { count: 0, anySource: false };
        byEndPos[endPos] = {
          count: prev.count + 1,
          // Once any link marks this position as source, keep it source.
          anySource: prev.anySource || !!isSourceHere
        };
      });
    });
    if (Object.keys(byEndPos).length === 0) {
      // Legacy link (no :start-end suffix) — fall back to one icon at
      // end of block, same as the prior end-of-paragraph behavior.
      // For the legacy path, check if any link is sourced from this container.
      var legacyAnySource = links.some(function(l) {
        return l.source && (l.source.key === hlKey || l.source.key.indexOf(keyPrefix) === 0);
      });
      container.appendChild(_buildLinkIcon(hlKey, links.length, legacyAnySource));
      return;
    }

    // Process highest position first so each insertion doesn't shift the
    // character offsets of earlier (lower-offset) insertions still pending.
    var positions = Object.keys(byEndPos).map(Number).sort(function(a, b) { return b - a; });
    positions.forEach(function(endPos) {
      _insertLinkIconAt(container, hlKey, endPos, byEndPos[endPos].count, byEndPos[endPos].anySource);
    });
  });
}

/* Build an inline chain icon span.
   isSource=true  -> this container originated the link; render at full gold (--gold).
   isSource=false -> this container is a link destination; render dimmer (--gold-dim).
   The visual distinction lets the user see at a glance "I anchored this" vs
   "something else points here". Both icons are still fully tappable. */
function _buildLinkIcon(hlKey, count, isSource) {
  var icon = document.createElement('span');
  // Apply source/target distinction via CSS class; default is dim (target role).
  icon.className = 'inline-link-icon' + (isSource ? ' inline-link-icon-source' : '');
  icon.title = count + ' link' + (count > 1 ? 's' : '');
  icon.innerHTML = '<svg viewBox="0 0 24 24"><path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71"/><path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71"/></svg>';
  var openSidebar = function(e) {
    e.preventDefault(); e.stopPropagation();
    if (window.__openLinkSidebar) window.__openLinkSidebar(hlKey);
  };
  icon.addEventListener('click', openSidebar);
  icon.addEventListener('touchend', openSidebar);
  return icon;
}

function _insertLinkIconAt(container, hlKey, endPos, count, isSource) {
  var WORD = /[\w''\-]/;
  var CLOSE_PUNCT = /[.,;:!?)\]}"'…—]/;
  // Inline elements the icon must NOT land directly before — sliding
  // past keeps their tap targets clear and matches user intent
  // (icons should bracket the linked phrase, not interrupt
  // reference / footnote markers).
  var SKIP_RX = /\b(fn-ref|tap-ref|letter-link-ref|verse-link-icon|hl-note-icon)\b/;

  function isSkip(el) {
    return el && el.nodeType === 1 && el.className && SKIP_RX.test(el.className);
  }
  function isPhraseChar(c) { return !!c && (WORD.test(c) || CLOSE_PUNCT.test(c)); }

  /* Starting from `node`, walk forward through the DOM looking for the
     first "insertable" position that isn't directly before a skip element.
     A skip element is jumped over as a unit. When the current node has no
     nextSibling, walk UP to the parent and try again — this handles cases
     like `<span>...written.</span><span class="fn-ref">1</span>` where the
     fn-ref is a sibling of the text's wrapper, not of the text itself.
     Returns the DOM node to insert before, or null to append to container. */
  function nextInsertionPoint(node) {
    var cur = node;
    while (cur && cur !== container) {
      var sib = cur.nextSibling;
      if (sib === null) {
        cur = cur.parentElement;
        continue;
      }
      if (isSkip(sib)) {
        cur = sib;
        continue;
      }
      return sib;
    }
    return null;
  }

  // Collect all text nodes in document order. We slide across text-node
  // boundaries (through inline emphasis wrappers like <em>/<strong>/<i>)
  // when there's no visible whitespace between them — Android selection
  // handles often snap to text-node boundaries, so a user dragging into
  // an italicised phrase like "...become the <em>same?</em>..." can land
  // the selection END at the boundary BEFORE the <em>. Without the cross-
  // node slide the icon ends up at "...become the [icon]same?" — exactly
  // the bug the user reported. With the slide we follow the phrase into
  // the next text node until reaching real whitespace.
  var textNodes = [];
  var w = document.createTreeWalker(container, NodeFilter.SHOW_TEXT, null, false);
  while (w.nextNode()) textNodes.push(w.currentNode);

  // Find the text node + local offset for endPos.
  var charPos = 0, nodeIdx = -1, localOffset = 0;
  for (var i = 0; i < textNodes.length; i++) {
    var nodeEnd = charPos + textNodes[i].length;
    if (endPos > charPos && endPos <= nodeEnd) {
      nodeIdx = i;
      localOffset = endPos - charPos;
      break;
    }
    charPos = nodeEnd;
  }
  if (nodeIdx < 0) {
    container.appendChild(_buildLinkIcon(hlKey, count, isSource));
    return;
  }

  // If endPos landed INSIDE a skip element (fn-ref bubble's "1" text node,
  // a letter-link's label text, etc.), slide past the whole skip element
  // instead of placing the icon inside it.
  var ancestor = textNodes[nodeIdx].parentElement;
  var skipAncestor = null;
  while (ancestor && ancestor !== container) {
    if (isSkip(ancestor)) skipAncestor = ancestor;
    ancestor = ancestor.parentElement;
  }
  if (skipAncestor) {
    var ref = nextInsertionPoint(skipAncestor);
    var icon = _buildLinkIcon(hlKey, count, isSource);
    if (ref) ref.parentNode.insertBefore(icon, ref);
    else container.appendChild(icon);
    return;
  }

  // Block-level tags that visually break the reading flow. When sliding
  // across text-node boundaries, we STOP if the path between two adjacent
  // text nodes contains any of these — but we KEEP going through inline
  // emphasis wrappers (em/strong/i/b/span/etc.) so a phrase like
  // "...the <em>same?</em> Therefore..." reads as one continuous unit
  // for icon-placement purposes.
  var BLOCK_TAGS = /^(BR|P|DIV|H[1-6]|LI|BLOCKQUOTE|HR|UL|OL|TR|TD|TH|TABLE|SECTION|ARTICLE|HEADER|FOOTER|NAV|MAIN|FIGURE|FIGCAPTION|PRE|ADDRESS)$/;
  function hasBlockBetween(prevTextNode, nextTextNode) {
    var bw = document.createTreeWalker(container, NodeFilter.SHOW_ALL, null, false);
    bw.currentNode = prevTextNode;
    var n;
    while ((n = bw.nextNode())) {
      if (n === nextTextNode) return false;
      if (n.nodeType === 1 && BLOCK_TAGS.test(n.tagName)) return true;
    }
    return true;
  }

  // Slide forward through phrase characters (word chars + closing
  // punctuation), crossing text-node boundaries whenever the next text
  // node is in the SAME inline context — i.e., no block element on the
  // DOM path between them. This is what makes the icon flow through an
  // <em>-wrapped phrase even when Android's selection handle dropped at
  // the text-node boundary BEFORE the <em>.
  // Skip elements (fn-ref, etc.) are jumped over by advancing the
  // node index past any of their child text nodes — they're part of
  // the visible reading flow but the icon shouldn't land inside them.
  while (true) {
    var text = textNodes[nodeIdx].nodeValue;
    while (localOffset < text.length && isPhraseChar(text[localOffset])) {
      localOffset++;
    }
    if (localOffset < text.length) break;          // stopped at whitespace mid-node
    var nextNodeIdx = nodeIdx + 1;
    while (nextNodeIdx < textNodes.length) {
      var na = textNodes[nextNodeIdx].parentElement;
      var inSkip = false;
      while (na && na !== container) {
        if (isSkip(na)) { inSkip = true; break; }
        na = na.parentElement;
      }
      if (!inSkip) break;
      nextNodeIdx++;
    }
    if (nextNodeIdx >= textNodes.length) break;     // no more nodes
    if (hasBlockBetween(textNodes[nodeIdx], textNodes[nextNodeIdx])) break;
    nodeIdx = nextNodeIdx;
    localOffset = 0;
  }

  // Final placement.
  var finalNode = textNodes[nodeIdx];
  var finalText = finalNode.nodeValue;
  var insertBeforeNode = null;
  if (localOffset >= finalText.length) {
    insertBeforeNode = nextInsertionPoint(finalNode);
  } else if (localOffset === 0) {
    insertBeforeNode = finalNode;
  } else {
    insertBeforeNode = finalNode.splitText(localOffset);
  }
  var iconEl = _buildLinkIcon(hlKey, count, isSource);
  if (insertBeforeNode) {
    insertBeforeNode.parentNode.insertBefore(iconEl, insertBeforeNode);
  } else {
    container.appendChild(iconEl);
  }
}

/* ══════════════════════════════════════════════════════════════════════
   CachedStore — shared localStorage cache factory
   ══════════════════════════════════════════════════════════════════════
   Global-scope module. Concatenates with index.html via <script src>.
   No dependencies. Loaded FIRST (every other store uses this at
   load time via `Object.assign(CachedStore(...), {...})`).
   ═══════════════════════════════════════════════════════════════════════ */

/* ── CachedStore factory — shared localStorage cache/load/save ── */
export function CachedStore(storageKey, defaultVal) {
  return {
    _cache: null,
    _load() {
      if (this._cache) return this._cache;
      try { this._cache = JSON.parse(localStorage.getItem(storageKey) || JSON.stringify(defaultVal)); }
      catch (e) { this._cache = typeof defaultVal === 'object' ? (Array.isArray(defaultVal) ? [] : {}) : defaultVal; }
      return this._cache;
    },
    _save() {
      try { localStorage.setItem(storageKey, JSON.stringify(this._cache)); } catch (e) { console.warn('localStorage write failed for', storageKey, e); }
    },
    raw() { return this._load(); }
  };
}

/* ═══════════════════════════════════════════════════════════════
   JOURNAL MEDIA STORE — IndexedDB wrapper for images + audio blobs
   ═══════════════════════════════════════════════════════════════
   Global-scope module. Concatenates with index.html via <script src>.
   No dependencies — uses only browser IndexedDB.

   Why IndexedDB: a single audio recording is ~200-400 KB and an image
   ~150 KB after compression. localStorage caps at ~5 MB across the
   ENTIRE app. Even modest journal use would exhaust that quota fast.
   IndexedDB on Android WebView has effectively unlimited quota.

   Public API (all methods return Promises):
     JournalMediaStore.put(record)    → Promise<id>
     JournalMediaStore.get(id)        → Promise<record | null>
     JournalMediaStore.delete(id)     → Promise<void>
     JournalMediaStore.list()         → Promise<Array<record-without-blob>>
     JournalMediaStore.allIds()       → Promise<Array<id>>
     JournalMediaStore.objectUrl(id)  → Promise<string | null>   (cached Blob URLs)

   Record shape:
     { id, type:'image'|'audio', blob:Blob, mime, size,
       width?, height?, duration?, created }

   Object-URL cache: created Blob URLs are cached per-id so repeated
   reads inside the same session don't create duplicate URLs. Caller
   should NOT revokeObjectURL on these — the cache handles cleanup
   on store delete.
═══════════════════════════════════════════════════════════════ */

export var JournalMediaStore = (function() {
  var DB_NAME = 'vot-journal-media';
  var DB_VERSION = 1;
  var STORE = 'media';
  var _dbPromise = null;
