/* ═══════════════════════════════════════════════════════════════
   LINK STORE — bidirectional link persistence
   ═══════════════════════════════════════════════════════════════
   Global-scope module. Concatenates with index.html; no import/export.
   Depends on: CachedStore (defined earlier in the main script block).

   Data model:
     vot-links: Array<{
       id:      string,
       source:  LinkEndpoint,   // passage where the user originated the link
       target:  LinkEndpoint,   // destination the user picked
       created: number          // Date.now()
     }>

     LinkEndpoint: {
       type:    'bible' | 'study' | 'letter' | 'wtlb' | 'blessed' | 'holy-days',
       key:     string,   // e.g. "bible:genesis:1:3-7" or "letter:the-wide-path:2:10-40"
       label:   string,
       // Optional:
       bookId?, chapter?, verse?, verseEnd?, collection?, letterId?, entryId?,
       start?,  end?,   // char offsets within the container (source endpoints)
       text?,           // captured text of the linked range
       preview?         // resolved verse / excerpt text for LinkCard display
     }

   Migration: legacy {a, b} records are automatically rewritten to
   {source, target} on first load (one-time per user).
═══════════════════════════════════════════════════════════════ */

import { CachedStore } from './cached-store.js';

/* ID generators — also used by AnnotationStore (hlId) */
export function hlId() { return 'hl_' + Date.now() + '_' + Math.random().toString(36).slice(2,6); }
export function lnkId() { return 'lnk_' + Date.now() + '_' + Math.random().toString(36).slice(2,6); }

export const LinkStore = Object.assign(CachedStore('vot-links', []), {
  /* Override _load to migrate legacy {a,b} records to {source,target} on
     first access. Migration is one-time per user: after it runs the
     persisted data is already in the new shape, so subsequent loads are
     no-ops in the migration branch. */
  _load() {
    if (this._cache) return this._cache;
    try { this._cache = JSON.parse(localStorage.getItem('vot-links') || '[]'); }
    catch (e) { this._cache = []; }

    // Migrate legacy {a, b} records → {source, target}. Coalesce FIRST so a
    // half-migrated record (source set but a still present, or vice-versa —
    // e.g. an interrupted prior migration or a hand-edited export) is
    // healed instead of silently dropped (was real data-loss).
    let migrated = false;
    this._cache = this._cache.filter(function(lnk) {
      if (!lnk || typeof lnk !== 'object') return false;
      if (!lnk.source && lnk.a) { lnk.source = lnk.a; migrated = true; }
      if (!lnk.target && lnk.b) { lnk.target = lnk.b; migrated = true; }
      if (lnk.a) { delete lnk.a; migrated = true; }
      if (lnk.b) { delete lnk.b; migrated = true; }
      // A record is only unusable if BOTH endpoints (with .key) are missing.
      if (!lnk.source || !lnk.source.key || !lnk.target || !lnk.target.key) {
        console.warn('[LinkStore] dropping malformed record (incomplete endpoints):', lnk.id);
        return false;
      }
      return true;
    });
    if (migrated) this._save();
    return this._cache;
  },
  getForKey(key) {
    return this._load().filter(lnk =>
      (lnk.source && lnk.source.key === key) || (lnk.target && lnk.target.key === key));
  },
  getForKeyPrefix(prefix) {
    return this._load().filter(lnk => {
      if (!lnk.source || !lnk.source.key || !lnk.target || !lnk.target.key) return false;
      const srcMatch = lnk.source.key === prefix || lnk.source.key.startsWith(prefix + ':') || prefix.startsWith(lnk.source.key + ':');
      const tgtMatch = lnk.target.key === prefix || lnk.target.key.startsWith(prefix + ':') || prefix.startsWith(lnk.target.key + ':');
      return srcMatch || tgtMatch;
    });
  },
  all() { return this._load(); },
  add(link) {
    this._load().push(link);
    this._save();
  },
  remove(linkId) {
    this._cache = this._load().filter(l => l.id !== linkId);
    this._save();
  }
});

/* Persist a link, dedup'ing if the exact pair already exists.
   Returns the link object on success OR when the link already exists
   (so callers can show the green ✓ either way). Returns null only when
   sourceEndpoint.key is missing. */
export function persistLink(sourceEndpoint, targetEndpoint) {
  if (!sourceEndpoint || !sourceEndpoint.key) return null;
  const existing = LinkStore.getForKey(sourceEndpoint.key);
  // Dedup: a link exists if either endpoint on any existing record touches
  // the desired target key (so we don't create duplicate pairs regardless
  // of which side was "source" when the prior link was made).
  const dup = existing.find(l => l.source.key === targetEndpoint.key || l.target.key === targetEndpoint.key);
  if (dup) return dup; // already exists — return it so the green ✓ still shows
  const link = { id: lnkId(), source: sourceEndpoint, target: targetEndpoint, created: Date.now() };
  LinkStore.add(link);
  return link;
}

/* ===================================================================
   Tab thumbnail store — IndexedDB-backed dataURL cache
   ===================================================================
   ES module (G.2.3). Module-private state — moved out of index.html as
   part of the strict-mode conversion (esbuild ES modules are strict, so
   the in-function `_thumbDbPromise = ...` assignment would throw if the
   binding wasn't declared at module scope).
   Bundled helpers (P5e):
   - openThumbDB
   - idbPut
   - idbDelete
   - idbReadAll
   =================================================================== */

export const THUMB_DB = 'vot-thumbs';
export const THUMB_STORE = 'thumbs';
export let _thumbDbPromise = null;

export function openThumbDB() {
  if (_thumbDbPromise) return _thumbDbPromise;
  _thumbDbPromise = new Promise((resolve) => {
    try {
      const req = indexedDB.open(THUMB_DB, 1);
      req.onupgradeneeded = (e) => {
        const db = e.target.result;
        if (!db.objectStoreNames.contains(THUMB_STORE)) db.createObjectStore(THUMB_STORE);
      };
      req.onsuccess = (e) => resolve(e.target.result);
      req.onerror = () => resolve(null);
    } catch (e) {resolve(null);}
  });
  return _thumbDbPromise;
}

export function idbPut(key, value) {
  return openThumbDB().then((db) => {
    if (!db) return;
    return new Promise((resolve) => {
      try {
        const tx = db.transaction(THUMB_STORE, 'readwrite');
        tx.objectStore(THUMB_STORE).put(value, key);
        tx.oncomplete = () => resolve();
        tx.onerror = () => resolve();
        tx.onabort = () => resolve();
      } catch (e) {resolve();}
    });
  });
}

export function idbDelete(key) {
  return openThumbDB().then((db) => {
    if (!db) return;
    return new Promise((resolve) => {
      try {
        const tx = db.transaction(THUMB_STORE, 'readwrite');
        tx.objectStore(THUMB_STORE).delete(key);
        tx.oncomplete = () => resolve();
        tx.onerror = () => resolve();
      } catch (e) {resolve();}
    });
  });
}

export function idbReadAll() {
  return openThumbDB().then((db) => {
    if (!db) return {};
    return new Promise((resolve) => {
      try {
        const tx = db.transaction(THUMB_STORE, 'readonly');
        const store = tx.objectStore(THUMB_STORE);
        const out = {};
        const req = store.openCursor();
        req.onsuccess = (e) => {
          const c = e.target.result;
          if (c) {out[c.key] = c.value;c.continue();} else
          resolve(out);
        };
        req.onerror = () => resolve(out);
      } catch (e) {resolve({});}
    });
  });
}

/* ═══════════════════════════════════════════════════════════════════════
   BookmarkIcon — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function BookmarkIcon({ hlKey, hlTick }) {
  const bookmarks = React.useMemo(
    () => BookmarkStore.getForKeyPrefix(hlKey),
    [hlKey, hlTick]
  );
  if (!bookmarks || bookmarks.length === 0) return null;

  const ids = bookmarks.map((b) => b.id);
  const open = (e) => {
    e.stopPropagation();
    e.preventDefault();
    // Single bookmark — open the create/edit sheet directly. atSource:true
    // suppresses the sheet's "Open Source" button (the user is already on
    // the bookmarked passage). Mirrors _buildBookmarkIcon's tap handler.
    if (ids.length === 1 && window.__bookmarkEdit) {
      window.__bookmarkEdit(ids[0], { atSource: true });
      return;
    }
    // Multiple bookmarks — the popover disambiguates.
    const rect = e.currentTarget.getBoundingClientRect();
    if (window.__openBookmarkPopover) {
      window.__openBookmarkPopover(ids, rect.left + rect.width / 2, rect.bottom + 4, hlKey);
    }
  };

  return (
    <span
      className={"inline-bookmark-icon" + (ids.length > 1 ? " inline-bookmark-icon-multi" : "")}
      onClick={open}
      title={ids.length === 1 ? "Bookmark" : ids.length + " bookmarks"}
    >
      <svg viewBox="0 0 24 24" fill="currentColor" stroke="currentColor">
        <path
          fill="currentColor"
          stroke="currentColor"
          strokeWidth="1.5"
          strokeLinejoin="round"
          d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z"
        />
      </svg>
    </span>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   ChapterBookmarkBtn — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function ChapterBookmarkBtn({ chapterBookmark, hlTick }) {
  // Hook must run on every render (rules-of-hooks) — guard moved INSIDE the
  // memo so we always call useMemo regardless of whether we'll render anything.
  const hlKey = chapterBookmark && chapterBookmark.hlKey;
  const existing = React.useMemo(
    () => (hlKey && typeof BookmarkStore !== 'undefined')
      ? BookmarkStore.getForKey(hlKey)
      : [],
    [hlKey, hlTick]
  );
  if (!hlKey || typeof BookmarkStore === 'undefined') return null;
  const isBookmarked = existing.length > 0;

  const onClick = (e) => {
    e.stopPropagation();
    if (isBookmarked) {
      // Open the popover near the button so the user can edit thought / delete.
      const rect = e.currentTarget.getBoundingClientRect();
      const ids = existing.map(b => b.id);
      if (window.__openBookmarkPopover) {
        window.__openBookmarkPopover(ids, rect.left + rect.width / 2, rect.bottom + 4, chapterBookmark.hlKey);
      }
      return;
    }
    // Open the pre-commit create sheet so the user can refine label +
    // attach a thought before persisting. Same flow as the
    // SelectionToolbar bookmark action — consistent experience whether
    // the user bookmarks a phrase or a whole chapter.
    if (window.__bookmarkCreate) {
      window.__bookmarkCreate({
        hlKey: chapterBookmark.hlKey,
        sourceLabel: chapterBookmark.label || '',
        excerpt: '',
        defaultLabel: chapterBookmark.label || 'Chapter bookmark'
      });
    } else {
      // Fallback (bridge missing): silent-add so the action is never lost.
      BookmarkStore.add({
        id: (typeof bkmId === 'function') ? bkmId() : ('bkm_' + Date.now()),
        hlKey: chapterBookmark.hlKey,
        label: chapterBookmark.label || 'Chapter bookmark',
        thought: '',
        created: Date.now(),
        updated: Date.now()
      });
      if (window.__bumpHlTick) window.__bumpHlTick();
    }
  };

  return (
    <button
      className={"nav-bookmark-btn" + (isBookmarked ? " nav-bookmark-btn-active" : "")}
      onClick={onClick}
      title={isBookmarked ? "Open bookmark options" : "Bookmark this chapter"}
      aria-label={isBookmarked ? "Open bookmark options" : "Bookmark this chapter"}
    >
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
        <path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z" fill={isBookmarked ? "currentColor" : "none"} />
      </svg>
    </button>
  );
}

