/* ═══════════════════════════════════════════════════════════════════════
   ProphecyCard — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function ProphecyCard({ type, tag, label, blocks, fnProps, stateKey, statesRef, onSaveStates, expandSignal }) {
  // Read initial state from persistent ref, default to expanded (true)
  const stored = statesRef && statesRef.current[stateKey];
  const [expanded, setExpandedRaw] = React.useState(stored !== undefined ? stored : true);
  // setExpanded must handle BOTH a raw boolean value AND an updater function
  // like real React setState — the toggle path at the header uses
  // `setExpanded((e) => !e)`, which would otherwise store the function itself
  // into statesRef and JSON.stringify it to `{}` → empty saved blob → all
  // cards reset to expanded on next reload. Resolve the updater first, then
  // persist the resolved boolean.
  const setExpanded = (val) => {
    setExpandedRaw((prev) => {
      const next = typeof val === 'function' ? val(prev) : val;
      if (statesRef) { statesRef.current[stateKey] = next; onSaveStates && onSaveStates(); }
      return next;
    });
  };
  // React to external expand/collapse all signal
  React.useEffect(() => {
    if (expandSignal !== undefined && expandSignal !== null && expandSignal !== 0) {
      const newVal = expandSignal > 0;
      setExpandedRaw(newVal);
      if (statesRef) statesRef.current[stateKey] = newVal;
    }
  }, [expandSignal]);
  const cls = `prophecy-card pc-${type}`;
  const cardFnProps = fnProps;
  return (
    <div className={cls}>
      <div className="prophecy-card-header" onClick={() => setExpanded(e => !e)}>
        <span className="prophecy-card-tag">{tag}</span>
        <span className={`prophecy-card-chevron${expanded ? "" : " collapsed"}`}>{"▼"}</span>
      </div>
      <div className={`prophecy-card-body${expanded ? "" : " collapsed"}`}>
        {label && <div className="prophecy-card-sublabel">{label}</div>}
        {blocks.map((block, bi) => {
          if (block.type === "para") return (
            <p key={bi} className="letter-para">
              <Segments {..._extends({ segments: block.segments }, cardFnProps)} />
            </p>
          );

          if (block.type === "poetry") return (
            <div key={bi} className="letter-poetry">
              {block.lines.map((line, li) => (
                <div key={li} className="poetry-line">
                  <Segments {..._extends({ segments: line }, fnProps)} />
                </div>
              ))}
            </div>
          );

          if (block.type === "heading") return (
            <h2 key={bi} className={`study-heading study-heading-l${block.level || 3}`}>{block.text}</h2>
          );

          return null;
        })}
      </div>
    </div>
  );

}

/* ═══════════════════════════════════════════════════════════════════════
   ScreenLayout — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function ScreenLayout({ navChildren, children, showProgress, hideTabsBtn }) {
  const ref = React.useCallback((el) => {__scrollEl = el;}, []);

  React.useEffect(() => {
    if (!showProgress) return;
    const onScroll = () => {
      if (!__scrollEl) return;
      const { scrollTop, scrollHeight, clientHeight } = __scrollEl;
      const sentinel = __scrollEl.querySelector('.reading-end');
      let max;
      if (sentinel) {
        const containerTop = __scrollEl.getBoundingClientRect().top;
        const sentinelTop = sentinel.getBoundingClientRect().top;
        const sentinelOffset = sentinelTop - containerTop + scrollTop;
        max = Math.max(sentinelOffset - clientHeight, 1);
      } else {
        max = Math.max(scrollHeight - clientHeight, 1);
      }
      const pct = Math.min(scrollTop / max, 1);
      if (pct >= 0.9 && window.__onReadingComplete) window.__onReadingComplete();
    };
    let el = null;
    const attach = () => {
      if (__scrollEl !== el) {
        if (el) el.removeEventListener("scroll", onScroll);
        el = __scrollEl;
        if (el) el.addEventListener("scroll", onScroll, { passive: true });
      }
    };
    attach();
    const poll = setInterval(attach, 300);
    return () => {
      clearInterval(poll);
      if (el) el.removeEventListener("scroll", onScroll);
    };
  }, [showProgress]);

  return (
    <div className="screen-layout">
      <nav className="top-nav">
        {navChildren}
        {hideTabsBtn ? null : <TabsNavBtn />}
      </nav>
      <div className="screen-scroll" ref={ref}>
        {children}
      </div>
    </div>
  );
}

/* ════════════════════════════════════════════════════════════════════════
   Segments — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function Segments({ segments, activeFn, onFnClick, onScripClick, onLetterClick, onInAppLink, studyMode, footnotes, highlightText }) {
  return segments.map((seg, i) => {
    if (seg.t === "fn") {
      // Always render as a gold circled number (Volumes style). Studies
      // and Volumes now use the exact same footnote affordance: tap the
      // number → FootnoteSheet shows scripture text / in-app link /
      // external URL depending on the footnote type.
      return (
        <span
          key={i}
          className={`fn-ref${activeFn === seg.v ? " active" : ""}`}
          data-fn-num={seg.v}
          onClick={() => onFnClick(seg.v)}
          title={`Footnote ${seg.v}`}
        >{seg.v}</span>
      );
    }
    if (seg.t === "letter-link") {
      // Two tap-through mechanisms:
      //   (a) seg.link { collection, letterTitle } — cross-volume via
      //       openInAppLetter, with back-stack routing + back-hint pill.
      //   (b) seg.letterId + seg.screen — legacy matthew.js path.
      if (seg.link && onInAppLink) {
        return (
          <span key={i} className="letter-link-ref" onClick={() => onInAppLink(seg.link)}>{seg.label}</span>
        );
      }
      return (
        <span key={i} className="letter-link-ref" onClick={() => onLetterClick && onLetterClick(seg.letterId, seg.screen)}>{seg.label}</span>
      );
    }
    if (seg.t === "stanza-break") return <div key={i} className="stanza-break" />;
    // Collision guard: inject a leading space when the previous segment ended with
    // a non-whitespace character and this segment starts with a word char, opening
    // paren/bracket, or opening quote. Avoids false positives before trailing
    // punctuation (commas, periods, etc.) that the fetch script split into segments.
    const prevV = i > 0 ? segments[i - 1].v || '' : '';
    const v = seg.v && /^[\w(\[{"\u201c\u2018]/.test(seg.v) && /\S$/.test(prevV) ? ' ' + seg.v : seg.v || '';
    if (seg.t === "bold-italic") return <React.Fragment key={i}>{renderTextWithScripRefs(v, "bold-italic", onScripClick, highlightText)}</React.Fragment>;
    if (seg.t === "italic") return <React.Fragment key={i}>{renderTextWithScripRefs(v, "italic-text", onScripClick, highlightText)}</React.Fragment>;
    if (seg.t === "caps") return <span key={i} style={{ fontWeight: 600, letterSpacing: '0.03em' }}>{v}</span>;
    return <React.Fragment key={i}>{renderTextWithScripRefs(v, null, onScripClick, highlightText)}</React.Fragment>;
  });
}

