          <div className="notes-index-list" style={{ marginTop: '0.75rem' }}>
            {displayBookmarks.map(function(bkm) {
              return (
                <BookmarkRow
                  key={bkm.id}
                  bkm={bkm}
                  onNavigate={navigateToBookmark}
                  onLongPress={function(b) { setActionTarget(b); }}
                  editingId={editingId}
                  onEditStart={function(id) { setEditingId(id); }}
                  onEditSave={onEditSave}
                  onEditCancel={function() { setEditingId(null); }}
                />
              );
            })}
          </div>
        )}

        {actionTarget && (
          <BookmarkRowActionSheet
            bkm={actionTarget}
            onClose={function() { setActionTarget(null); }}
            onNavigate={function(bkm) { navigateToBookmark(bkm); setActionTarget(null); }}
            onEditLabel={function(id) { setEditingId(id); setActionTarget(null); }}
            onEditThought={function() { if (setHlTick) setHlTick(function(t){ return t + 1; }); }}
            onDelete={onDeleteDone}
          />
        )}
      </div>
    </ScreenLayout>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   ChapterIndex — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function ChapterIndex({ book, onSelect, onBack, onSearch, onHistory, onSettings, currentChapter, theme, onThemeChange, isRead, markAsReadEnabled, restoredNames, showChapterTitle }) {
  const currentRef = React.useRef(null);
  React.useEffect(() => {
    if (currentRef.current) {
      setTimeout(() => currentRef.current.scrollIntoView({ behavior: "smooth", block: "center" }), 120);
    }
  }, []);
  // Restored-Name chrome lookup for the chapter cards. When restoredNames
  // is on, show the restored chapter title; otherwise fall back to the
  // standard. If showChapterTitle is off, titles are hidden entirely.
  const getChapterTitle = (ch) => {
    if (showChapterTitle === false) return null;
    if (restoredNames && typeof BOOKS_RESTORED !== "undefined" && BOOKS_RESTORED[book.id]) {
      const r = BOOKS_RESTORED[book.id].chapters.find((c) => c.num === ch.num);
      if (r && r.title) return r.title;
    }
    return ch.title;
  };
  return (
    <ScreenLayout
      navChildren={
        <>
          <button className="nav-home" onClick={onBack}>{"← Books"}</button>
          <HomeBtn />
          <NavButtons onSettings={onSettings} onHistory={onHistory} onSearch={onSearch} theme={theme} onThemeChange={onThemeChange} />
        </>
      }
    >
      <div className="vol-index">
        <div className="vol-index-header">
          <div className="vol-index-eyebrow">Scriptures of Truth</div>
          <h1 className="vol-index-title">{book.title}</h1>
          <div className="vol-index-subtitle">{book.subtitle}</div>
          <div className="vol-index-ornament">
            <div className="vol-index-ornament-line" />
            <div className="vol-index-ornament-diamond" />
            <div className="vol-index-ornament-line r" />
          </div>
        </div>
        <div className="chapter-cards">
          {book.chapters.map((ch, i) => {
            const isCurrent = ch.num === currentChapter;
            return (
              <button
                key={ch.num}
                ref={isCurrent ? currentRef : null}
                className={`chapter-card-btn${isCurrent ? " is-current" : ""}`}
                onClick={() => onSelect(ch.num)}
              >
                <span className="chapter-card-num">{ch.num}</span>
                <div className="chapter-card-divider" />
                <div className="chapter-card-info">
                  {(() => {
                    const t = getChapterTitle(ch);
                    return t
                      ? <div className="chapter-card-title">{t}</div>
                      : <div className="chapter-card-title untitled">Chapter {ch.num}</div>;
                  })()}
                </div>
                {markAsReadEnabled && isRead(ch.num) && <span className="read-check">✓</span>}
              </button>
            );
          })}
        </div>
      </div>
    </ScreenLayout>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   GardenView — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export const GARDEN_PRELOAD_AHEAD = 5;
export const GARDEN_CRAWL_DELAY = 500; // ms between background crawl downloads

export function GardenView({ page, onPageChange, onBack, theme, onThemeChange, tier }) {
  const [loading, setLoading] = React.useState(false);
  const [error, setError] = React.useState(false);
  const [jumpMode, setJumpMode] = React.useState(false);
  const [jumpInput, setJumpInput] = React.useState("");
  const jumpRef = React.useRef(null);
  const crawlRef = React.useRef(null);
  const pageRef = React.useRef(page);
  pageRef.current = page;

  // Enter immersive mode on mount, exit on unmount
  React.useEffect(() => {
    if (window.AndroidBridge?.setImmersiveMode) window.AndroidBridge.setImmersiveMode(true);
    return () => {if (window.AndroidBridge?.setImmersiveMode) window.AndroidBridge.setImmersiveMode(false);};
  }, []);

  // Reset error + native zoom on page change or tier change.
  React.useEffect(() => {
    setError(false);
    setLoading(!gardenIsCached(page, tier));
    if (window.AndroidBridge?.resetZoom) window.AndroidBridge.resetZoom();
  }, [page, tier]);

  // Priority preload: current page + 5 ahead (immediate, no throttle)
  React.useEffect(() => {
    gardenPreload(page, tier);
    for (let i = page + 1; i <= Math.min(page + GARDEN_PRELOAD_AHEAD, GARDEN_TOTAL); i++) {
      gardenPreload(i, tier);
    }
  }, [page, tier]);

  // Background sequential crawl: fills in all pages from 1 forward, throttled.
  // Restarts when tier changes (because all existing cached pages are for a
  // different tier now).
  React.useEffect(() => {
    let cancelled = false;
    let crawlPage = 1;

    const crawlNext = () => {
      if (cancelled) return;
      // Skip already-cached pages (for the CURRENT tier)
      while (crawlPage <= GARDEN_TOTAL && gardenImageCache[gardenCacheKey(crawlPage, tier)]) crawlPage++;
      if (crawlPage > GARDEN_TOTAL) return;

      const cur = pageRef.current;
      if (crawlPage >= cur && crawlPage <= cur + GARDEN_PRELOAD_AHEAD) {
        crawlPage++;
      }

      if (crawlPage <= GARDEN_TOTAL && !gardenImageCache[gardenCacheKey(crawlPage, tier)]) {
        gardenPreload(crawlPage, tier);
        crawlPage++;
      }

      crawlRef.current = setTimeout(crawlNext, GARDEN_CRAWL_DELAY);
    };

    crawlRef.current = setTimeout(crawlNext, 1500);

    return () => {
      cancelled = true;
      if (crawlRef.current) clearTimeout(crawlRef.current);
    };
  }, [tier]);

  // Focus jump input when it opens
  React.useEffect(() => {
    if (jumpMode && jumpRef.current) jumpRef.current.focus();
  }, [jumpMode]);

  const goNext = () => {if (page < GARDEN_TOTAL) onPageChange(page + 1);};
  const goPrev = () => {if (page > 1) onPageChange(page - 1);};

  const handleJump = () => {
    const n = parseInt(jumpInput, 10);
    if (n >= 1 && n <= GARDEN_TOTAL) onPageChange(n);
    setJumpMode(false);
    setJumpInput("");
  };

  // Enable native Android zoom while Garden is open
  React.useEffect(() => {
    if (window.AndroidBridge?.setZoomEnabled) window.AndroidBridge.setZoomEnabled(true);
    return () => {if (window.AndroidBridge?.setZoomEnabled) window.AndroidBridge.setZoomEnabled(false);};
  }, []);

  return (
    <div className="garden-fullscreen">
      <div className="garden-top-bar">
        <button className="garden-back-btn" onClick={onBack}>
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <polyline points="15 18 9 12 15 6" />
          </svg>
        </button>
        {jumpMode ? (
          <form className="garden-jump-form" onSubmit={(e) => {e.preventDefault();handleJump();}}>
            <input
              ref={jumpRef}
              type="number"
              min="1"
              max={GARDEN_TOTAL}
              className="garden-jump-input"
              value={jumpInput}
              onChange={(e) => setJumpInput(e.target.value)}
              onBlur={() => {setJumpMode(false);setJumpInput("");}}
              placeholder={`1–${GARDEN_TOTAL}`}
            />
            <span className="garden-jump-hint">/ {GARDEN_TOTAL}</span>
          </form>
        ) : (
          <button className="garden-page-counter" onClick={() => setJumpMode(true)}>
            {page} / {GARDEN_TOTAL}
          </button>
        )}
      </div>

      <div className="garden-image-area">
        {loading && (
          <div className="garden-loading">
            <div style={{ color: "rgba(255,255,255,0.6)", fontSize: "0.9rem" }}>
              {error ? "Failed to load — check your connection" : `Loading page ${page}...`}
            </div>
          </div>
        )}
        <img
          key={`${tier}-${page}`}
          src={gardenUrl(page, tier)}
          alt={`Garden page ${page}`}
          className="garden-page-img"
          style={{ opacity: loading ? 0 : 1, transition: "opacity 0.3s" }}
          onLoad={() => setLoading(false)}
          onError={() => {setLoading(true);setError(true);}}
        />
      </div>

      <div className="garden-bottom-bar">
        <button className="garden-arrow-btn" onClick={goPrev} disabled={page <= 1}>
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <polyline points="15 18 9 12 15 6" />
          </svg>
        </button>
        <button className="garden-arrow-btn" onClick={goNext} disabled={page >= GARDEN_TOTAL}>
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <polyline points="9 6 15 12 9 18" />
          </svg>
        </button>
      </div>
    </div>
  );
}

