/* ── LinksScreen ─────────────────────────────────────────────────── */
export function LinksScreen(props) {
  var onBack = props.onBack;
  var onHome = props.onHome;
  var onNavigateToSource = props.onNavigateToSource;
  var onNavigateToTarget = props.onNavigateToTarget;
  var hlTick = props.hlTick;
  var setHlTick = props.setHlTick;
  var theme = props.theme;
  var onThemeChange = props.onThemeChange;
  var onSearch = props.onSearch;
  var onHistory = props.onHistory;
  var historyEnabled = props.historyEnabled;

  var useState = React.useState;
  var useMemo = React.useMemo;

  var _sq = useState('');
  var searchQuery = _sq[0];
  var setSearchQuery = _sq[1];

  var _ss = useState('recent');
  var sortMode = _ss[0];
  var setSortMode = _ss[1];

  var _sm = useState(false);
  var showSortMenu = _sm[0];
  var setShowSortMenu = _sm[1];

  var _as = useState(null);
  var actionTarget = _as[0];
  var setActionTarget = _as[1];

  var allLinks = useMemo(function() {
    return LinkStore.all();
  }, [hlTick]);

  var displayLinks = useMemo(function() {
    var q = searchQuery.trim().toLowerCase();
    var filtered = q
      ? allLinks.filter(function(lnk) {
          return _epSearchText(lnk.source).includes(q) || _epSearchText(lnk.target).includes(q);
        })
      : allLinks.slice();

    filtered.sort(function(a, b) {
      if (sortMode === 'oldest') return (a.created || 0) - (b.created || 0);
      if (sortMode === 'source-az') {
        var la = (a.source && a.source.label) ? a.source.label.toLowerCase() : '';
        var lb = (b.source && b.source.label) ? b.source.label.toLowerCase() : '';
        return la < lb ? -1 : la > lb ? 1 : 0;
      }
      if (sortMode === 'target-az') {
        var ta = (a.target && a.target.label) ? a.target.label.toLowerCase() : '';
        var tb = (b.target && b.target.label) ? b.target.label.toLowerCase() : '';
        return ta < tb ? -1 : ta > tb ? 1 : 0;
      }
      return (b.created || 0) - (a.created || 0);
    });
    return filtered;
  }, [allLinks, searchQuery, sortMode]);

  var brokenLinks = useMemo(function() {
    return allLinks.filter(function(lnk) {
      return !_endpointResolves(lnk.source) || !_endpointResolves(lnk.target);
    });
  }, [allLinks]);

  var sortLabels = { recent: 'Recent', oldest: 'Oldest', 'source-az': 'Source A–Z', 'target-az': 'Target A–Z' };

  var navigateToEndpoint = function(endpoint, label) {
    if (!endpoint) return;
    if (typeof onNavigateToSource === 'function') {
      onNavigateToSource(endpoint, { sourceLetterTitle: label || 'My Links' });
    }
  };

  var onNavigateSource = function(lnk) {
    navigateToEndpoint(lnk.source, 'My Links');
  };

  var onNavigateTarget = function(lnk) {
    if (!lnk.target) return;
    if (typeof onNavigateToTarget === 'function') {
      onNavigateToTarget(lnk.target, { sourceLetterTitle: 'My Links' });
    } else {
      navigateToEndpoint(lnk.target, 'My Links');
    }
  };

  var onDeleteFromSheet = function() {
    if (typeof setHlTick === 'function') setHlTick(function(t) { return t + 1; });
  };

  // Standard app-wide Library nav (back + Home left, icon cluster right).
  var navChildren = LibraryNav({
    onBack: onBack, onSearch: onSearch, onHistory: onHistory,
    onSettings: props.onSettings,
    theme: theme, onThemeChange: onThemeChange
  });

  return (
    <ScreenLayout navChildren={navChildren}>
      <div className="links-screen">
        {/* Header */}
        <div className="notes-index-header">
          <h1 className="notes-index-title">My Links</h1>
          <span className="notes-index-count">
            {allLinks.length}
            {allLinks.length === 1 ? ' link' : ' links'}
          </span>
        </div>

        {/* Search */}
        <input
          className="notes-index-search"
          type="search"
          placeholder="Search links…"
          value={searchQuery}
          onChange={function(e) { setSearchQuery(e.target.value); }}
        />

        {/* Controls row: single sort TOGGLE */}
        <div className="notes-index-controls" style={{ marginTop: '0.7rem' }}>
          <button
            className="notes-index-sort-btn"
            style={{ marginLeft: 'auto' }}
            onClick={function() { setSortMode(function(m) { return m === 'oldest' ? 'recent' : 'oldest'; }); }}
            title="Toggle sort order"
          >
            {sortMode === 'oldest' ? 'Sort: Oldest ↑' : 'Sort: Newest ↓'}
          </button>
        </div>

        {/* Broken links callout */}
        {brokenLinks.length > 0 && !searchQuery && (
          <div className="links-broken-callout">
            <span className="links-broken-icon">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
                <path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71" />
                <path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71" />
                <line x1="2" y1="2" x2="22" y2="22" />
              </svg>
            </span>
            <span className="links-broken-text">
              {brokenLinks.length}
              {brokenLinks.length === 1
                ? ' link points to content that can no longer be found (the source or target was deleted).'
                : ' links point to content that can no longer be found (a source or target was deleted).'}
              {' Long-press a link to remove it.'}
            </span>
          </div>
        )}

        {/* Empty state: no links at all */}
        {allLinks.length === 0 && (
          <div className="notes-empty">
            <div className="notes-empty-title">No Links Yet</div>
            <div className="notes-empty-hint">
              Select text in any letter or Bible chapter, tap Link in the toolbar, and pick a destination. Your links will appear here.
            </div>
          </div>
        )}

        {/* Empty state: no matches */}
        {allLinks.length > 0 && displayLinks.length === 0 && (
          <div className="notes-empty">
            <div className="notes-empty-title">No Matches</div>
            <div className="notes-empty-hint">Try a different search term.</div>
          </div>
        )}

        {/* Link rows */}
        {displayLinks.length > 0 && (
          <div className="notes-index-list" style={{ marginTop: '0.75rem' }}>
            {displayLinks.map(function(lnk) {
              return (
                <LinkRow
                  key={lnk.id}
                  lnk={lnk}
                  onNavigateSource={onNavigateSource}
                  onNavigateTarget={onNavigateTarget}
                  onLongPress={function(l) { setActionTarget(l); }}
                />
              );
            })}
          </div>
        )}

        {/* Action sheet (long-press on a row) */}
        {actionTarget && (
          <LinkRowActionSheet
            lnk={actionTarget}
            onClose={function() { setActionTarget(null); }}
            onNavigateSource={function(lnk) { onNavigateSource(lnk); setActionTarget(null); }}
            onNavigateTarget={function(lnk) { onNavigateTarget(lnk); setActionTarget(null); }}
            onDelete={onDeleteFromSheet}
          />
        )}
      </div>
    </ScreenLayout>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   NotesIndexScreen — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function NotesIndexScreen({ onBack, onHome, onOpenNote, onNavigateToSource, hlTick, setHlTick, theme, onThemeChange, onSearch, onHistory, onSettings, historyEnabled }) {
  // All notes — annotations on letters, scripture, AND journal paragraphs.
  // Notes from inside journal entries are real annotations and belong here,
  // labeled with their journal source via noteSourceLabel.
  const allNotes = React.useMemo(() => NoteStore.list(), [hlTick]);
  const notebooks = React.useMemo(() => NotebookStore.list(), [hlTick]);
  // Restore the user's place (tab + drilled notebook) when returning from a
  // source tap-through. window.__notesReturnCtx is set in onRowTap before we
  // navigate away and consumed on this mount, so the back-pill ("Back to
  // Devotional") actually lands back in the Devotional drilled view.
  const _notesRet = (typeof window !== 'undefined' && window.__notesReturnCtx) || null;
  const [tab, setTab] = React.useState((_notesRet && _notesRet.tab) || 'notebooks'); // 'notebooks' | 'all-notes'
  const [drilledNbId, setDrilledNbId] = React.useState((_notesRet && _notesRet.drilledNbId) || null); // null | 'uncategorized' | <notebookId>
  React.useEffect(() => { if (typeof window !== 'undefined' && window.__notesReturnCtx) window.__notesReturnCtx = null; }, []);
  const [newNbInline, setNewNbInline] = React.useState(false);
  const [newNbName, setNewNbName] = React.useState('');
  const [renaming, setRenaming] = React.useState(false);
  const [renameValue, setRenameValue] = React.useState('');
  const [confirmDeleteNb, setConfirmDeleteNb] = React.useState(false);
  const [allNotesSort, setAllNotesSort] = React.useState('newest'); // 'newest' | 'oldest'
  const [drilledSort, setDrilledSort] = React.useState('newest');

  // Build the back-pill source label from the user's current location.
  // — Drilled into a user notebook: that notebook's name
  // — Drilled into Uncategorized: "Uncategorized"
  // — All Notes tab: "My Notes" (default)
  const currentSourceTitle = () => {
    if (drilledNbId === 'uncategorized') return 'Uncategorized';
    if (drilledNbId) {
      const nb = NotebookStore.get(drilledNbId);
      if (nb && nb.name) return nb.name;
    }
    return 'My Notes';
  };

  const onRowTap = (note) => {
    const nav = noteSourceNav(note);
    if (nav) {
      window.__pendingOpenNote = note.groupId;
      // Remember which tab/notebook we're in so the back-pill returns the
      // user to the exact list they tapped from (consumed on next mount).
      window.__notesReturnCtx = { tab: tab, drilledNbId: drilledNbId };
      onNavigateToSource(nav, { sourceLetterTitle: currentSourceTitle() });
    } else {
      onOpenNote(note.groupId);
    }
  };

  // Count notes per notebook for the cards
  const counts = React.useMemo(() => {
    const c = { __uncategorized: 0 };
    notebooks.forEach(nb => { c[nb.id] = 0; });
    allNotes.forEach(n => {
      const ids = n.notebookIds || [];
      if (ids.length === 0) c.__uncategorized++;
      else ids.forEach(id => { if (id in c) c[id]++; });
    });
    return c;
  }, [allNotes, notebooks]);

  // Sort helper for newest/oldest
  const sortList = (list, mode) => {
    const arr = [...list];
    arr.sort((a, b) => (b.updated || b.created || 0) - (a.updated || a.created || 0));
    if (mode === 'oldest') arr.reverse();
    return arr;
  };

  // Drilled-in notes for the current notebook
  const drilledNotes = React.useMemo(() => {
    if (!drilledNbId) return [];
    let list;
    if (drilledNbId === 'uncategorized') {
      list = allNotes.filter(n => !n.notebookIds || n.notebookIds.length === 0);
    } else {
      list = allNotes.filter(n => (n.notebookIds || []).includes(drilledNbId));
    }
    return sortList(list, drilledSort);
  }, [allNotes, drilledNbId, drilledSort]);

  const allNotesSorted = React.useMemo(() => sortList(allNotes, allNotesSort), [allNotes, allNotesSort]);

  const createNotebook = () => {
    const trimmed = newNbName.trim();
    if (!trimmed) return;
    NotebookStore.add(trimmed);
    setHlTick(t => t + 1);
    setNewNbName('');
    setNewNbInline(false);
  };

  const drilledNb = drilledNbId && drilledNbId !== 'uncategorized' ? NotebookStore.get(drilledNbId) : null;
  const drilledTitle = drilledNbId === 'uncategorized' ? 'Uncategorized' : (drilledNb ? drilledNb.name : '');

  const startRename = () => {
    if (!drilledNb) return;
    setRenameValue(drilledNb.name);
    setRenaming(true);
  };
  const commitRename = () => {
    const trimmed = renameValue.trim();
    if (trimmed && drilledNb) {
      NotebookStore.rename(drilledNb.id, trimmed);
      setHlTick(t => t + 1);
    }
    setRenaming(false);
  };
  const deleteCurrent = () => {
    if (!drilledNb) return;
    NotebookStore.remove(drilledNb.id);
    setHlTick(t => t + 1);
    setConfirmDeleteNb(false);
    setDrilledNbId(null);
  };

  return (
    <ScreenLayout navChildren={LibraryNav({ onBack: onBack, onSearch: onSearch, onHistory: onHistory, onSettings: onSettings, theme: theme, onThemeChange: onThemeChange })}>
      <div className="notes-index-screen">
        <div className="notes-index-header">
          <h1 className="notes-index-title">My Notes</h1>
          <span className="notes-index-count">{allNotes.length}{allNotes.length === 1 ? " note" : " notes"}</span>
        </div>
        {/* Tab strip — hidden while drilled in */}
        {!drilledNbId && (
          <div className="notes-tabs">
            <button
              className={"notes-tab" + (tab === 'notebooks' ? ' active' : '')}
              onClick={() => setTab('notebooks')}
            >Notebooks</button>
            <button
              className={"notes-tab" + (tab === 'all-notes' ? ' active' : '')}
              onClick={() => setTab('all-notes')}
            >All Notes</button>
          </div>
        )}
        {/* ── DRILLED VIEW (inside a notebook) ── */}
        {drilledNbId && (
          <>
            <div className="nb-drilled-header">
              <button className="nb-drilled-back" onClick={() => { setDrilledNbId(null); setRenaming(false); setConfirmDeleteNb(false); }} title="Back to Notebooks" aria-label="Back to Notebooks">‹</button>
              {renaming
                ? <input
                    className="nb-drilled-rename"
                    autoFocus type="text" value={renameValue}
                    onChange={e => setRenameValue(e.target.value)}
                    // No onBlur commit — explicit Save/Cancel buttons own the
                    // commit so tapping a button doesn't race the blur handler
                    // (Android has no Escape key; blur-commit was non-obvious).
                    onKeyDown={e => { if (e.key === 'Enter') { e.preventDefault(); commitRename(); } else if (e.key === 'Escape') setRenaming(false); }}
                    maxLength={60}
                  />
                : <span className="nb-drilled-title">{drilledTitle}</span>
              }
              {/* Rename mode: explicit Save / Cancel. Otherwise (user notebooks
                  only, not Uncategorized): Rename / Delete. */}
              {renaming
                ? <>
                    <button className="nb-drilled-action" onClick={commitRename} title="Save name">Save</button>
                    <button className="nb-drilled-action" onClick={() => setRenaming(false)} title="Cancel rename">Cancel</button>
                  </>
                : drilledNb && <>
                    <button className="nb-drilled-action" onClick={startRename} title="Rename notebook">Rename</button>
                    <button className="nb-drilled-action danger" onClick={() => setConfirmDeleteNb(true)} title="Delete notebook">Delete</button>
                  </>
              }
            </div>
            {confirmDeleteNb && (
              <div className="ann-chip-confirm" style={{ padding: '10px 12px', marginBottom: '0.8rem' }}>
                <span className="ann-chip-confirm-q">Delete “{drilledTitle}”? Notes will move to Uncategorized.</span>
                <button className="ann-chip-confirm-btn ann-chip-confirm-cancel" onClick={() => setConfirmDeleteNb(false)}>Cancel</button>
                <button className="ann-chip-confirm-btn ann-chip-confirm-yes" onClick={deleteCurrent}>Yes, delete</button>
              </div>
            )}
            {drilledNotes.length > 0 && (
              <div className="notes-index-controls">
                <button
                  className="notes-index-sort-btn"
                  onClick={() => setDrilledSort(s => s === 'newest' ? 'oldest' : 'newest')}
                  style={{ marginLeft: 'auto' }} title="Toggle sort order"
                >{drilledSort === 'newest' ? "Sort: Newest ↓" : "Sort: Oldest ↑"}</button>
              </div>
            )}
            {drilledNotes.length === 0
              ? (
                  <div className="notes-empty">
                    <div className="notes-empty-title">Nothing here yet</div>
                    <div className="notes-empty-hint">
                      {drilledNbId === 'uncategorized'
                        ? "Notes that aren't in any notebook will appear here."
                        : "Add notes to this notebook from the ⋯ menu on any note."
                      }
                    </div>
                  </div>
                )
              : (
                  <div className="notes-index-list">
                    {drilledNotes.map(note => <NoteRow key={note.groupId} note={note} onTap={onRowTap} />)}
                  </div>
                )
            }
          </>
        )}
        {/* ── NOTEBOOKS TAB (cards) ── */}
        {!drilledNbId && tab === 'notebooks' && (
          <div className="nb-card-grid">
            <button
              className="nb-card uncategorized"
              onClick={() => setDrilledNbId('uncategorized')}
            >
              <span className="nb-card-eyebrow">Default</span>
              <span className="nb-card-name">Uncategorized</span>
              <span className="nb-card-count">{counts.__uncategorized}{counts.__uncategorized === 1 ? " note" : " notes"}</span>
              <span className="nb-card-arrow">›</span>
            </button>
            {notebooks.map(nb => (
              <button
                key={nb.id}
                className="nb-card"
                onClick={() => setDrilledNbId(nb.id)}
              >
                <span className="nb-card-eyebrow">Notebook</span>
                <span className="nb-card-name">{nb.name}</span>
                <span className="nb-card-count">{(counts[nb.id] || 0)}{(counts[nb.id] || 0) === 1 ? " note" : " notes"}</span>
                <span className="nb-card-arrow">›</span>
              </button>
            ))}
            {newNbInline
              ? (
                  <div className="nb-card" style={{ cursor: 'default' }}>
                    <div className="nb-card-create-form">
                      <input
                        className="nb-card-create-input"
                        autoFocus type="text"
                        placeholder="Notebook name…"
                        value={newNbName}
                        onChange={e => setNewNbName(e.target.value)}
                        onKeyDown={e => { if (e.key === 'Enter') { e.preventDefault(); createNotebook(); } else if (e.key === 'Escape') { setNewNbInline(false); setNewNbName(''); } }}
                        maxLength={60}
                      />
                      <div className="nb-card-create-actions">
                        <button className="note-sheet-secondary" onClick={() => { setNewNbInline(false); setNewNbName(''); }} style={{ padding: '7px 10px' }}>Cancel</button>
                        <button className={"note-sheet-save" + (newNbName.trim() ? '' : ' disabled')} onClick={createNotebook} disabled={!newNbName.trim()} style={{ padding: '7px 10px' }}>Create</button>
                      </div>
                    </div>
                  </div>
                )
              : (
                  <button
                    className="nb-card new-notebook"
                    onClick={() => setNewNbInline(true)}
                  >
                    <span className="nb-card-plus">+</span>
                    <span className="nb-card-name">New Notebook</span>
                  </button>
                )
            }
          </div>
        )}
        {/* ── ALL NOTES TAB ── */}
        {!drilledNbId && tab === 'all-notes' && (
          <>
            {allNotes.length > 0 && (
              <div className="notes-index-controls">
                <button
                  className="notes-index-sort-btn"
                  onClick={() => setAllNotesSort(s => s === 'newest' ? 'oldest' : 'newest')}
                  style={{ marginLeft: 'auto' }} title="Toggle sort order"
                >{allNotesSort === 'newest' ? "Sort: Newest ↓" : "Sort: Oldest ↑"}</button>
              </div>
            )}
            {allNotes.length === 0
              ? (
                  <div className="notes-empty">
                    <div className="notes-empty-title">No Notes Yet</div>
                    <div className="notes-empty-hint">Long-press text in any chapter, tap Note in the toolbar, and your notes will appear here.</div>
                  </div>
                )
              : (
                  <div className="notes-index-list">
                    {allNotesSorted.map(note => <NoteRow key={note.groupId} note={note} onTap={onRowTap} />)}
                  </div>
                )
            }
          </>
        )}
      </div>
    </ScreenLayout>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   ScripturesHome — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function ScripturesHome({ onSelect, onGenre, onBack, onSearch, onHistory, onSettings, theme, onThemeChange, onMatthewStudy, layout }) {
  const handleTile = (group) => {
    if (group.single) {onSelect(group.books[0].id, true);} else
    onGenre(group.id);
  };
  const handleBook = (id) => {onSelect(id);};
  const allGenres = [...SCRIPTURE_GENRES.ot, ...SCRIPTURE_GENRES.nt];
  const allBooks = allGenres.flatMap((g) => g.books);

  const navBar = (
    <>
      <button className="nav-home" onClick={onBack}>{"← Home"}</button>
      <NavButtons onSettings={onSettings} onHistory={onHistory} onSearch={onSearch} theme={theme} onThemeChange={onThemeChange} />
    </>
  );

  const hero = (
    <>
      <div className="home-eyebrow">New King James Version</div>
      <h1 className="home-title">The Scriptures of Truth</h1>
      <div className="home-ornament">
        <div className="home-ornament-line" />
        <div className="home-ornament-diamond" />
        <div className="home-ornament-line r" />
      </div>
    </>
  );

  /* ── GENRE GRID (default) ── */
  if (layout === "genre" || !layout) return (
    <ScreenLayout navChildren={navBar}>
      <div className="home-screen scriptures-landing">
        {hero}
        <div className="genre-columns">
          <div className="genre-col genre-col-stretch">
            <div className="genre-col-label">Old Testament</div>
            {SCRIPTURE_GENRES.ot.map((g) => {
              const totalCh = g.books.reduce((s, b) => s + (BOOKS[b.id]?.chapters.length || 0), 0);
              const bookCount = g.books.length;
              const bookLabel = `${bookCount} ${bookCount === 1 ? "Book" : "Books"}`;
              return (
                <button key={g.id} className="genre-tile" onClick={() => handleTile(g)}>
                  <div className="genre-tile-title">{g.label}</div>
                  <div className="genre-tile-sub">{bookLabel}{" · "}{totalCh} Chapters</div>
                </button>
              );
            })}
          </div>
          <div className="genre-col genre-col-stretch">
            <div className="genre-col-label">New Testament</div>
            {SCRIPTURE_GENRES.nt.map((g) => {
              const totalCh = g.books.reduce((s, b) => s + (BOOKS[b.id]?.chapters.length || 0), 0);
              const bookCount = g.books.length;
              const bookLabel = `${bookCount} ${bookCount === 1 ? "Book" : "Books"}`;
              return (
                <button key={g.id} className="genre-tile" onClick={() => handleTile(g)}>
                  <div className="genre-tile-title">{g.label}</div>
                  <div className="genre-tile-sub">{bookLabel}{" · "}{totalCh} Chapters</div>
                </button>
              );
            })}
          </div>
        </div>
      </div>
    </ScreenLayout>
  );

  /* ── COMPACT LIST ── */
  if (layout === "compact") return (
    <ScreenLayout navChildren={navBar}>
      <div className="home-screen">
        {hero}
        <div className="compact-list">
          {[
            { label: "Old Testament", genres: SCRIPTURE_GENRES.ot },
            { label: "New Testament", genres: SCRIPTURE_GENRES.nt }
          ].map((section) => (
            <React.Fragment key={section.label}>
              <div className="compact-list-header" style={{ fontSize: "0.65rem", color: "var(--gold)", marginTop: "0.8rem" }}>{section.label}</div>
              {section.genres.map((g) => (
                <div key={g.id} className="compact-list-group">
                  <div className="compact-list-header">{g.label}</div>
                  {g.books.map((b) => (
                    <button key={b.id} className="compact-list-item" onClick={() => handleBook(b.id)}>
                      <span className="compact-list-title">{b.title}</span>
                      <span className="compact-list-detail">{b.detail}</span>
                    </button>
                  ))}
                </div>
              ))}
            </React.Fragment>
          ))}
        </div>
      </div>
    </ScreenLayout>
  );

  /* ── BOOK GRID ── */
  if (layout === "grid") return (
    <ScreenLayout navChildren={navBar}>
      <div className="home-screen">
        {hero}
        <div className="flat-grid">
          {allBooks.map((b) => (
            <button key={b.id} className="flat-grid-card" onClick={() => handleBook(b.id)}>
              <div className="flat-grid-title">{b.title}</div>
              <div className="flat-grid-detail">{b.detail}</div>
            </button>
          ))}
        </div>
      </div>
    </ScreenLayout>
  );

  /* ── CANONICAL SCROLL ── */
  const otBooks = SCRIPTURE_GENRES.ot.flatMap((g) => g.books);
  const ntBooks = SCRIPTURE_GENRES.nt.flatMap((g) => g.books);
  let canonNum = 0;
  return (
    <ScreenLayout navChildren={navBar}>
      <div className="home-screen">
        {hero}
        <div className="canon-scroll">
          <div className="canon-scroll-divider">Old Testament</div>
          {otBooks.map((b) => {
            canonNum++;
            return (
              <button key={b.id} className="canon-card" style={{ animationDelay: `${canonNum * 0.3 % 5}s` }} onClick={() => handleBook(b.id)}>
                <span className="canon-card-num">{String(canonNum).padStart(2, "0")}</span>
                <div className="canon-card-body">
                  <div className="canon-card-title">{b.title}</div>
                  {CANON_SUBTITLES[b.id] && <div className="canon-card-sub">{CANON_SUBTITLES[b.id]}</div>}
                  <div className="canon-card-detail">{b.detail}</div>
                </div>
              </button>
            );
          })}
          <div className="canon-scroll-divider">New Testament</div>
          {ntBooks.map((b) => {
            canonNum++;
            return (
              <button key={b.id} className="canon-card" style={{ animationDelay: `${canonNum * 0.3 % 5}s` }} onClick={() => handleBook(b.id)}>
                <span className="canon-card-num">{String(canonNum).padStart(2, "0")}</span>
                <div className="canon-card-body">
                  <div className="canon-card-title">{b.title}</div>
                  {CANON_SUBTITLES[b.id] && <div className="canon-card-sub">{CANON_SUBTITLES[b.id]}</div>}
                  <div className="canon-card-detail">{b.detail}</div>
                </div>
              </button>
            );
          })}
        </div>
      </div>
    </ScreenLayout>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   SearchScreen — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function SearchScreen({ query, onQueryChange, settings, onSettingsChange, onSelect, onBack, searchScope, searchContext, onToggleScope, onCommand }) {
  const inputRef = React.useRef(null);
  const [state, setState] = React.useState({ phase: 'idle', parsed: null, results: [], terms: [], error: null, total: 0 });
  const [buildInfo, setBuildInfo] = React.useState({ ready: false, building: false, progress: null });
  const [showSuggest, setShowSuggest] = React.useState(false);
  const [suggestions, setSuggestions] = React.useState([]);
  const debounceRef = React.useRef(null);

  // Build index on first mount
  React.useEffect(() => {
    if (!window.VotSearch) {
      setBuildInfo({ ready: false, building: false, progress: null, error: 'Search engine failed to load. Check browser console.' });
      return;
    }
    if (window.VotSearch.getState().ready) {setBuildInfo({ ready: true, building: false, progress: null });return;}
    setBuildInfo({ ready: false, building: true, progress: null });
    window.VotSearch.init({
      onProgress: (done, total) => setBuildInfo((b) => ({ ...b, progress: { done, total } }))
    }).then(() => setBuildInfo({ ready: true, building: false, progress: null })).
    catch((err) => setBuildInfo({ ready: false, building: false, progress: null, error: err?.message || String(err) }));
  }, []);

  // Focus input on mount
  React.useEffect(() => {
    const t = setTimeout(() => {if (inputRef.current) inputRef.current.focus();}, 80);
    return () => clearTimeout(t);
  }, []);

  // Compute suggestions as-you-type. Re-show on every query change, hide only
  // on explicit user action (pick / blur / Escape / clear).
  const [suggestDismissed, setSuggestDismissed] = React.useState(false);
  React.useEffect(() => {setSuggestDismissed(false);}, [query]);
  React.useEffect(() => {
    const q = (query || '').trim();
    if (!q || q.length < 1 || q.length > 40) {setSuggestions([]);setShowSuggest(false);return;}
    const s = window.VotSearch.suggest(q, { max: 8 });
    setSuggestions(s);
    setShowSuggest(s.length > 0 && !buildInfo.building && !suggestDismissed);
  }, [query, buildInfo.building, suggestDismissed]);

  // Run search with debounce — one box, one index, everything included.
  React.useEffect(() => {
    if (!buildInfo.ready) return;
    const q = (query || '').trim();
    if (!q) {setState({ phase: 'idle', parsed: null, results: [], terms: [], error: null, total: 0 });return;}
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => {
      window.VotSearch.search(q, {
        translation: settings.translation || 'nkjv',
        useStopWords: settings.searchUseStopWords !== false,
        scope: searchScope || null,
        corpus: settings.searchCorpus || 'all',
        limit: 400
      }).then((r) => {
        const terms = r.parsed && r.parsed.kind === 'text' ?
        [r.parsed.phrase].filter(Boolean).concat(r.parsedTerms || []) :
        [];
        setState({ phase: 'done', parsed: r.parsed, results: r.results || [], terms, error: r.error ? String(r.error) : null, total: (r.results || []).length });
      }).catch((err) => {
        setState({ phase: 'done', parsed: null, results: [], terms: [], error: err?.message || String(err), total: 0 });
      });
    }, 140);
    return () => {if (debounceRef.current) clearTimeout(debounceRef.current);};
  }, [query, buildInfo.ready, settings.translation, settings.searchUseStopWords, settings.searchCorpus, searchScope]);

  // Handle command-kind parsed results
  React.useEffect(() => {
    if (state.parsed && state.parsed.kind === 'command') {
      if (onCommand) onCommand(state.parsed.action);
    }
  }, [state.parsed]);

  // Group results by source
  const grouped = React.useMemo(() => {
    if (!state.results.length) return [];
    const groups = {};
    for (let i = 0; i < state.results.length; i++) {
      const entry = state.results[i];
      const g = srchGroupKey(entry.doc);
      if (!groups[g]) groups[g] = [];
      groups[g].push(entry);
    }
    const keys = Object.keys(groups);
    keys.sort((a, b) => {
      const aTop = groups[a][0]?.score || 0;
      const bTop = groups[b][0]?.score || 0;
      if (aTop !== bTop) return bTop - aTop;
      return (SRCH_GROUP_META[a]?.order || 99) - (SRCH_GROUP_META[b]?.order || 99);
    });
    return keys.map((k) => ({ key: k, items: groups[k] }));
  }, [state.results]);

  // Build "direct" fake entries from parsed ref/passage/book (shown at top before results).
  // Engine-gated: Scriptures corpus shows only bible/book/named-passage refs;
  // Volumes corpus shows only letter refs. No crossover.
  const directEntries = React.useMemo(() => {
    const p = state.parsed;
    if (!p) return [];
    const curCorpus = settings.searchCorpus || 'all';
    const allowBible = curCorpus === 'all' || curCorpus === 'scriptures';
    const allowLetter = curCorpus === 'all' || curCorpus === 'volumes';
    const out = [];
    if ((p.kind === 'ref-bible' || p.kind === 'named-passage') && allowBible) {
      const lbl = p.bookTitle + ' ' + p.chapter + (p.chapterEnd ? '–' + p.chapterEnd : '') + (p.verseStart ? ':' + p.verseStart + (p.verseEnd ? '-' + p.verseEnd : '') : '');
      out.push({ __direct: true, __corpus: curCorpus, __label: lbl, __sub: p.kind === 'named-passage' ? 'Named passage — open' : 'Open chapter', ref: p });
    } else if (p.kind === 'ref-letter' && allowLetter) {
      out.push({ __direct: true, __corpus: curCorpus, __label: p.label, __sub: 'Open letter', ref: p });
    } else if (p.kind === 'ref-book' && allowBible) {
      out.push({ __direct: true, __corpus: curCorpus, __label: p.bookTitle, __sub: 'Open book index', ref: p });
    }
    return out;
  }, [state.parsed, settings.searchCorpus]);

  // Top results: best 5 cross-corpus hits shown before groups (All mode only,
  // only for text queries — ref queries already have directEntries cards)
  const topResults = React.useMemo(() => {
    if (!state.results.length) return [];
    if (directEntries.length > 0) return [];
    const corpus = settings.searchCorpus || 'all';
    if (corpus !== 'all') return [];
    if (grouped.length <= 1) return [];
    return state.results.slice(0, 5);
  }, [state.results, grouped.length, settings.searchCorpus, directEntries.length]);

  // Fuzzy book suggestion for did-you-mean — very conservative.
  // Only fires when the query is a SHORT single-token that plausibly looks
  // like a mistyped book name (≥4 chars, no spaces, no results, no ref parse).
  const didYouMean = React.useMemo(() => {
    if (!state.parsed || state.parsed.kind !== 'text' || state.results.length) return null;
    const q = (query || '').trim();
    if (!q || q.length < 4 || q.length > 15) return null;
    if (/\s/.test(q)) return null; // multi-word: not a book attempt
    if (/[0-9:.,;\-]/.test(q)) return null; // has digits/punctuation: already a ref attempt
    const guess = window.VotSearch.fuzzyBookSuggest(q);
    if (!guess) return null;
    const disp = window.VotSearchData.BOOK_DISPLAY[guess] || guess;
    if (disp.toLowerCase() === q.toLowerCase()) return null;
    return { original: q, suggestion: disp, rewrite: disp };
  }, [state.parsed, state.results.length, query]);

  const clearQuery = () => {onQueryChange('');setShowSuggest(false);setSuggestDismissed(true);};

  const fireSuggestion = (sug) => {
    onQueryChange(sug.query);
    setShowSuggest(false);
    setSuggestDismissed(true);
  };

  const handleKey = (e) => {
    if (e.key === 'Escape') {
      if (showSuggest) {setShowSuggest(false);setSuggestDismissed(true);} else
      if (query) {clearQuery();} else
      onBack();
    }
  };

  return (
    <ScreenLayout hideTabsBtn={true} navChildren={
      <>
        <button className="nav-home" onClick={onBack} aria-label="Back">{"←"}</button>
        <div className="srch-input-row">
          <input
            ref={inputRef}
            className="search-input"
            type="text"
            placeholder="Search scriptures, volumes, studies…"
            value={query}
            onChange={(e) => onQueryChange(e.target.value)}
            onFocus={() => setShowSuggest(suggestions.length > 0)}
            onKeyDown={handleKey}
            autoComplete="off"
            autoCorrect="off"
            spellCheck={false}
          />
          {query ? <button className="srch-clear-btn" onClick={clearQuery}>{"✕"}</button> : null}
        </div>
      </>
    }>
      <div className="search-screen">

        <div className="srch-corpus-row" role="tablist" aria-label="Search corpus">
          {[
            { k: 'all', label: 'All' },
            { k: 'scriptures', label: 'Scriptures' },
            { k: 'volumes', label: 'Volumes' }
          ].map((opt) => {
            const active = (settings.searchCorpus || 'all') === opt.k;
            return (
              <button
                key={opt.k}
                role="tab"
                aria-selected={active}
                className={"srch-corpus-btn" + (active ? " active" : "")}
                onClick={() => onSettingsChange('searchCorpus', opt.k)}
              >{opt.label}</button>
            );
          })}
        </div>

        {searchContext && (
          <button
            className={"srch-scope-chip " + (searchScope ? "active" : "")}
            onClick={onToggleScope}
          >
            {searchScope ? (
              <>
                <span className="srch-scope-chip-icon">{"✓"}</span>
                <span>Scoped to {searchContext.label}</span>
                <span className="srch-scope-chip-x">{"✕"}</span>
              </>
            ) : (
              <>
                <span className="srch-scope-chip-icon">{"⌕"}</span>
                <span>Search in {searchContext.label}</span>
              </>
            )}
          </button>
        )}

        {buildInfo.error && <div className="srch-error">{buildInfo.error}</div>}

        {buildInfo.building && !buildInfo.progress && (
          <div className="srch-progress">
            <span>Building search index…</span>
          </div>
        )}

        {buildInfo.building && buildInfo.progress && (
          <div className="srch-progress">
            <span>Building search index… {buildInfo.progress.done.toLocaleString()} / {buildInfo.progress.total.toLocaleString()}</span>
            <div className="srch-progress-bar">
              <div className="srch-progress-bar-fill" style={{ width: 100 * buildInfo.progress.done / Math.max(1, buildInfo.progress.total) + '%' }} />
            </div>
          </div>
        )}

        {showSuggest && suggestions.length > 0 && (
          <div className="srch-suggest">
            {suggestions.map((s, i) => (
              <button key={i} className="srch-suggest-item" onMouseDown={(e) => {e.preventDefault();fireSuggestion(s);}}>
                <span className="srch-suggest-kind">{s.kind}</span>
                <span className="srch-suggest-label">{s.label}</span>
                {s.hint && <span className="srch-suggest-hint">{s.hint}</span>}
              </button>
            ))}
          </div>
        )}

        {state.error && <div className="srch-error">Error: {state.error}</div>}

        {!query && buildInfo.ready && (
          <>
            <div className="srch-empty-hero">
              <h3>Search everything</h3>
              <p>Verses, letters, study notes, headings, footnotes — across all 66 books and every Volume.</p>
            </div>
            <div className="srch-section-label">Quick picks</div>
            <div className="srch-quick-row">
              {SRCH_QUICK_PICKS.map((q) => (
                <button key={q} className="srch-quick-chip" onClick={() => onQueryChange(q.toLowerCase())}>{q}</button>
              ))}
            </div>
          </>
        )}

        {didYouMean && (
          <div className="srch-did-you-mean">
            No results for "{didYouMean.original}" — did you mean <button onClick={() => onQueryChange(didYouMean.rewrite)}>{didYouMean.suggestion}</button>?
          </div>
        )}

        {query && buildInfo.ready && state.phase === 'done' && state.results.length > 0 && (
          <div className="srch-results-summary">
            Found <strong>{state.results.length} {state.results.length === 1 ? "match" : "matches"}</strong>
            {" across "}<strong>{grouped.length} {grouped.length === 1 ? "section" : "sections"}</strong>
          </div>
        )}

        {directEntries.length > 0 && (
          <div className="srch-groups">
            {directEntries.map((d, i) => (
              <SrchCard key={'d' + i} entry={d} terms={[]} onSelect={onSelect} isDirect={true} />
            ))}
          </div>
        )}

        {topResults.length > 0 && (
          <div className="srch-top-results">
            <div className="srch-section-label">Best Matches</div>
            {topResults.map((entry, i) => (
              <SrchCard key={'top' + i} entry={entry} terms={state.terms} onSelect={onSelect} />
            ))}
          </div>
        )}

        {grouped.length > 0 && (
          <div className="srch-groups">
            {grouped.map((g, i) => (
              <SrchGroup
                key={g.key + '|' + query}
                gkey={g.key}
                items={g.items}
                terms={state.terms}
                onSelect={onSelect}
                defaultOpen={state.results.length <= 30 || i < 5}
              />
            ))}
          </div>
        )}

        {query && buildInfo.ready && state.phase === 'done' && state.results.length === 0 && directEntries.length === 0 && !didYouMean && (
          <div className="search-no-results">No results for "{query.trim()}"</div>
        )}

      </div>
    </ScreenLayout>
  );
}

