                      <span className="progress-row-tally">{sRead} / {sTotal}</span>
                      <button
                        className={CLEAR_CLASSES[secStage]}
                        disabled={sRead === 0}
                        onClick={handleClearTap(sectionKey, () => sectionBooks(grp).forEach((b) => onClearBook(b.id)))}
                      >
