              >
                <div className="genre-tile-title">{v.title}</div>
                {(v.detail || v.sub) && <div className="genre-tile-sub">{[v.detail, v.sub].filter(Boolean).join(" · ")}</div>}
                {v.locked && <div className="genre-tile-badge">Coming Soon</div>}
              </button>
            ))}
          </div>
          <div className="genre-col genre-col-stretch">
            <div className="genre-col-label">Collections</div>
            {collections.map((b, i) => (
              <button
                key={b.id}
                className={`genre-tile${b.locked ? " locked" : ""}`}
                onClick={() => !b.locked && onSelect(b.id)}
              >
                <div className="genre-tile-title">{b.title}</div>
                {b.sub && <div className="genre-tile-sub">{b.sub}</div>}
                {b.locked && <div className="genre-tile-badge">Coming Soon</div>}
              </button>
            ))}
          </div>
          <button
            className="genre-tile genre-full-width"
            style={{ textAlign: "center", padding: "1.4rem 1rem" }}
            onClick={() => onSelect("garden")}
          >
            <div className="genre-tile-title">A Return to The Garden</div>
            <div className="genre-tile-sub">209 Pages · A Visual Journey</div>
          </button>
        </div>
      </div>
    </ScreenLayout>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   WtlbEntryView — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function WtlbEntryView({ entry, partLabel, onHome, onNavigate, onSearch, onSettings, onHistory, onNavToChapter, prevBoundary, onPrevBoundary, nextBoundary, onNextBoundary, theme, onThemeChange, onMarkRead, onUnmark, isRead, markAsReadEnabled, showProgressBar, scripturesDict, indexLabel, footnotesMode, backHint, onBack, hlTick, onLinkOpen, onInAppLink }) {
  const [scriptureRef, setScriptureRef] = React.useState(null);
  const [scriptureText, setScriptureText] = React.useState(null);
  const [highlightedFn, setHighlightedFn] = React.useState(null);
  const wtlbMainRef = React.useRef(null);
  React.useEffect(() => {
    const pending = window.__pendingHighlight;
    if (!pending || pending.letterId !== entry.id || !pending.excerpt) return;
    window.__pendingHighlight = null;
    const excerpt = pending.excerpt;
    const t = setTimeout(() => highlightExcerptInDom(wtlbMainRef.current, excerpt), 80);
    return () => clearTimeout(t);
  }, [entry.id]);

  // Pre-scan paragraphs for scripture refs.
  const refAnalysis = React.useMemo(() => {
    const perParagraph = [];
    const refNumMap = {};
    const orderedRefs = [];
    let num = 0;
    entry.paragraphs.forEach((p) => {
      const arr = [];
      const re = /\{\{ref:([^}]+)\}\}/g;
      let m;
      while ((m = re.exec(p.text)) !== null) {
        const ref = m[1].trim();
        const after = p.text.slice(m.index + m[0].length);
        const stripped = after.replace(/\{\{(?:ref|nav):[^}]+\}\}/g, '');
        const hasWordChar = /\w/.test(stripped);
        const hasLaterMarker = /\{\{(?:ref|nav):/.test(after);
        const trailing = !hasWordChar && !hasLaterMarker;
        let n = null;
        if (footnotesMode && !trailing) {
          if (!(ref in refNumMap)) {
            num++;
            refNumMap[ref] = num;
            orderedRefs.push(ref);
          }
          n = refNumMap[ref];
        }
        arr.push({ ref, trailing, num: n });
      }
      perParagraph.push(arr);
    });
    return { perParagraph, refNumMap, orderedRefs };
  }, [entry.id, footnotesMode]);

  const lookupVerse = (ref) => {
    const perEntry = entry.scriptures || {};
    const dict = scripturesDict || WTLB_SCRIPTURES;
    return perEntry[ref] || dict[ref] || null;
  };

  React.useEffect(() => {
    if (scriptureRef === null) return;
    var prev = window.__closeSheet;
    window.__closeSheet = () => setScriptureRef(null);
    return () => { window.__closeSheet = prev || null; };
  }, [scriptureRef]);

  const openSheetForRef = (ref) => {
    setScriptureRef(ref);
    setScriptureText(lookupVerse(ref));
  };

  const handleBubbleClick = (ref, n) => {
    openSheetForRef(ref);
  };

  useMarkAsRead(markAsReadEnabled, onMarkRead);

  React.useEffect(() => { setScriptureRef(null); setScriptureText(null); setHighlightedFn(null); }, [entry.id]);

  React.useEffect(() => {
    const root = wtlbMainRef.current;
    if (!root) return;
    root.querySelectorAll('.fn-ref.active').forEach((e) => e.classList.remove('active'));
    if (highlightedFn != null) {
      const el = root.querySelector('.fn-ref[data-fn-num="' + String(highlightedFn).replace(/"/g, '\\"') + '"]');
      if (el) el.classList.add('active');
    }
  }, [highlightedFn, entry.id]);

  const prevEntry = entry.prevEntry;
  const nextEntry = entry.nextEntry;

  const _attrCollectionLabel = (volStr) => {
    if (!volStr) return null;
    const s = String(volStr).trim().toLowerCase();
    const NUMS = { '1':'One', '2':'Two', '3':'Three', '4':'Four', '5':'Five', '6':'Six', '7':'Seven' };
    if (NUMS[s]) return 'Volume ' + NUMS[s];
    const WORDS = ['one','two','three','four','five','six','seven'];
    if (WORDS.includes(s)) return 'Volume ' + s.charAt(0).toUpperCase() + s.slice(1);
    return null;
  };

  const renderLine = (line, consumeRef) => {
    const parts = line.split(/(\*\*.*?\*\*|_.*?_|\{\{ref:[^}]+\}\}|\{\{nav:[^}]+\}\}|\[From [^\]]+\])/g);
    return parts.map((seg, si) => {
      if (!seg) return null;
      if (seg.startsWith('**') && seg.endsWith('**')) return <strong key={si}>{renderLine(seg.slice(2, -2), consumeRef)}</strong>;
      if (seg.startsWith('_') && seg.endsWith('_')) return <em key={si}>{renderLine(seg.slice(1, -1), consumeRef)}</em>;
      const attrMatch = seg.match(/^\[From ["“”](.+?)["“”]\s*~\s*Volume\s+(\d+|[A-Za-z]+)\]$/);
      if (attrMatch && onInAppLink) {
        const title = attrMatch[1];
        const collection = _attrCollectionLabel(attrMatch[2]);
        if (collection) {
          return (
            <span
              key={si}
              className="letter-link-ref"
              onClick={() => onInAppLink(
                { collection: collection, letterTitle: title },
                { sourceLetterTitle: entry.title, sourceVolumeLabel: partLabel || null }
              )}
              title={'Open "' + title + '" in ' + collection}
            >
              {seg}
            </span>
          );
        }
      }
      const refMatch = seg.match(/^\{\{ref:(.+)\}\}$/);
      if (refMatch) {
        const ref = refMatch[1].trim();
        const info = consumeRef();
        if (info && footnotesMode && !info.trailing && info.num != null) {
          const n = info.num;
          return (
            <span
              key={si}
              className={`fn-ref${highlightedFn === n ? " active" : ""}`}
              data-fn-num={n}
              onClick={() => handleBubbleClick(ref, n)}
              title={`Footnote ${n}`}
            >
              {n}
            </span>
          );
        }
        return (
          <a key={si} className="wtlb-cite" href="#" onClick={(e) => { e.preventDefault(); openSheetForRef(ref); }}>
            ({ref})
          </a>
        );
      }
      const navMatch = seg.match(/^\{\{nav:([^:]+):(\d+)\}\}$/);
      if (navMatch) {
        const bookId = navMatch[1], ch = parseInt(navMatch[2], 10);
        const bookTitle = BOOKS[bookId]?.title || bookId;
        return (
          <a key={si} className="fn-link" href="#" onClick={(e) => { e.preventDefault(); onNavToChapter(bookId, ch); }}>
            [{bookTitle} {ch}]
          </a>
        );
      }
      return <React.Fragment key={si}>{seg}</React.Fragment>;
    });
  };

  return (
    <ScreenLayout
      showProgress={showProgressBar}
      navChildren={
        <>
          <button className="nav-home nav-back-icon" onClick={onHome} title="← Index" aria-label="Back to Index">‹</button>
          <HomeBtn />
          <div className="nav-arrows">
            <button
              className="nav-arrow-btn"
              disabled={!prevEntry && !prevBoundary}
              onClick={() => prevEntry ? onNavigate(prevEntry.id) : onPrevBoundary && onPrevBoundary()}
              title="Previous"
              aria-label="Previous entry"
            >‹</button>
            <button
              className="nav-arrow-btn"
              disabled={!nextEntry && !nextBoundary}
              onClick={() => nextEntry ? onNavigate(nextEntry.id) : onNextBoundary && onNextBoundary()}
              title="Next"
              aria-label="Next entry"
            >›</button>
          </div>
          <NavButtons
            onSettings={onSettings}
            onHistory={onHistory}
            onSearch={onSearch}
            theme={theme}
            onThemeChange={onThemeChange}
            reading={true}
            chapterBookmark={entry ? { hlKey: 'wtlb:' + entry.id, label: entry.title || (partLabel ? partLabel + ' — Entry ' + entry.num : 'Bookmark') } : null}
            hlTick={hlTick}
          />
        </>
      }
    >
      <StickyChapterNav
        onPrev={() => prevEntry ? onNavigate(prevEntry.id) : onPrevBoundary && onPrevBoundary()}
        onNext={() => nextEntry ? onNavigate(nextEntry.id) : onNextBoundary && onNextBoundary()}
        prevDisabled={!prevEntry && !prevBoundary}
        nextDisabled={!nextEntry && !nextBoundary}
        prevLabel="Previous entry"
        nextLabel="Next entry"
      />

      {backHint && (
        <div className="back-hint-row">
          <button className="back-hint-pill" onClick={onBack} aria-label="Back to source letter">
            <span className="back-hint-arrow">‹</span>Back to{' '}
            <span className="back-hint-title">{backHint.volumeLabel ? `${backHint.volumeLabel} · ${backHint.title}` : backHint.title}</span>
          </button>
        </div>
      )}

      <header className="hero">
        <div className="hero-bg vol" />
        <div className="hero-content">
          <div className="hero-eyebrow">{partLabel} {"\xA0\xB7\xA0"} {entry.num}</div>
          <h1 className="hero-title">{entry.title}</h1>
          <div className="hero-ornament">
            <div className="hero-ornament-line" />
            <div className="hero-ornament-diamond" />
            <div className="hero-ornament-line r" />
          </div>
        </div>
      </header>

      <div className="page-wrapper">
        <div className="content-layout">
          <main className="letter-body" ref={wtlbMainRef}>
            {entry.paragraphs.map((p, pi) => {
              const paraRefs = refAnalysis.perParagraph[pi] || [];
              let refCursor = 0;
              const consumeRef = () => paraRefs[refCursor++];
              return (
                <p
                  key={entry.id + ":" + pi}
                  style={{ textAlign: p.align }}
                  className={p.align === 'center' ? 'letter-poetry' : 'letter-para'}
                  data-hl-key={wtlbHlKey(entry.id, pi)}
                  data-hl-dom={true}
                >
                  <StaticSubtree>
                    {p.text.split('\n').map((line, li, arr) => (
                      <React.Fragment key={li}>
                        {renderLine(line, consumeRef)}
                        {li < arr.length - 1 && <br />}
                      </React.Fragment>
                    ))}
                  </StaticSubtree>
                </p>
              );
            })}

            {/* Reading-end sentinel: end of body text, before footnotes/nav. */}
            <div className="reading-end" />

            {footnotesMode && refAnalysis.orderedRefs.length > 0 && (
              <div className="footnote-list wtlb-footnote-list">
                <div className="footnote-list-header">Footnotes</div>
                {refAnalysis.orderedRefs.map((ref) => {
                  const num = refAnalysis.refNumMap[ref];
                  const verseText = lookupVerse(ref);
                  return (
                    <div key={ref} id={`wtlb-fn-${entry.id}-${num}`} className={`footnote-list-item${highlightedFn === num ? " pulse" : ""}`}>
                      <div className="footnote-list-num">{num}.</div>
                      <div>
                        <span className="footnote-list-ref">{ref}</span>
                        {verseText && <ExpandableVerse text={verseText} refStr={ref} />}
                      </div>
                    </div>
                  );
                })}
              </div>
            )}

            <div className="ornament-divider">
              <div className="ornament-divider-line" />
              <div className="ornament-divider-symbol">✦</div>
              <div className="ornament-divider-line" />
            </div>

            <div className="bottom-nav">
              {prevEntry ? (
                <button className="bottom-nav-card" onClick={() => onNavigate(prevEntry.id)}>
                  <div className="bottom-nav-label">‹ Previous</div>
                  <div className="bottom-nav-title">{prevEntry.title}</div>
                </button>
              ) : prevBoundary ? (
                <button className="bottom-nav-card" onClick={onPrevBoundary}>
                  <div className="bottom-nav-label">{prevBoundary.short ? `‹ Previous · ${prevBoundary.short}` : "‹ Previous"}</div>
                  <div className="bottom-nav-title">{prevBoundary.title}</div>
                </button>
              ) : (
                <div className="bottom-nav-card placeholder">
                  <div className="bottom-nav-label">‹ Previous</div>
                  <div className="bottom-nav-title">—</div>
                </div>
              )}

              {nextEntry ? (
                <button className="bottom-nav-card next" onClick={() => onNavigate(nextEntry.id)}>
                  <div className="bottom-nav-label">Next ›</div>
                  <div className="bottom-nav-title">{nextEntry.title}</div>
                </button>
              ) : nextBoundary ? (
                <button className="bottom-nav-card next" onClick={onNextBoundary}>
                  <div className="bottom-nav-label">{nextBoundary.short ? `Next · ${nextBoundary.short} ›` : "Next ›"}</div>
                  <div className="bottom-nav-title">{nextBoundary.title}</div>
                </button>
              ) : (
                <div className="bottom-nav-card next placeholder">
                  <div className="bottom-nav-label">Next ›</div>
                  <div className="bottom-nav-title">—</div>
                </div>
              )}
            </div>
          </main>
        </div>
      </div>

      <>
        <div className={`fn-sheet-backdrop${scriptureRef ? " open" : ""}`} onClick={() => setScriptureRef(null)} />
        <div className={`fn-sheet${scriptureRef ? " open" : ""}`}>
          <div className="fn-sheet-handle" />
          {scriptureRef && (
            <>
              <span className="sc-sheet-tag">Scripture Reference</span>
              <span className="sc-sheet-cite">{scriptureRef}</span>
              {scriptureText ? (
                <div className="sc-sheet-verse"><ScriptureVerseText text={scriptureText} cite={scriptureRef} /></div>
              ) : (
                <div className="sc-sheet-verse" style={{ color: 'var(--cream-dim)', fontStyle: 'italic' }}>Verse text not available in app data</div>
              )}
            </>
          )}
        </div>
      </>
    </ScreenLayout>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   BookmarkCreateSheet — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function BookmarkCreateSheet({ pending, onConfirm, onCancel, onDelete, onOpen }) {
  var useState = React.useState;
  var useEffect = React.useEffect;
  var useRef = React.useRef;

  var labelRef = useRef(null);
  var isEditMode = !!(pending && pending.editId);

  var _label = useState(
    isEditMode ? (pending.currentLabel || '') : ((pending && pending.defaultLabel) || '')
  );
  var label = _label[0]; var setLabel = _label[1];
  var _thought = useState(isEditMode ? (pending.currentThought || '') : '');
  var thought = _thought[0]; var setThought = _thought[1];

  // Inline delete-confirm state (tap-confirm strip, never instant)
  var _confirmDel = useState(false);
  var confirmingDelete = _confirmDel[0]; var setConfirmingDelete = _confirmDel[1];

  // Track the values the sheet opened with so we can gate the Save button
  // on an actual change. In EDIT mode this prevents accidental no-op writes
  // (the user opens, glances, taps ✓ out of habit → silent no-op + 'updated'
  // timestamp bump). In CREATE mode we still want Save tappable on first
  // glance, so this ref just records the auto-derived defaults; the canSave
  // rule below treats CREATE differently (any non-empty label is fine).
  var initialRef = useRef({ label: '', thought: '' });

  // Re-sync local state if a different `pending` arrives. The two-key
  // dependency captures both mode (editId) and instance (hlKey), so
  // back-to-back opens (e.g. close edit → open create on another spot)
  // both reset cleanly.
  useEffect(function() {
    if (!pending) return;
    if (pending.editId) {
      setLabel(pending.currentLabel || '');
      setThought(pending.currentThought || '');
      initialRef.current = {
        label: pending.currentLabel || '',
        thought: pending.currentThought || ''
      };
    } else {
      setLabel(pending.defaultLabel || '');
      setThought('');
      initialRef.current = {
        label: pending.defaultLabel || '',
        thought: ''
      };
    }
    setConfirmingDelete(false);
    // Focus the label input on mount so users can immediately refine it
    // in CREATE mode or jump straight to editing in EDIT mode.
    setTimeout(function() {
      if (labelRef.current) {
        labelRef.current.focus();
        labelRef.current.select();
      }
    }, 60);
  }, [pending && pending.editId, pending && pending.hlKey]);

  // canSave drives both the visual disabled state and the keyboard-shortcut
  // guard. EDIT-mode: only if at least one field differs from what we
  // opened with (whitespace-tolerant). CREATE-mode: a non-empty label is
  // enough — the auto-derived default satisfies this on first render so
  // the fast "highlight → ✓" path stays one tap.
  var canSave;
  if (isEditMode) {
    canSave = label.trim() !== initialRef.current.label.trim()
           || thought.trim() !== initialRef.current.thought.trim();
  } else {
    canSave = label.trim().length > 0;
  }

  // Wire Android hardware back to dismiss (same save/restore pattern
  // every overlay in the app uses).
  useEffect(function() {
    if (!pending) return;
    var prev = window.__closeSheet;
    window.__closeSheet = onCancel;
    return function() { window.__closeSheet = prev || null; };
  }, [pending, onCancel]);

  if (!pending) return null;

  function commit() {
    var trimmedLabel = label.trim() || pending.defaultLabel || pending.currentLabel || 'Bookmark';
    var trimmedThought = thought.trim();
    onConfirm({
      editId: pending.editId || null,
      hlKey: pending.hlKey,
      label: trimmedLabel,
      thought: trimmedThought
    });
  }

  function handleDelete() {
    if (!confirmingDelete) { setConfirmingDelete(true); return; }
    if (typeof onDelete === 'function') onDelete(pending.editId);
  }

  function handleOpen() {
    if (typeof onOpen === 'function') onOpen(pending.editId);
  }

  var title = isEditMode ? 'Edit Bookmark' : 'New Bookmark';
  var saveTitle = isEditMode ? 'Save changes' : 'Save bookmark';

  return (
    <div className="link-picker-overlay" onClick={onCancel}>
      <div
        className={'link-picker-sheet navpick-sheet bkm-create-sheet' + (isEditMode ? ' bkm-create-sheet-edit' : '')}
        onClick={function(e) { e.stopPropagation(); }}
      >
        <div className="navpick-header">
          <button
            className="navpick-close navpick-close-undo"
            onClick={onCancel}
            aria-label="Cancel"
          >×</button>
          <span className="navpick-title">{title}</span>
          <button
            className="navpick-confirm-green"
            onClick={canSave ? commit : undefined}
            disabled={!canSave}
            aria-label={saveTitle}
            title={canSave ? saveTitle : (isEditMode ? 'No changes to save' : 'Add a label')}
          >
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <polyline points="20 6 9 17 4 12" />
            </svg>
          </button>
        </div>

        <div className="bkm-create-body">
          {pending.sourceLabel && <div className="bkm-create-source">{pending.sourceLabel}</div>}
          {pending.excerpt && <div className="bkm-create-excerpt">“{pending.excerpt}”</div>}

          <div className="bkm-create-field-label">Label</div>
          <input
            ref={labelRef}
            className="bkm-create-label-input"
            type="text"
            value={label}
            onChange={function(e) { setLabel(e.target.value); }}
            onKeyDown={function(e) {
              if (e.key === 'Enter') { e.preventDefault(); if (canSave) commit(); }
              else if (e.key === 'Escape') { e.preventDefault(); onCancel(); }
            }}
            placeholder="A short name for this bookmark…"
            maxLength={200}
          />

          <div className="bkm-create-field-label">
            A Thought
            <span className="bkm-create-field-hint"> (optional — why did you save this?)</span>
          </div>
          <textarea
            className="bkm-create-thought-input"
            value={thought}
            onChange={function(e) { setThought(e.target.value); }}
            onKeyDown={function(e) {
              if (e.key === 'Escape') { e.preventDefault(); onCancel(); }
              else if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) { e.preventDefault(); if (canSave) commit(); }
            }}
            placeholder="A few words for your future self…"
            rows={4}
          />

          {/* Edit-mode actions: Open Source + Delete (tap-confirm). Only
              rendered when we're editing an existing bookmark.
              `pending.atSource` is set true by callers who know the user is
              already on the bookmarked passage (currently: inline-icon tap
              in dom-bookmarks.js). In that case the Open Source button is
              a no-op so we hide it — keeps the EDIT sheet tighter and
              avoids the dead-action confusion. Future callers from a list
              surface (e.g. BookmarksScreen → row → Edit, if/when wired)
              will leave atSource unset and get the Open button by default. */}
          {isEditMode && (
            <div className="bkm-create-edit-actions">
              {!pending.atSource && (
                <button
                  className="bkm-create-edit-btn"
                  onClick={handleOpen}
                  title="Open this passage"
                >
                  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6" />
                    <polyline points="15 3 21 3 21 9" />
                    <line x1="10" y1="14" x2="21" y2="3" />
                  </svg>
                  <span>Open Source</span>
                </button>
              )}
              {!confirmingDelete && (
                <button
                  className="bkm-create-edit-btn bkm-create-edit-btn-danger"
                  onClick={handleDelete}
                  title="Delete this bookmark"
                >
                  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
                    <polyline points="3 6 5 6 21 6" />
                    <path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6" />
                    <path d="M10 11v6" />
                    <path d="M14 11v6" />
                  </svg>
                  <span>Delete</span>
                </button>
              )}
              {confirmingDelete && (
                <div className="ann-chip-confirm bkm-create-edit-confirm">
                  <span className="ann-chip-confirm-q">Delete bookmark?</span>
                  <button className="ann-chip-confirm-btn ann-chip-confirm-cancel" onClick={function() { setConfirmingDelete(false); }}>Cancel</button>
                  <button className="ann-chip-confirm-btn ann-chip-confirm-yes" onClick={handleDelete}>Yes, delete</button>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   JournalInsertSheet — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function JournalInsertSheet(props) {
  var useState = React.useState;
  var useMemo = React.useMemo;

  var onClose = props.onClose;
  var onInsertBlock = props.onInsertBlock;
  var onInsertImage = props.onInsertImage;
  var onRecordAudio = props.onRecordAudio;
  var excludeJournalId = props.excludeJournalId;

  var _mode = useState('menu');
  var mode = _mode[0]; var setMode = _mode[1];

  var _q = useState('');
  var query = _q[0]; var setQuery = _q[1];

  // Journal block-picker state: which entry the user drilled into.
  var _drilled = useState(null);
  var drilledEntry = _drilled[0]; var setDrilledEntry = _drilled[1];

  function close() { try { onClose && onClose(); } catch (e) {} }

  function emitBlock(block) {
    if (!block) { close(); return; }
    try { onInsertBlock && onInsertBlock(block); }
    catch (e) { console.warn('JournalInsertSheet emitBlock failed', e); }
    close();
  }

  // ── Block constructors ────────────────────────────────────
  function insertDivider() { emitBlock(JournalHelpers.newBlock('divider')); }
  function insertBodyText() { emitBlock(JournalHelpers.newBlock('p', { text: '' })); }

  // ── Card / Excerpt via LinkPicker ────────────────────────
  function openCardPicker() {
    if (typeof window.__openLinkPickerForTarget !== 'function') {
      console.warn('LinkPicker bridge unavailable');
      return;
    }
    close();
    window.__openLinkPickerForTarget('card', function(target, item) {
      try {
        var block = targetToJournalBlock(target, item, false);
        if (block && onInsertBlock) onInsertBlock(block);
      } catch (e) { console.warn('Insert card failed', e); }
    });
  }
  function openExcerptPicker() {
    if (typeof window.__openLinkPickerForTarget !== 'function') {
      console.warn('LinkPicker bridge unavailable');
      return;
    }
    close();
    window.__openLinkPickerForTarget('excerpt', function(target, item) {
      try {
        var block = targetToJournalBlock(target, item, true);
        if (block && onInsertBlock) onInsertBlock(block);
      } catch (e) { console.warn('Insert excerpt failed', e); }
    });
  }

  function targetToJournalBlock(target, item, asExcerpt) {
    if (!target) return null;
    var t = target.type;
    if (t === 'bible' || t === 'study') {
      var hasText = !!(target.text && target.text.length);
      var hasVerse = target.verse != null;
      if (asExcerpt && hasText) {
        var ref = target.label || ((target.bookId || '') + ' ' + (target.chapter || '')
          + (hasVerse ? (':' + target.verse + (target.verseEnd ? '-' + target.verseEnd : '')) : ''));
        return JournalHelpers.newBlock('verse-block', {
          ref: ref,
          text: target.text,
          partial: !!target.partial,
          bookId: target.bookId,
          chapter: target.chapter,
          verse: target.verse || null,
          verseEnd: target.verseEnd || null,
          isStudy: t === 'study'
        });
      }
      if (target.bookId != null && target.chapter != null) {
        return JournalHelpers.newBlock('chapter-card', {
          bookId: target.bookId,
          chapter: target.chapter,
          isStudy: t === 'study'
        });
      }
      return null;
    }
    if (t === 'letter' || t === 'wtlb' || t === 'blessed' || t === 'holy-days' || t === 'study-letter') {
      var letterId = target.letterId || target.entryId || target.studyChapterId;
      var volKey = target.volKey;
      if (!volKey && target.collection && typeof COLLECTIONS !== 'undefined') {
        for (var i = 0; i < COLLECTIONS.length; i++) {
          if (COLLECTIONS[i].label === target.collection) { volKey = COLLECTIONS[i].volKey; break; }
        }
      }
      if (!volKey && item && item.collection && typeof COLLECTIONS !== 'undefined') {
        for (var j = 0; j < COLLECTIONS.length; j++) {
          if (COLLECTIONS[j].label === item.collection) { volKey = COLLECTIONS[j].volKey; break; }
        }
      }
      var extra = { volKey: volKey, letterId: letterId };
      if (t === 'study-letter') {
        extra.studyId = target.studyId;
        extra.studyChapterId = target.studyChapterId || letterId;
      }
      if (asExcerpt && target.text) {
        extra.excerpt = target.text;
        extra.blockKey = target.blockKey || null;
        extra.start = target.start != null ? target.start : null;
        extra.end = target.end != null ? target.end : null;
      }
      if (!volKey || !letterId) return null;
      return JournalHelpers.newBlock('letter-card', extra);
    }
    return null;
  }

  function pickBookmark() { setQuery(''); setMode('pick-bookmark'); }
  function pickNote() { setQuery(''); setMode('pick-note'); }
  function pickJournal() { setQuery(''); setMode('pick-journal'); }
