  function chooseJournal(e) {
    if (!e || !e.id) { close(); return; }
    setQuery('');
    setDrilledEntry(e);
    setMode('pick-journal-block');
  }

  function chooseWholeEntry(e) {
    if (!e || !e.id) { close(); return; }
    emitBlock(JournalHelpers.newBlock('journal-card', { entryId: e.id }));
