    for (var i = 0; i < count; i++) {
      var v = src.length ? src[Math.min(src.length - 1, Math.floor(i * src.length / count))] : 0.3;
      var h = Math.max(4, Math.min(56, Math.round(v * 56)));
      bars.push(
        <div
          key={i}
          className={'bar' + ((i / count) <= prog ? ' is-played' : '')}
          style={{ height: h + 'px' }}
        />
      );
    }
    return (
      <div
        className="jrn-rec-waveform is-scrubbable"
        onClick={seekPreviewFromEvent}
        role="slider"
        aria-label="Scrub recording"
      >
        {bars}
      </div>
    );
  }

  function renderContent() {
    if (stage === 'error') {
      return (
        <div>
          <div className="jrn-rec-error">{error || 'Recording failed.'}</div>
          <div className="jrn-rec-actions">
            <button className="jrn-rec-cancel" onClick={discard}>Close</button>
          </div>
        </div>
      );
    }
    if (stage === 'requesting') {
      return (
        <div className="jrn-rec-content">
          <div className="jrn-rec-requesting">Requesting microphone access…</div>
          <div className="jrn-rec-actions">
            <button className="jrn-rec-cancel" onClick={discard}>Cancel</button>
          </div>
        </div>
      );
    }
    if (stage === 'recording' || stage === 'paused') {
      var isPaused = stage === 'paused';
      return (
        <div className="jrn-rec-content">
          <div className={"jrn-rec-status" + (isPaused ? ' is-paused' : '')}>{isPaused ? 'Paused' : 'Recording'}</div>
          <div className="jrn-rec-time">{fmtTime(seconds)}</div>
          {renderRecordingWave(waveLive)}
          <div className="jrn-rec-actions">
            <button className="jrn-rec-cancel" onClick={discard} aria-label="Cancel">Cancel</button>
            {isPaused ? (
              <button className="jrn-rec-pause-btn" onClick={resumeRecording} aria-label="Resume" title="Resume">
                <svg viewBox="0 0 24 24" fill="currentColor">
                  <path d="M6 3v18l16-9z" />
                </svg>
              </button>
            ) : (
              <button className="jrn-rec-pause-btn" onClick={pauseRecording} aria-label="Pause" title="Pause">
                <svg viewBox="0 0 24 24" fill="currentColor">
                  <path d="M6 4h4v16H6zM14 4h4v16h-4z" />
                </svg>
              </button>
            )}
            <button className="jrn-rec-stop-btn" onClick={stopRecording} aria-label="Finish" title="Finish">
              <svg viewBox="0 0 24 24" fill="currentColor">
                <rect x={6} y={6} width={12} height={12} rx={2} />
              </svg>
            </button>
          </div>
        </div>
      );
    }
    // preview — scrub through real waveform, green ✓ to confirm
    return (
      <div className="jrn-rec-content jrn-rec-preview">
        <div className="jrn-rec-status">Review</div>
        <div className="jrn-rec-time">
          {fmtTime(Math.floor((progress || 0) * (previewDurationRef.current || seconds)))}
          <span className="jrn-rec-time-total">{' / ' + fmtTime(previewDurationRef.current || seconds)}</span>
        </div>
        {renderScrubWave(waveFinal, progress)}
        <div className="jrn-rec-preview-actions">
          <button className="jrn-rec-pp" onClick={togglePreviewPlay} aria-label={previewPlaying ? 'Pause' : 'Play'} title={previewPlaying ? 'Pause' : 'Play'}>
            <svg viewBox="0 0 24 24" fill="currentColor">
              {previewPlaying
                ? <path d="M6 4h4v16H6zM14 4h4v16h-4z" />
                : <path d="M6 3v18l16-9z" />}
            </svg>
          </button>
        </div>
        <div className="jrn-rec-actions">
          <button className="jrn-rec-discard-btn" onClick={discard} aria-label="Discard" title="Discard">×</button>
          <button className="jrn-rec-confirm-btn" onClick={save} aria-label="Save" title="Save">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.6" strokeLinecap="round" strokeLinejoin="round">
              <polyline points="20 6 9 17 4 12" />
            </svg>
          </button>
        </div>
        {previewUrlRef.current && (
          <audio
            ref={previewAudioRef}
            src={previewUrlRef.current}
            style={{ display: 'none' }}
            onPlay={function() { setPreviewPlaying(true); }}
            onPause={function() { setPreviewPlaying(false); }}
            onEnded={function() { setPreviewPlaying(false); setProgress(0); }}
            onTimeUpdate={onPreviewTimeUpdate}
          />
        )}
      </div>
    );
  }

  return (
    <div className="note-sheet-overlay" onClick={function(e) { if (e.target === e.currentTarget) discard(); }}>
      <div className="note-sheet jrn-rec-sheet" onClick={function(e) { e.stopPropagation(); }}>
        <div className="note-sheet-header">
          <span className="note-sheet-title" style={{ flex: 1 }}>{stage === 'preview' ? 'Review Recording' : 'Voice Recording'}</span>
          {stage !== 'preview' && (
            <button className="note-sheet-menu-btn" onClick={discard} aria-label="Close" style={{ fontSize: '18px' }}>×</button>
          )}
        </div>
        {renderContent()}
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   LinkPicker — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function LinkPicker({ sourceKey, sourceLabel, sourceStart, sourceEnd, sourceText, hlTick, setHlTick, onClose, onRequestRefine, lastCreatedLink, onLinkCreated, mode, onPickTarget }) {
  const [input, setInput] = React.useState('');
  const inputRef = React.useRef(null);
  // Re-read RecentNavStore every render so newly-added picks float to the top
  // without remounting the picker. Cheap localStorage read; runs at most once
  // per render.
  const [, setRecentTick] = React.useState(0);
  const bumpRecent = React.useCallback(() => setRecentTick(t => t + 1), []);
  const recent = RecentNavStore.list();
  React.useEffect(() => {
    if (inputRef.current) setTimeout(() => inputRef.current.focus(), 50);
  }, []);

  // Android back button closes the picker (same save/restore pattern as every
  // other overlay in the app — picks up the previous closer on unmount).
  React.useEffect(() => {
    const prev = window.__closeSheet;
    window.__closeSheet = onClose;
    return () => { window.__closeSheet = prev || null; };
  }, [onClose]);

  // Compute search results (or empty when input is empty)
  const results = React.useMemo(() => {
    if (!input.trim()) return [];
    return searchNavIndex(input.trim(), 30).map(s => s.item);
  }, [input]);

  const createLinkTo = React.useCallback((item) => {
    if (!item) return;
    const target = navItemToEndpoint(item);
    if (!target) return;
    RecentNavStore.add(item);

    // mode === 'card' → return the target directly without prompting for an
    // excerpt. Used by Journal's "Insert card" flow when the user only wants
    // a chapter/letter title (no body excerpt).
    if (mode === 'card' && onPickTarget) {
      onPickTarget(target, item);
      return;
    }

    // Refinement step:
    //   Bible/study chapter without a specific verse → verse picker
    //   Letter/WTLB/Blessed/Holy-Days → excerpt picker (text range)
    //   In 'excerpt' mode we ALWAYS run the picker (even for already-versed
    //   refs like "Eph 6:5") so the user can narrow further; in link/picker
    //   default mode we only refine when a chapter has no verse yet.
    const needsVersePicker =
      (target.type === 'bible' || target.type === 'study') &&
      (mode === 'excerpt' || !target.verse);
    const needsExcerptPicker =
      target.type === 'letter' || target.type === 'wtlb' ||
      target.type === 'blessed' || target.type === 'holy-days' ||
      target.type === 'study-letter';
    if (needsVersePicker || needsExcerptPicker) {
      onRequestRefine && onRequestRefine({
        kind: needsVersePicker ? 'verse' : 'excerpt',
        target, item
      });
      return; // refinement screen takes over (it leaves us back here on confirm)
    }

    // Source-less mode without refinement (rare — only Bible refs with both
    // book and verse pre-supplied AND not in excerpt mode). In picker mode,
    // hand the target back; in link mode, require a source to persist.
    if (mode === 'card' || mode === 'excerpt') {
      onPickTarget && onPickTarget(target, item);
      return;
    }
    if (!sourceKey) return;
    // Direct create: stay open so user can confirm (✓) or undo (×).
    const sourceEndpoint = buildSourceEndpoint(sourceKey, sourceLabel, sourceStart, sourceEnd, sourceText);
    const newLink = persistLink(sourceEndpoint, target);
    if (newLink) {
      setHlTick(t => t + 1);
      bumpRecent();
      onLinkCreated(newLink);
    }
  }, [sourceKey, sourceLabel, sourceStart, sourceEnd, sourceText, setHlTick, bumpRecent, onLinkCreated, mode, onPickTarget]);

  // Render a row for a nav item (used in both Results and Recent lists)
  const renderItemRow = (item, key) => (
    <button
      key={key}
      className="navpick-row"
      onClick={() => createLinkTo(item)}
    >
      <div className={"navpick-row-icon navpick-row-icon-" + item.kind}>
        {item.kind === 'bible-chapter' ? (item.category === 'Old Testament' ? 'OT' : 'NT') :
          item.kind === 'study-chapter' ? 'SB' :
          item.kind === 'study-letter-chapter' ? 'LS' :
          (COL_NAV_ICON.get(item.collection) || '?')}
      </div>
      <div className="navpick-row-text">
        <div className="navpick-row-label">{item.label}</div>
        <div className="navpick-row-cat">{item.category || ''}</div>
      </div>
    </button>
  );

  const isEmptyQuery = !input.trim();

  return (
    <div className="link-picker-overlay" onClick={onClose}>
      <div className="link-picker-sheet navpick-sheet" onClick={e => e.stopPropagation()}>
        {/* Header: title + red × (undo last link) + green ✓ (confirm & close) */}
        <div className="navpick-header">
          <span className="navpick-title">{mode === 'card' ? "Embed a Card" : mode === 'excerpt' ? "Embed an Excerpt" : "Link"}</span>
          <button
            className="navpick-close navpick-close-undo"
            onClick={() => {
              if (lastCreatedLink) {
                LinkStore.remove(lastCreatedLink.id);
                onLinkCreated(null);
              }
              onClose();
            }}
            aria-label="Cancel"
          >
            ×
          </button>
          {lastCreatedLink && (
            <button
              className="navpick-confirm-green"
              onClick={onClose}
              aria-label="Done"
            >
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <polyline points="20 6 9 17 4 12" />
              </svg>
            </button>
          )}
        </div>
        {/* Search input (rounded pill matching reference) */}
        <div className="navpick-search-wrap">
          <input
            ref={inputRef}
            className="navpick-search-input"
            placeholder="Search for verses, letters, or titles…"
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => { if (e.key === 'Enter' && results.length > 0) createLinkTo(results[0]); }}
          />
        </div>
        {/* Body: Recent OR Results */}
        <div className="navpick-body">
          {isEmptyQuery ? (
            recent.length > 0 ? (
              <>
                <div className="navpick-section-label">Recent</div>
                {recent.map((item, i) => renderItemRow(item, 'r' + i))}
              </>
            ) : (
              <div className="navpick-empty">
                <div className="navpick-empty-title">Search to link</div>
                <div className="navpick-empty-hint">Examples: "Eph 6:5", "v1l2", "WTLB1 33", or a letter title.</div>
              </div>
            )
          ) : (
            results.length > 0 ? (
              <>
                <div className="navpick-section-label">Results</div>
                {results.map((item, i) => renderItemRow(item, 's' + i))}
              </>
            ) : (
              <div className="navpick-empty">
                <div className="navpick-empty-title">No matches</div>
                <div className="navpick-empty-hint">Try "Genesis 1", "Eph 6:5", "V2 letter 5", "The Wide Path", "WTLB1 33".</div>
              </div>
            )
          )}
        </div>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   LinkSidebar — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function LinkSidebar({ hlKey, hlTick, setHlTick, onClose, onNavigate }) {
  // Letter/WTLB/Blessed/Holy-Days blocks anchor links by block-index, but
  // excerpts append ":start-end" to the stored endpoint key. Use prefix
  // matching for those scopes so the sidebar finds excerpt-scoped links from
  // the bare block hlKey. Bible verses stay exact-match (verse N is N).
  const isBlockScope = hlKey && (hlKey.startsWith('letter:') || hlKey.startsWith('wtlb:') || hlKey.startsWith('blessed:') || hlKey.startsWith('holy-days:'));
  const links = React.useMemo(
    () => isBlockScope ? LinkStore.getForKeyPrefix(hlKey) : LinkStore.getForKey(hlKey),
    [hlKey, hlTick, isBlockScope]
  );
  React.useEffect(() => {
    if (!hlKey) return;
    const prev = window.__closeSheet;
    window.__closeSheet = onClose;
    return () => { window.__closeSheet = prev || null; };
  }, [hlKey, onClose]);
  if (!hlKey) return null;
  // Show a count subtitle instead of a hardcoded date. The sidebar can contain
  // links created on different days (multiple links on one passage), so a
  // fixed "today" date would be actively misleading. A count is always correct
  // and tells the user at a glance how many links are on this passage.
  const countStr = links.length === 0 ? 'No links' : (links.length === 1 ? '1 link' : links.length + ' links');
  return (
    <>
      <div className="link-sidebar-overlay" onClick={onClose} />
      <div className="link-sidebar">
        <div className="link-sidebar-header">
          <button className="link-sidebar-close" onClick={onClose} title="Close">×</button>
          <span className="link-sidebar-title">Links</span>
        </div>
        <div className="link-sidebar-date">{countStr}</div>
        <div className="link-sidebar-body">
          {links.length === 0 && <div className="link-sidebar-empty">No links yet</div>}
          {links.map(lnk => <LinkCard key={lnk.id} lnk={lnk} hlKey={hlKey} isBlockScope={isBlockScope} onNavigate={onNavigate} setHlTick={setHlTick} />)}
        </div>
      </div>
    </>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   NoteSheet — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function NoteSheet({ groupId, startInEditMode, hlTick, setHlTick, onClose, onOpenNotebookPicker }) {
  const note = React.useMemo(() => NoteStore.get(groupId), [groupId, hlTick]);
  const segs = React.useMemo(() => AnnotationStore.getByGroup(groupId), [groupId, hlTick]);
  const [mode, setMode] = React.useState(startInEditMode ? 'edit' : 'read');
  const [body, setBody] = React.useState(note ? note.body || '' : '');
  const [menuOpen, setMenuOpen] = React.useState(false);
  const [confirmDelete, setConfirmDelete] = React.useState(false);
  const [showColors, setShowColors] = React.useState(false);
  const textareaRef = React.useRef(null);

  React.useEffect(() => {
    if (mode === 'edit' && textareaRef.current) {
      textareaRef.current.focus();
      // Move cursor to end so Edit-after-existing-content lands at the tail
      const len = textareaRef.current.value.length;
      textareaRef.current.setSelectionRange(len, len);
    }
  }, [mode]);

  if (!note || !segs.length) {
    // Note record went missing — close
    return null;
  }
  const color = note.color || 'yellow';
  const anchor = note.fullText || segs.map(s => s.ann.text || '').join(' … ');
  const truncatedAnchor = anchor.length > 220 ? anchor.slice(0, 220) + '…' : anchor;

  const save = () => {
    NoteStore.update(groupId, { body });
    setHlTick(t => t + 1);
    onClose();
  };

  const cancelEdit = () => {
    setBody(note.body || '');
    if (startInEditMode && !note.body) {
      // Fresh new note, never saved — convert back to a plain highlight
      // so the selection the user made is preserved on screen.
      AnnotationStore.convertGroup(groupId, 'highlight');
      NoteStore.remove(groupId);
      setHlTick(t => t + 1);
      onClose();
      return;
    }
    setMode('read');
  };

  const recolor = (c) => {
    AnnotationStore.recolorGroup(groupId, c);
    NoteStore.update(groupId, { color: c });
    setHlTick(t => t + 1);
    setShowColors(false);
    setMenuOpen(false);
  };

  const remove = () => {
    AnnotationStore.removeGroup(groupId);
    NoteStore.remove(groupId);
    setHlTick(t => t + 1);
    onClose();
  };

  const share = () => {
    const text = anchor + (note.body ? '\n\n' + note.body : '');
    if (navigator.share) navigator.share({ text }).catch(() => {});
    else navigator.clipboard.writeText(text).catch(() => {});
    setMenuOpen(false);
  };

  const closeOverlay = () => {
    if (menuOpen) { setMenuOpen(false); setConfirmDelete(false); setShowColors(false); return; }
    onClose();
  };

  // Blank notes are allowed — the body can be empty.
  const canSave = true;
  // Tapping the header color dot opens the color picker — works in either
  // mode AND closes any other panel that's open (menu, delete confirm).
  const openColorPicker = () => {
    setShowColors(true);
    setMenuOpen(false);
    setConfirmDelete(false);
  };

  return (
    <div className="note-sheet-overlay" onClick={closeOverlay}>
      <div className="note-sheet" onClick={e => e.stopPropagation()}>
        {/* Header: color dot (tappable) · "Note" · ⋯ menu (read mode only) */}
        <div className="note-sheet-header">
          <button
            className="note-sheet-color-dot ann-chip-color-btn"
            data-color={color}
            onClick={openColorPicker}
            title="Change color"
            aria-label="Change note color"
          />
          <div className="note-sheet-title">{mode === 'edit' ? (note.body ? 'Edit note' : 'New note') : 'Note'}</div>
          {mode === 'read' && (
            <button
              className="note-sheet-menu-btn"
              onClick={() => { setMenuOpen(v => !v); setShowColors(false); setConfirmDelete(false); }}
              aria-label="Options"
            >
              <svg viewBox="0 0 24 24" fill="currentColor">
                <circle cx="12" cy="5" r="1.7" />
                <circle cx="12" cy="12" r="1.7" />
                <circle cx="12" cy="19" r="1.7" />
              </svg>
            </button>
          )}
        </div>
        {/* Color picker takes over the body area when opened — by tapping the
            header dot OR the ⋯ menu's "Change color" item. */}
        {showColors ? (
          <div className="note-sheet-menu-colors">
            <button className="ann-chip-back" onClick={() => setShowColors(false)} title="Back">‹</button>
            {HL_COLORS.map(c => (
              <button
                key={c}
                className={"ann-chip-color-btn" + (color === c ? ' active' : '')}
                data-color={c}
                onClick={() => recolor(c)}
                title={c}
              />
            ))}
          </div>
        ) : (
          <>
            {/* Anchor text (italic quote) */}
            <div className="note-sheet-anchor">“{truncatedAnchor}”</div>
            {/* Date row — read mode only. Shows when the note was last edited
                (or when it was created if never edited). Subtle Cinzel caps
                so it doesn't compete with the body content. */}
            {mode === 'read' && (note.updated || note.created) && (
              <div className="note-sheet-date">{relativeDate(note.updated || note.created)}</div>
            )}
            {/* Edit mode: always-visible color row so users can pick a color
                without needing to open the ⋯ menu first. */}
            {mode === 'edit' && (
              <div className="note-edit-colors">
                {HL_COLORS.map(c => (
                  <button
                    key={c}
                    className={"ann-chip-color-btn" + (color === c ? ' active' : '')}
                    data-color={c}
                    onClick={() => recolor(c)}
                    title={c}
                  />
                ))}
              </div>
            )}
            {/* Notebook chips (only in read mode and only if any are assigned) */}
            {mode === 'read' && (note.notebookIds || []).length > 0 && (
              <div className="note-sheet-nb-chips">
                {(note.notebookIds || []).map(id => {
                  const nb = NotebookStore.get(id);
                  if (!nb) return null;
                  return (
                    <span key={id} className="note-sheet-nb-chip">
                      <svg viewBox="0 0 24 24">
                        <path d="M4 4h11l5 5v11a1 1 0 0 1-1 1H4z" />
                        <polyline points="15 4 15 9 20 9" />
                      </svg>
                      {nb.name}
                    </span>
                  );
                })}
              </div>
            )}
            {/* Body — read mode displays it; edit mode shows textarea */}
            {mode === 'read' ? (
              note.body
                ? <div className="note-sheet-body">{note.body}</div>
                : <div className="note-sheet-empty">Empty note. Tap ⋯ → Edit to add text.</div>
            ) : (
              <textarea
                ref={textareaRef}
                className="note-sheet-textarea"
                value={body}
                onChange={e => setBody(e.target.value)}
                placeholder="Write your note…"
                onFocus={() => {
                  setTimeout(() => {
                    try { textareaRef.current && textareaRef.current.scrollIntoView({ block: 'nearest', behavior: 'smooth' }); } catch (e) {}
                  }, 220);
                }}
              />
            )}
            {/* Edit mode: notebook assignment row — always visible so users
                can assign to a notebook during creation, not just after. */}
            {mode === 'edit' && (
              <button
                className="note-edit-nb-row"
                onClick={() => { onOpenNotebookPicker && onOpenNotebookPicker(groupId); }}
              >
                <svg viewBox="0 0 24 24" fill="none" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M4 4h11l5 5v11a1 1 0 0 1-1 1H4z" />
                  <polyline points="15 4 15 9 20 9" />
                </svg>
                {(note.notebookIds || []).length > 0
                  ? ((note.notebookIds || []).map(id => { const nb = NotebookStore.get(id); return nb ? nb.name : null; }).filter(Boolean).join(', ') || "Add to notebook…")
                  : "Add to notebook…"}
              </button>
            )}
            {/* Read mode: no Edit footer — use ⋯ → Edit. Edit mode: Cancel + Save.
                Save is always enabled — blank notes are valid. */}
            {mode === 'edit' && (
              <div className="note-sheet-footer">
                <button className="note-sheet-secondary" onClick={cancelEdit}>Cancel</button>
                <button className="note-sheet-save" onClick={save}>Save</button>
              </div>
            )}
            {/* ⋯ menu panel (read mode only). Color sub-panel was hoisted above
                so the menu only carries the action items + delete confirm. */}
            {mode === 'read' && menuOpen && (
              <div className="note-sheet-menu">
                {confirmDelete ? (
                  <div className="ann-chip-confirm">
                    <span className="ann-chip-confirm-q">Delete this note?</span>
                    <button className="ann-chip-confirm-btn ann-chip-confirm-cancel" onClick={() => setConfirmDelete(false)}>Cancel</button>
                    <button className="ann-chip-confirm-btn ann-chip-confirm-yes" onClick={remove}>Yes, delete</button>
                  </div>
                ) : (
                  <>
                    <button className="note-sheet-menu-item" onClick={() => { setMenuOpen(false); setMode('edit'); }}>Edit note</button>
                    <button className="note-sheet-menu-item" onClick={() => { setMenuOpen(false); openColorPicker(); }}>Change color</button>
                    <button
                      className="note-sheet-menu-item"
                      onClick={() => { setMenuOpen(false); onOpenNotebookPicker && onOpenNotebookPicker(groupId); }}
                    >
                      {((note.notebookIds || []).length > 0 ? "Manage notebooks…" : "Add to notebook…")}
                    </button>
                    <button className="note-sheet-menu-item" onClick={share}>Share</button>
                    <button className="note-sheet-menu-item danger" onClick={() => setConfirmDelete(true)}>Delete note</button>
                  </>
                )}
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   NotebookManagerSheet — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function NotebookManagerSheet({ hlTick, setHlTick, onClose }) {
  const notebooks = React.useMemo(() => NotebookStore.list(), [hlTick]);
  const [newName, setNewName] = React.useState('');
  const [renameId, setRenameId] = React.useState(null);    // notebook id being renamed
  const [renameValue, setRenameValue] = React.useState('');
  const [confirmDeleteId, setConfirmDeleteId] = React.useState(null);

  const counts = React.useMemo(() => {
    const map = {};
    NoteStore.list().forEach(n => {
      (n.notebookIds || []).forEach(id => { map[id] = (map[id] || 0) + 1; });
    });
    return map;
  }, [hlTick]);

  const createNotebook = () => {
    const trimmed = newName.trim();
    if (!trimmed) return;
    NotebookStore.add(trimmed);
    setHlTick(t => t + 1);
    setNewName('');
  };

  const startRename = (nb) => { setRenameId(nb.id); setRenameValue(nb.name); };
  const commitRename = () => {
    const trimmed = renameValue.trim();
    if (trimmed && renameId) {
      NotebookStore.rename(renameId, trimmed);
      setHlTick(t => t + 1);
    }
    setRenameId(null);
    setRenameValue('');
  };
  const cancelRename = () => { setRenameId(null); setRenameValue(''); };

  const deleteNb = (id) => {
    NotebookStore.remove(id);
    setHlTick(t => t + 1);
    setConfirmDeleteId(null);
  };

  return (
    <div className="nb-picker-overlay" onClick={onClose}>
      <div className="nb-picker" onClick={e => e.stopPropagation()}>
        <div className="nb-picker-header">
          <span className="nb-picker-title">Manage Notebooks</span>
          <button className="nb-picker-close" onClick={onClose} aria-label="Close">×</button>
        </div>
        <div className="nb-picker-new">
          <input
            className="nb-picker-new-input"
            type="text"
            placeholder="New notebook name…"
            value={newName}
            onChange={e => setNewName(e.target.value)}
            onKeyDown={e => { if (e.key === 'Enter') { e.preventDefault(); createNotebook(); } }}
            maxLength={60}
          />
          <button
            className={"nb-picker-new-btn" + (newName.trim() ? '' : ' disabled')}
            onClick={createNotebook}
            disabled={!newName.trim()}
          >Create</button>
        </div>
        {notebooks.length === 0
          ? <div className="nb-picker-empty">No notebooks yet. Type a name above to create your first one.</div>
          : <div className="nb-picker-list">
              {notebooks.map(nb => {
                if (confirmDeleteId === nb.id) {
                  return (
                    <div key={nb.id} className="ann-chip-confirm" style={{ padding: '10px 12px' }}>
                      <span className="ann-chip-confirm-q">Delete “{nb.name}”? Notes will move to Uncategorized.</span>
                      <button className="ann-chip-confirm-btn ann-chip-confirm-cancel" onClick={() => setConfirmDeleteId(null)}>Cancel</button>
                      <button className="ann-chip-confirm-btn ann-chip-confirm-yes" onClick={() => deleteNb(nb.id)}>Yes, delete</button>
                    </div>
                  );
                }
                if (renameId === nb.id) {
                  return (
                    <div key={nb.id} className="nb-picker-row checked" style={{ gap: '8px' }}>
                      <input
                        className="nb-picker-new-input"
                        type="text"
                        autoFocus
                        value={renameValue}
                        onChange={e => setRenameValue(e.target.value)}
                        onKeyDown={e => { if (e.key === 'Enter') { e.preventDefault(); commitRename(); } else if (e.key === 'Escape') cancelRename(); }}
                        maxLength={60}
                        style={{ flex: 1 }}
                      />
                      <button className="nb-picker-row-delete" onClick={cancelRename} title="Cancel">✕</button>
                      <button className="nb-picker-new-btn" onClick={commitRename}>Save</button>
                    </div>
                  );
                }
                const count = counts[nb.id] || 0;
                return (
                  <div key={nb.id} className="nb-picker-row" style={{ cursor: 'default' }}>
                    <span className="nb-picker-name">{nb.name}</span>
                    <span style={{ fontFamily: "'Cinzel',serif", fontSize: '0.52rem', letterSpacing: '0.12em', textTransform: 'uppercase', color: 'var(--cream-muted)', marginRight: '8px' }}>{count}{count === 1 ? ' note' : ' notes'}</span>
                    <button className="nb-picker-row-delete" onClick={() => startRename(nb)} title="Rename" style={{ color: 'var(--cream-muted)', padding: '4px 8px' }}>✎</button>
                    <button className="nb-picker-row-delete" onClick={() => setConfirmDeleteId(nb.id)} title="Delete notebook" aria-label="Delete notebook">×</button>
                  </div>
                );
              })}
            </div>
        }
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   NotebookPickerSheet — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function NotebookPickerSheet({ groupId, hlTick, setHlTick, onClose }) {
  const note = React.useMemo(() => NoteStore.get(groupId), [groupId, hlTick]);
  const notebooks = React.useMemo(() => NotebookStore.list(), [hlTick]);
  const [newName, setNewName] = React.useState('');
  const [confirmDeleteNb, setConfirmDeleteNb] = React.useState(null); // notebook id or null
  const inputRef = React.useRef(null);

  if (!note) return null;
  const memberIds = new Set(note.notebookIds || []);

  const createNotebook = () => {
    const trimmed = newName.trim();
    if (!trimmed) return;
    const nb = NotebookStore.add(trimmed);
    if (nb) {
      // Auto-add the note to the freshly-created notebook
      NoteStore.toggleNotebook(groupId, nb.id);
      setHlTick(t => t + 1);
      setNewName('');
    }
  };

  const toggle = (nbId) => {
    NoteStore.toggleNotebook(groupId, nbId);
    setHlTick(t => t + 1);
  };

  const deleteNb = (nbId) => {
    NotebookStore.remove(nbId);
    setHlTick(t => t + 1);
    setConfirmDeleteNb(null);
  };

  return (
    <div className="nb-picker-overlay" onClick={onClose}>
      <div className="nb-picker" onClick={e => e.stopPropagation()}>
        <div className="nb-picker-header">
          <span className="nb-picker-title">{memberIds.size > 0 ? "Manage Notebooks" : "Add to Notebook"}</span>
          <button className="nb-picker-close" onClick={onClose} aria-label="Close">×</button>
        </div>
        <div className="nb-picker-new">
          <input
            ref={inputRef}
            className="nb-picker-new-input"
            type="text"
            placeholder="New notebook name…"
            value={newName}
            onChange={e => setNewName(e.target.value)}
            onKeyDown={e => { if (e.key === 'Enter') { e.preventDefault(); createNotebook(); } }}
            maxLength={60}
          />
          <button
            className={"nb-picker-new-btn" + (newName.trim() ? '' : ' disabled')}
            onClick={createNotebook}
            disabled={!newName.trim()}
          >Create</button>
        </div>
        {notebooks.length === 0
          ? <div className="nb-picker-empty">No notebooks yet. Type a name above to create your first one.</div>
          : <div className="nb-picker-list">
              {notebooks.map(nb => {
                if (confirmDeleteNb === nb.id) {
                  return (
                    <div key={nb.id} className="ann-chip-confirm" style={{ padding: '10px 12px' }}>
                      <span className="ann-chip-confirm-q">Delete “{nb.name}”? Notes will move to Uncategorized.</span>
                      <button className="ann-chip-confirm-btn ann-chip-confirm-cancel" onClick={() => setConfirmDeleteNb(null)}>Cancel</button>
                      <button className="ann-chip-confirm-btn ann-chip-confirm-yes" onClick={() => deleteNb(nb.id)}>Yes, delete</button>
                    </div>
                  );
                }
                const checked = memberIds.has(nb.id);
                return (
                  <div
                    key={nb.id}
                    className={"nb-picker-row" + (checked ? ' checked' : '')}
                    onClick={() => toggle(nb.id)}
                    role="button"
                  >
                    <span className="nb-picker-check">
                      {checked && (
                        <svg viewBox="0 0 24 24">
                          <polyline points="20 6 9 17 4 12" />
                        </svg>
                      )}
                    </span>
                    <span className="nb-picker-name">{nb.name}</span>
                    <button
                      className="nb-picker-row-delete"
                      onClick={(e) => { e.stopPropagation(); setConfirmDeleteNb(nb.id); }}
                      title="Delete notebook"
                      aria-label="Delete notebook"
                    >×</button>
                  </div>
                );
              })}
            </div>
        }
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   SelectionToolbar — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function SelectionToolbar({ hlTick, setHlTick, onLinkRequest, onNoteRequest, onBookmarkRequest }) {
  const [visible, setVisible] = React.useState(false);
  const [pos, setPos] = React.useState({ x: 0, y: 0 });
  const [selInfo, setSelInfo] = React.useState(null); // { hlKey, start, end, text, existingHl, multiVerse }
  const [activeStyle, setActiveStyle] = React.useState('highlight'); // 'highlight' | 'underline'
  const toolbarRef = React.useRef(null);
  const suppressRef = React.useRef(false);

  // Compute character offset of a node+offset within a data-hl-key container's text
  const computeOffset = React.useCallback((container, node, offset) => {
    const walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT, null, false);
    let charPos = 0;
    while (walker.nextNode()) {
      if (walker.currentNode === node) return charPos + offset;
      charPos += walker.currentNode.textContent.length;
    }
    return charPos + offset;
  }, []);

  // Find the data-hl-key container for a DOM node
  const findHlContainer = React.useCallback((node) => {
    let el = node.nodeType === 3 ? node.parentElement : node;
    while (el && !el.dataset.hlKey) el = el.parentElement;
    return el;
  }, []);

  // Track whether the pointer/finger is currently down (drag in progress)
  const dragRef = React.useRef(false);
  // Debounce timer for selectionchange → show (handle-drag scenario)
  const selChangeTimerRef = React.useRef(null);
  // Track tap target and position for tap-on-mark detection
  const tapTargetRef = React.useRef(null);
  const tapPosRef = React.useRef({ x: 0, y: 0 });

  // Expose a hide bridge so the App-level navigation effect can dismiss
  // the toolbar when the user leaves the screen — otherwise the
  // always-mounted toolbar would persist with a stale selInfo anchored
  // to a hlKey that no longer exists.
  React.useEffect(() => {
    window.__hideSelectionToolbar = () => {
      setVisible(false);
      try { const s = window.getSelection(); if (s) s.removeAllRanges(); } catch (e) {}
    };
    return () => { window.__hideSelectionToolbar = null; };
  }, []);

  React.useEffect(() => {
    // Compute and show the toolbar from the current selection
    const computeAndShow = () => {
      if (suppressRef.current) return;
      const sel = window.getSelection();
      if (!sel || sel.isCollapsed || sel.rangeCount === 0) {
        setVisible(false);
        return;
      }
      const range = sel.getRangeAt(0);
      // Strip .fn-ref bubbles and .hl-note-icon elements from the selection text
      // so footnote numbers and note icons don't bleed into the link preview.
      const text = (() => {
        try {
          const frag = range.cloneContents();
          frag.querySelectorAll('.fn-ref, .hl-note-icon').forEach(function(el) { el.remove(); });
          return frag.textContent.trim();
        } catch (e) {
          return sel.toString().trim();
        }
      })();
      if (!text) { setVisible(false); return; }
      const container = findHlContainer(range.startContainer);
      const endContainer = findHlContainer(range.endContainer);
      const isMultiVerse = !container || !endContainer || endContainer !== container;
      if (isMultiVerse) {
        // Cross-container selection: find all [data-hl-key] containers that overlap
        const allHlContainers = Array.from(document.querySelectorAll('[data-hl-key]'))
          .filter(function(c) { return range.intersectsNode(c); });
        if (allHlContainers.length === 0) { setVisible(false); return; }
        setSelInfo({ hlKey: null, start: 0, end: 0, text, existingHl: null, multiVerse: true, multiContainers: allHlContainers });
      } else {
        const hlKey = container.dataset.hlKey;
        const start = computeOffset(container, range.startContainer, range.startOffset);
        const end = computeOffset(container, range.endContainer, range.endOffset);
        if (start >= end) { setVisible(false); return; }
        const existing = HighlightStore.get(hlKey).find(h => h.start <= start && h.end >= end);
        setSelInfo({ hlKey, start, end, text, existingHl: existing || null, multiVerse: false });
      }
      const rect = range.getBoundingClientRect();
      const toolbarW = 320;
      let x = rect.left + rect.width / 2 - toolbarW / 2;
      x = Math.max(8, Math.min(x, window.innerWidth - toolbarW - 8));
      let y = rect.top - 10;
      if (y < 80) y = rect.bottom + 10;
      setPos({ x, y });
      setVisible(true);
    };

    // Selection-change listener: hide on collapse; debounce-show after handle-drag
    const onSelectionChange = () => {
      if (suppressRef.current) return;
      const sel = window.getSelection();
      if (!sel || sel.isCollapsed || sel.rangeCount === 0) {
        if (selChangeTimerRef.current) { clearTimeout(selChangeTimerRef.current); selChangeTimerRef.current = null; }
        // Tiny delay so toolbar tap can fire before hiding
        setTimeout(() => {
          if (!suppressRef.current) {
            const s = window.getSelection();
            if (!s || s.isCollapsed) setVisible(false);
          }
        }, 150);
      } else if (!dragRef.current) {
        // Non-empty selection and pointer is already up: this is a handle-drag
        // adjustment. Debounce so we wait for the user to finish dragging.
        if (selChangeTimerRef.current) clearTimeout(selChangeTimerRef.current);
        selChangeTimerRef.current = setTimeout(function() {
          selChangeTimerRef.current = null;
          computeAndShow();
        }, 350);
      }
    };

    // Pointer/touch lifecycle: track drag state and commit on release
    const onPointerDown = (e) => {
      if (toolbarRef.current && toolbarRef.current.contains(e.target)) return;
      tapTargetRef.current = e.target;
      tapPosRef.current = { x: e.clientX || 0, y: e.clientY || 0 };
      dragRef.current = true;
      setVisible(false);
    };
    const onPointerUp = (e) => {
      if (!dragRef.current) return;
      dragRef.current = false;
      const sel = window.getSelection();
      const isCollapsed = !sel || sel.isCollapsed;
      const tapTarget = tapTargetRef.current;
      const pos = (e && e.clientX) ? { x: e.clientX, y: e.clientY } : tapPosRef.current;
      // Tap detection: collapsed selection + tap on a mark or note icon.
      // Notes route to NoteSheet (read mode); highlights/underlines route
      // to the action chip. Overlapping note marks at the tap point show
      // the multi-note disambiguation popover.
      if (isCollapsed && tapTarget) {
        const el = tapTarget.nodeType === 3 ? tapTarget.parentElement : tapTarget;
        // Note icon at end of a note span — opens note (or multi-note popover
        // if it's a merged badge icon) directly via the icon's own click handler
        const iconEl = el && el.closest('.hl-note-icon');
        if (iconEl) {
          const gids = (iconEl.getAttribute('data-group-ids') || iconEl.getAttribute('data-group-id') || '').split(',').filter(Boolean);
          if (gids.length > 1 && window.__showMultiNote) { window.__showMultiNote(gids, pos.x, pos.y); return; }
          if (gids.length === 1 && window.__openNote) { window.__openNote(gids[0]); return; }
        }
        const markEl = el && el.closest('mark.hl-mark');
        if (markEl) {
          const groupId = markEl.getAttribute('data-group-id') || markEl.getAttribute('data-hl-id');
          const kind = markEl.getAttribute('data-kind') || 'highlight';
          const containerEl = markEl.closest('[data-hl-key]');
          const hlKey = containerEl ? containerEl.getAttribute('data-hl-key') : null;
          if (groupId && hlKey) {
            if (kind === 'note') {
              // Look for OTHER overlapping note marks at this exact tap point
              const overlapGids = new Set([groupId]);
              try {
                const stack = document.elementsFromPoint(pos.x, pos.y);
                stack.forEach(n => {
                  if (n.matches && n.matches('mark.hl-note[data-kind="note"]')) {
                    const g = n.getAttribute('data-group-id');
                    if (g) overlapGids.add(g);
                  }
                });
              } catch (e) {}
              if (overlapGids.size > 1 && window.__showMultiNote) {
                window.__showMultiNote([...overlapGids], pos.x, pos.y);
                return;
              }
              if (window.__openNote) { window.__openNote(groupId); return; }
            }
            if (window.__showAnnChip) { window.__showAnnChip(pos.x, pos.y + 12, hlKey, groupId); return; }
          }
        }
      }
      setTimeout(computeAndShow, 150);
    };

    // Android long-press / right-click: same routing as tap.
    const onContextMenu = (e) => {
      const hlContainer = e.target.closest('[data-hl-key]');
      if (hlContainer) e.preventDefault();
      const iconEl = e.target.closest('.hl-note-icon');
      if (iconEl) {
        const gid = iconEl.getAttribute('data-group-id');
        if (gid && window.__openNote) { setVisible(false); window.__openNote(gid); return; }
      }
      const mark = e.target.closest('mark.hl-mark');
      if (mark) {
        const groupId = mark.getAttribute('data-group-id') || mark.getAttribute('data-hl-id');
        const kind = mark.getAttribute('data-kind') || 'highlight';
        const container = mark.closest('[data-hl-key]');
        const hlKey = container ? container.getAttribute('data-hl-key') : null;
        if (groupId && hlKey) {
          setVisible(false);
          if (kind === 'note' && window.__openNote) { window.__openNote(groupId); return; }
          if (window.__showAnnChip) { window.__showAnnChip(e.clientX, e.clientY, hlKey, groupId); return; }
        }
      }
      setTimeout(computeAndShow, 80);
    };

    document.addEventListener('selectionchange', onSelectionChange);
    document.addEventListener('pointerdown', onPointerDown);
    document.addEventListener('pointerup', onPointerUp);
    document.addEventListener('touchend', onPointerUp);
    document.addEventListener('contextmenu', onContextMenu);

    return () => {
      document.removeEventListener('selectionchange', onSelectionChange);
      document.removeEventListener('pointerdown', onPointerDown);
      document.removeEventListener('pointerup', onPointerUp);
      document.removeEventListener('touchend', onPointerUp);
      document.removeEventListener('contextmenu', onContextMenu);
    };
  }, [computeOffset, findHlContainer, hlTick]);

  const applyHighlight = React.useCallback((color) => {
    if (!selInfo) return;
    suppressRef.current = true;
    const kind = activeStyle === 'underline' ? 'underline' : 'highlight';
    if (selInfo.multiVerse) {
      // Multi-container: all spans share ONE groupId so they act as one annotation
      const sel = window.getSelection();
      const range = sel && sel.rangeCount > 0 ? sel.getRangeAt(0) : null;
      const containers = selInfo.multiContainers ||
        (range ? Array.from(document.querySelectorAll('[data-hl-key]')).filter(function(c) { return range.intersectsNode(c); }) : []);
      const groupId = hlId();
      // Recolor semantics: only remove groups whose range EXACTLY matches
      // the new selection in this container — partial overlap is preserved
      // so users can layer highlights/underlines/notes.
      const groupsToRemove = new Set();
      containers.forEach(function(container) {
        var hlKey = container.dataset.hlKey;
        var containerLen = container.textContent.length;
        var start = range && container.contains(range.startContainer)
          ? computeOffset(container, range.startContainer, range.startOffset) : 0;
        var end = range && container.contains(range.endContainer)
          ? computeOffset(container, range.endContainer, range.endOffset) : containerLen;
        AnnotationStore.get(hlKey).forEach(function(h) {
          if (h.start === start && h.end === end && h.groupId) groupsToRemove.add(h.groupId);
        });
      });
      groupsToRemove.forEach(function(gid) { AnnotationStore.removeGroup(gid); NoteStore.remove(gid); });
      // Now add the new group — snap each container's range to word boundaries
      containers.forEach(function(container) {
        var hlKey = container.dataset.hlKey;
        var containerText = container.textContent;
        var containerLen = containerText.length;
        var rawStart = range && container.contains(range.startContainer)
          ? computeOffset(container, range.startContainer, range.startOffset) : 0;
        var rawEnd = range && container.contains(range.endContainer)
          ? computeOffset(container, range.endContainer, range.endOffset) : containerLen;
        var snap = snapRangeToWords(containerText, rawStart, rawEnd);
        if (snap.start >= snap.end) return;
        AnnotationStore.add(hlKey, {
          id: hlId(), groupId: groupId, kind: kind,
          start: snap.start, end: snap.end, color: color,
          text: containerText.slice(snap.start, snap.end),
          created: Date.now()
        });
      });
    } else {
      // Single container — only remove EXACT-RANGE matches (recolor flow).
      // Partial overlap stacks: the user can layer multiple highlights,
      // underlines, and notes on the same passage. Range snaps to whole-word
      // boundaries first so the visual mark never lands mid-word.
      const container = document.querySelector('[data-hl-key="' + selInfo.hlKey.replace(/"/g, '\\"') + '"]');
      const containerText = container ? container.textContent : selInfo.text;
      const snap = snapRangeToWords(containerText, selInfo.start, selInfo.end);
      const existing = AnnotationStore.get(selInfo.hlKey);
      const groupsToRemove = new Set();
      existing.forEach(h => {
        if (h.start === snap.start && h.end === snap.end && h.groupId) groupsToRemove.add(h.groupId);
      });
      groupsToRemove.forEach(gid => { AnnotationStore.removeGroup(gid); NoteStore.remove(gid); });
      const id = hlId();
      AnnotationStore.add(selInfo.hlKey, {
        id: id, groupId: id, kind: kind,
        start: snap.start, end: snap.end,
        color: color, text: containerText.slice(snap.start, snap.end),
        created: Date.now()
      });
    }
    window.getSelection().removeAllRanges();
    setVisible(false);
    setHlTick(t => t + 1);
    setTimeout(() => { suppressRef.current = false; }, 300);
  }, [selInfo, activeStyle, setHlTick, computeOffset]);

  const removeHighlight = React.useCallback(() => {
    if (!selInfo) return;
    suppressRef.current = true;
    const sel = window.getSelection();
    const range = sel && sel.rangeCount > 0 ? sel.getRangeAt(0) : null;
    const containers = selInfo.multiVerse
      ? (selInfo.multiContainers ||
          (range ? Array.from(document.querySelectorAll('[data-hl-key]')).filter(c => range.intersectsNode(c)) : []))
      : [document.querySelector('[data-hl-key="' + (selInfo.hlKey || '').replace(/"/g, '\\"') + '"]')].filter(Boolean);
    const removedGroups = new Set();
    containers.forEach(function(container) {
      if (!container) return;
      var hlKey = container.dataset.hlKey;
      var containerLen = container.textContent.length;
      var start = selInfo.multiVerse
        ? (range && container.contains(range.startContainer) ? computeOffset(container, range.startContainer, range.startOffset) : 0)
        : selInfo.start;
      var end = selInfo.multiVerse
        ? (range && container.contains(range.endContainer) ? computeOffset(container, range.endContainer, range.endOffset) : containerLen)
        : selInfo.end;
      AnnotationStore.get(hlKey).forEach(function(h) {
        if (h.start < end && h.end > start && h.groupId && !removedGroups.has(h.groupId)) {
          removedGroups.add(h.groupId);
          AnnotationStore.removeGroup(h.groupId);
          NoteStore.remove(h.groupId);
        }
      });
    });
    window.getSelection().removeAllRanges();
    setVisible(false);
    setHlTick(t => t + 1);
    setTimeout(() => { suppressRef.current = false; }, 300);
  }, [selInfo, setHlTick, computeOffset]);

  const copyText = React.useCallback(() => {
    if (!selInfo) return;
    navigator.clipboard.writeText(selInfo.text).catch(() => {});
    window.getSelection().removeAllRanges();
    setVisible(false);
  }, [selInfo]);

  const handleLink = React.useCallback(() => {
    if (!selInfo) return;
    window.getSelection().removeAllRanges();
    setVisible(false);
    // For multi-container selections anchor the link to the first hl-key container
    var linkInfo = selInfo;
    if (selInfo.multiVerse && selInfo.multiContainers && selInfo.multiContainers.length > 0) {
      linkInfo = Object.assign({}, selInfo, { hlKey: selInfo.multiContainers[0].dataset.hlKey });
    }
    onLinkRequest && onLinkRequest(linkInfo);
  }, [selInfo, onLinkRequest]);

  const handleNote = React.useCallback(() => {
    if (!selInfo) return;
    // Default note color = yellow. If selection sits inside an existing
    // group, convert that group to a note (preserving color); otherwise
    // create a new note-kind annotation across the selected range(s).
    const sel = window.getSelection();
    const range = sel && sel.rangeCount > 0 ? sel.getRangeAt(0) : null;
    let groupId;
    if (selInfo.multiVerse) {
      const containers = selInfo.multiContainers ||
        (range ? Array.from(document.querySelectorAll('[data-hl-key]')).filter(c => range.intersectsNode(c)) : []);
      // Look for an OVERLAPPING non-note group within the selection range.
      // If found, convert it (highlight/underline → note). Notes always
      // stack — never convert an existing note; create a new one alongside.
      let convertTarget = null;
      containers.forEach(function(container) {
        if (convertTarget) return;
        var hlKey = container.dataset.hlKey;
        var containerLen = container.textContent.length;
        var start = range && container.contains(range.startContainer)
          ? computeOffset(container, range.startContainer, range.startOffset) : 0;
        var end = range && container.contains(range.endContainer)
          ? computeOffset(container, range.endContainer, range.endOffset) : containerLen;
        AnnotationStore.get(hlKey).forEach(function(h) {
          if (convertTarget) return;
          if (h.start < end && h.end > start && h.kind !== 'note' && h.groupId) {
            convertTarget = h.groupId;
          }
        });
      });
      if (convertTarget) {
        AnnotationStore.convertGroup(convertTarget, 'note');
        groupId = convertTarget;
      } else {
        groupId = hlId();
        containers.forEach(function(container) {
          var hlKey = container.dataset.hlKey;
          var containerText = container.textContent;
          var containerLen = containerText.length;
          var rawStart = range && container.contains(range.startContainer)
            ? computeOffset(container, range.startContainer, range.startOffset) : 0;
          var rawEnd = range && container.contains(range.endContainer)
            ? computeOffset(container, range.endContainer, range.endOffset) : containerLen;
          var snap = snapRangeToWords(containerText, rawStart, rawEnd);
          if (snap.start >= snap.end) return;
          AnnotationStore.add(hlKey, {
            id: hlId(), groupId: groupId, kind: 'note',
            start: snap.start, end: snap.end, color: 'yellow',
            text: containerText.slice(snap.start, snap.end),
            created: Date.now()
          });
        });
      }
    } else {
      // Single-container: snap to word boundaries, then look for any
      // OVERLAPPING non-note covering group to convert; otherwise create
      // new (allowing stacking with existing notes on the same range).
      const container = document.querySelector('[data-hl-key="' + selInfo.hlKey.replace(/"/g, '\\"') + '"]');
      const containerText = container ? container.textContent : selInfo.text;
      const snap = snapRangeToWords(containerText, selInfo.start, selInfo.end);
      // Empty / whitespace-only / collapsed selection — bail before we create
      // a zero-width annotation (would render as nothing but persist forever).
      if (snap.start >= snap.end) {
        window.getSelection().removeAllRanges();
        setVisible(false);
        return;
      }
      const existing = AnnotationStore.get(selInfo.hlKey).find(h =>
        h.start <= snap.start && h.end >= snap.end && h.kind !== 'note'
      );
      if (existing) {
        AnnotationStore.convertGroup(existing.groupId, 'note');
        groupId = existing.groupId;
      } else {
        const id = hlId();
        groupId = id;
        AnnotationStore.add(selInfo.hlKey, {
          id: id, groupId: id, kind: 'note',
          start: snap.start, end: snap.end,
          color: 'yellow', text: containerText.slice(snap.start, snap.end),
          created: Date.now()
        });
      }
    }
    // Build/refresh the NoteStore record — but only if at least one
    // segment actually exists for this groupId.
    const segs = AnnotationStore.getByGroup(groupId);
    if (segs.length === 0) {
      window.getSelection().removeAllRanges();
      setVisible(false);
      return;
    }
    const fullText = segs.map(s => s.ann.text || '').join(' … ');
    const keys = [...new Set(segs.map(s => s.key))];
    const existingNote = NoteStore.get(groupId);
    NoteStore.set(groupId, {
      color: segs[0] ? segs[0].ann.color : 'yellow',
      fullText, keys,
      body: existingNote ? existingNote.body : ''
    });
    window.getSelection().removeAllRanges();
    setVisible(false);
    setHlTick(t => t + 1);
    onNoteRequest && onNoteRequest(groupId, /*startInEditMode=*/true);
  }, [selInfo, setHlTick, onNoteRequest, computeOffset]);

  const handleShare = React.useCallback(() => {
    if (!selInfo) return;
    const text = selInfo.text;
    if (navigator.share) {
      navigator.share({ text }).catch(() => {});
    } else {
      navigator.clipboard.writeText(text).catch(() => {});
    }
    window.getSelection().removeAllRanges();
    setVisible(false);
  }, [selInfo]);

  const handleSearch = React.useCallback(() => {
    if (!selInfo) return;
    const text = selInfo.text;
    window.getSelection().removeAllRanges();
    setVisible(false);
    // Stash query & route to search screen via global bridge
    window.__pendingSearchQuery = text;
    if (window.__goSearch) window.__goSearch();
  }, [selInfo]);

  const handleBookmark = React.useCallback(() => {
    if (!selInfo) return;
    // Determine the hlKey: single-container uses selInfo.hlKey;
    // multi-container uses the first container's key.
    var hlKey = selInfo.hlKey;
    if (selInfo.multiVerse && selInfo.multiContainers && selInfo.multiContainers.length > 0) {
      hlKey = selInfo.multiContainers[0].dataset.hlKey;
    }
    if (!hlKey) { window.getSelection().removeAllRanges(); setVisible(false); return; }

    // Snap selection range to word boundaries (single-container only;
    // multi-container bookmarks use the first-container start as a proxy).
    var container = document.querySelector('[data-hl-key="' + hlKey.replace(/"/g, '\\"') + '"]');
    var containerText = container ? container.textContent : (selInfo.text || '');
    var snap = (typeof snapRangeToWords === 'function')
      ? snapRangeToWords(containerText, selInfo.start || 0, selInfo.end || 0)
      : { start: selInfo.start || 0, end: selInfo.end || 0 };

    // Derive label from the highlighted text. Two-strategy approach so the
    // label is reliably the user's actual selection across every selection
    // shape:
    //   1. Container slice with word-boundary snap — preferred when we have
    //      the source container and a valid offset range. Keeps the label
    //      tidy when the user's drag ends mid-word.
    //   2. Raw selInfo.text fallback — needed for multi-container
    //      selections (start/end are 0 in that branch) and for the rare case
    //      where the container DOM has unmounted between selection and tap.
    //   3. Source-style fallback ("Bookmark in <Title>") only if both
    //      above produced nothing — defensive last resort.
    var labelText = '';
    if (container && snap.end > snap.start) {
      labelText = containerText.slice(snap.start, snap.end).trim();
    }
    if (!labelText && selInfo.text) {
      labelText = selInfo.text.trim();
    }
    // Truncate very long auto-labels to 120 chars so they read as a short tag
    if (labelText.length > 120) labelText = labelText.slice(0, 117) + '...';
    if (!labelText) {
      // Build a human-readable fallback from the container key kind
      var parts = hlKey.split(':');
      var kind = parts[0];
      if (kind === 'bible' || kind === 'study') {
        labelText = 'Bookmark';
      } else if (kind === 'letter' || kind === 'wtlb' || kind === 'blessed' || kind === 'holy-days') {
        var ctx = (typeof findEntryContext === 'function') ? findEntryContext(parts[1], kind) : null;
        labelText = ctx && ctx.title ? ('Bookmark in ' + ctx.title) : 'Bookmark';
      } else {
        labelText = 'Bookmark';
      }
    }

    // Build the stored hlKey: append :start-end if we have a valid range.
    var storedKey = hlKey;
    if (snap.end > snap.start) {
      storedKey = hlKey + ':' + snap.start + '-' + snap.end;
    }

    // Excerpt: same two-strategy pattern as labelText so the preview block
    // in the BookmarkCreateSheet always shows the actual highlight.
    var excerpt = '';
    if (container && snap.end > snap.start) {
      excerpt = containerText.slice(snap.start, snap.end);
    }
    if (!excerpt && selInfo.text) {
      excerpt = selInfo.text;
    }
    if (excerpt.length > 220) excerpt = excerpt.slice(0, 217) + '...';

    // Source label: re-use the same derivation that BookmarksScreen rows do.
    var sourceLabel = (typeof _bookmarkSourceLabel === 'function')
      ? _bookmarkSourceLabel(storedKey)
      : '';

    window.getSelection().removeAllRanges();
    setVisible(false);

    // Open the pre-commit BookmarkCreateSheet — replaces the previous
    // silent BookmarkStore.add. The sheet lets the user refine the
    // auto-derived label and add an optional thought BEFORE persisting,
    // then commits on its own (App-level onConfirm wires the store write).
    if (typeof window.__bookmarkCreate === 'function') {
      window.__bookmarkCreate({
        hlKey: storedKey,
        sourceLabel: sourceLabel,
        excerpt: excerpt,
        defaultLabel: labelText
      });
    } else {
      // Fallback: defensive path if the App-level bridge wasn't installed
      // yet — directly persist so we never lose the user's intent.
      BookmarkStore.add({
        id: (typeof bkmId === 'function') ? bkmId() : ('bkm_' + Date.now()),
        hlKey: storedKey, label: labelText, thought: '',
        created: Date.now(), updated: Date.now()
      });
      if (typeof setHlTick === 'function') setHlTick(function(t) { return t + 1; });
    }
    if (typeof onBookmarkRequest === 'function') onBookmarkRequest(storedKey);
  }, [selInfo, setHlTick, onBookmarkRequest]);

  if (!visible || !selInfo) return null;

  // Style label preview: the colored "A" varies based on activeStyle
  const styleAClass = (color) => 'sel-style-A sel-style-A-' + (activeStyle === 'underline' ? 'underline' : 'fill') + ' sel-style-A-' + color;

  var mv = selInfo.multiVerse;
  // Show color row for multi-verse too, as long as there are hl-key containers affected
  var mvCanHighlight = mv && selInfo.multiContainers && selInfo.multiContainers.length > 0;
  var showColors = !mv || mvCanHighlight;
  // For multi-verse: check if ANY of the containers has an overlapping highlight to show ✕
  var mvHasExisting = mvCanHighlight && (selInfo.multiContainers || []).some(function(c) {
    return HighlightStore.get(c.dataset.hlKey).length > 0;
  });

  return (
    <div
      ref={toolbarRef}
      className="sel-toolbar"
      style={{ left: pos.x, top: pos.y, transform: 'translateY(-100%)' }}
      onPointerDown={(e) => { e.stopPropagation(); suppressRef.current = true; }}
      onPointerUp={() => { setTimeout(() => { suppressRef.current = false; }, 300); }}
    >
      {/* Top row: style toggle + colors */}
      {showColors && (
        <div className="sel-toolbar-row sel-toolbar-styles">
          <button
            className={"sel-style-btn" + (activeStyle === 'highlight' ? ' active' : '')}
            onClick={() => setActiveStyle('highlight')}
            title="Highlight"
          >
            A
          </button>
          <button
            className={"sel-style-btn sel-style-btn-underline" + (activeStyle === 'underline' ? ' active' : '')}
            onClick={() => setActiveStyle('underline')}
            title="Underline"
          >
            A
          </button>
          <div className="sel-toolbar-divider" />
          <div className="sel-toolbar-colors">
            {HL_COLORS.map(c => (
              <button
                key={c}
                className={"sel-color-btn sel-color-" + activeStyle + (selInfo.existingHl && selInfo.existingHl.color === c && (selInfo.existingHl.kind || 'highlight') === activeStyle ? ' active' : '')}
                data-color={c}
                onClick={() => applyHighlight(c)}
                title={c}
              />
            ))}
            {(selInfo.existingHl || mvHasExisting) && (
              <button
                className="sel-color-btn sel-color-clear"
                onClick={removeHighlight}
                title="Remove highlight"
              >
                ✕
              </button>
            )}
          </div>
        </div>
      )}
      {/* Action buttons: note only for single-container; link + copy/share/search always */}
      <div className="sel-toolbar-row sel-toolbar-actions">
        {!mv && (
          <button className="sel-action-btn" onClick={handleNote} title="Note">
            <svg viewBox="0 0 24 24">
              <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" />
              <polyline points="14 2 14 8 20 8" />
              <line x1="8" y1="13" x2="16" y2="13" />
              <line x1="8" y1="17" x2="16" y2="17" />
            </svg>
            <span>Note</span>
          </button>
        )}
        {showColors && (
          <button className="sel-action-btn" onClick={handleLink} title="Link">
            <svg viewBox="0 0 24 24">
              <path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71" />
              <path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71" />
            </svg>
            <span>Link</span>
          </button>
        )}
        <button className="sel-action-btn" onClick={copyText} title="Copy">
          <svg viewBox="0 0 24 24">
            <rect x="9" y="9" width="13" height="13" rx="2" ry="2" />
            <path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" />
          </svg>
          <span>Copy</span>
        </button>
        <button className="sel-action-btn" onClick={handleShare} title="Share">
          <svg viewBox="0 0 24 24">
            <circle cx="18" cy="5" r="3" />
            <circle cx="6" cy="12" r="3" />
            <circle cx="18" cy="19" r="3" />
            <line x1="8.59" y1="13.51" x2="15.42" y2="17.49" />
            <line x1="15.41" y1="6.51" x2="8.59" y2="10.49" />
          </svg>
          <span>Share</span>
        </button>
        <button className="sel-action-btn" onClick={handleSearch} title="Search">
          <svg viewBox="0 0 24 24">
            <circle cx="11" cy="11" r="8" />
            <line x1="21" y1="21" x2="16.65" y2="16.65" />
          </svg>
          <span>Search</span>
        </button>
        <button className="sel-action-btn" onClick={handleBookmark} title="Bookmark">
          <svg viewBox="0 0 24 24">
            <path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z" />
          </svg>
          <span>Bookmark</span>
        </button>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   TabsOverview — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function TabsOverview({ tabs, activeTabIdx, onSelect, onClose, onNewTab, onLongPress, onClearAll, clearAllStage, onDedupe, MAX_TABS, thumbnails }) {
  const total = tabs.length;
  const handleLongPress = React.useRef(null);
  const startLongPress = (idx) => (e) => {
    handleLongPress.current = setTimeout(() => {
      onLongPress && onLongPress(idx);
      handleLongPress.current = null;
    }, 520);
  };
  const cancelLongPress = () => {
    if (handleLongPress.current) {clearTimeout(handleLongPress.current);handleLongPress.current = null;}
  };
  // Count duplicates (same content signature) — surface the number on the button
  const dupeCount = React.useMemo(() => {
    const seen = new Map();
    let dupes = 0;
    tabs.forEach((t) => {
      const k = tabContentKey(t);
      if (seen.has(k)) dupes++;else
      seen.set(k, true);
    });
    return dupes;
  }, [tabs]);

  // Clear-All button mirrors the Mark-as-Read clear pattern: stage cycles
  // 0 → 1 → 2, matching label + color class. Tapping anywhere else in the
  // overview instantly resets stage back to 0.
  const clearLabelLocal = clearAllStage === 0 ? 'Clear All' : CLEAR_LABELS[clearAllStage];
  const clearClassLocal = CLEAR_CLASSES[clearAllStage];
  const resetClearOnOutsideTap = (e) => {
    if (clearAllStage > 0) onClearAll && onClearAll(-1); // -1 signals reset
  };
  return (
    <div className="tabs-overview" onClick={resetClearOnOutsideTap}>
      <div className="tabs-overview-header">
        <div className="tabs-overview-eyebrow">Reading Places</div>
        <h1 className="tabs-overview-title">Tabs</h1>
        <div className="tabs-overview-ornament">
          <div className="tabs-overview-ornament-line" />
          <div className="tabs-overview-ornament-diamond">{"✦"}</div>
          <div className="tabs-overview-ornament-line r" />
        </div>
        <div className="tabs-overview-meta">{total} / {MAX_TABS} {total === 1 ? 'tab' : 'tabs'} open</div>
        <div className="tabs-overview-actions">
          <button
            className={clearClassLocal}
            onClick={(e) => {e.stopPropagation();onClearAll();}}
            disabled={total <= 1 && clearAllStage === 0}
          >{clearLabelLocal}</button>
          <button
            className="tabs-action-btn"
            onClick={(e) => {e.stopPropagation();onDedupe();}}
            disabled={dupeCount === 0}
            title={dupeCount === 0 ? 'No duplicate tabs' : `Merge ${dupeCount} duplicate ${dupeCount === 1 ? 'tab' : 'tabs'}`}
          >Deduplicate{dupeCount > 0 ? ` · ${dupeCount}` : ''}</button>
        </div>
      </div>
      <div className="tabs-overview-grid">
        {tabs.map((t, i) => {
          const { title, subtitle } = describeTab(t);
          const scrollKey = scrollKeyForTab(t);
          const saved = t.scrollPositions && t.scrollPositions[scrollKey];
          const pctLive = saved == null ? 0 :
            typeof saved === 'object' && typeof saved.pct === 'number' ? saved.pct : 0;
          const isActive = i === activeTabIdx;
          const thumb = thumbnails ? thumbnails[tabContentKey(t)] : null;
          return (
            <div
              key={i}
              className={`tab-card${isActive ? ' active' : ''}${thumb ? ' has-thumb' : ''}`}
              onClick={() => onSelect(i)}
              onTouchStart={startLongPress(i)}
              onTouchEnd={cancelLongPress}
              onTouchMove={cancelLongPress}
              onMouseDown={startLongPress(i)}
              onMouseUp={cancelLongPress}
              onMouseLeave={cancelLongPress}
            >
              <button
                className="tab-card-close"
                onClick={(e) => {e.stopPropagation();onClose(i);}}
                title="Close tab"
                aria-label="Close tab"
              >{"\xD7"}</button>
              <div className="tab-card-thumb-wrap">
                {thumb
                  ? <img className="tab-card-thumb" src={thumb} alt="" />
                  : <div className="tab-card-thumb-placeholder">
                      <div className="tab-card-thumb-sigil">{"✦"}</div>
                    </div>
                }
                <div className="tab-card-thumb-scrim" />
              </div>
              <div className="tab-card-body">
                <div className="tab-card-eyebrow">Tab {i + 1} / {total}</div>
                <div className="tab-card-title">{title}</div>
                <div className="tab-card-subtitle">{subtitle}</div>
                {tabHasProgressBar(t) && (
                  <div className="tab-card-progress">
                    <div className="tab-card-progress-fill" style={{ width: `${Math.round(pctLive * 100)}%` }} />
                  </div>
                )}
              </div>
            </div>
          );
        })}
        {total < MAX_TABS && (
          <button
            className="tab-card tab-card-new"
            onClick={() => onNewTab()}
            title="New tab"
            aria-label="New tab"
          >
            <span className="tab-card-new-plus">+</span>
            <span className="tab-card-new-label">New Tab</span>
          </button>
        )}
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════════
   VersePickerScreen — Cluster D (esbuild bundle-d.js)
   ═══════════════════════════════════════════════════════════════════════ */

export function VersePickerScreen({ refineRequest, sourceKey, sourceLabel, sourceStart, sourceEnd, sourceText, setHlTick, onClose, returnTargetInsteadOfLink }) {
  const target = refineRequest.target;
  const item = refineRequest.item;
  const isStudy = target.type === 'study';
  const bodyRef = React.useRef(null);
  // Native-selection capture. Shape:
  //   { verseStart, verseEnd, charStart, charEnd, text }
  //   verseStart/verseEnd: verse numbers spanned
  //   charStart: offset within verseStart's text where the selection begins
  //   charEnd: offset within verseEnd's text where the selection ends
  //   text: the actual selected substring (used for preview + Journal excerpt)
  const [selInfo, setSelInfo] = React.useState(null);

  // Resolve chapter object
  const chapter = React.useMemo(() => {
    if (isStudy) {
      const M = _matthew();
      return M && M.chapters.find(c => c.num === target.chapter) || null;
    }
    const b = _allBooks()[target.bookId];
    return b && b.chapters.find(c => c.num === target.chapter) || null;
  }, [isStudy, target.bookId, target.chapter]);

  // Flat verses list — handles both Bible (sections[].verses[]) and study (verses[]) shapes
  const verses = React.useMemo(() => {
    if (!chapter) return [];
    if (chapter.verses) return chapter.verses;
    if (chapter.sections) return chapter.sections.flatMap(s => s.verses);
    return [];
  }, [chapter]);

  // Android back button goes back to LinkPicker (same save/restore pattern).
  React.useEffect(() => {
    const prev = window.__closeSheet;
    window.__closeSheet = () => onClose(null);
    return () => { window.__closeSheet = prev || null; };
  }, [onClose]);

  // captureSelectionSync — find the verse element(s) the user selected, build
  // a span descriptor with the actual selected text plus verse-level + char-
  // level offsets so downstream consumers (Journal excerpt, link overlay
  // renderer) can position the selection precisely.
  //
  // The verse num lives on the verse element's `data-verse` attribute. We
  // walk DOM Ranges to compute the char offset within the verse's text-only
  // content (which is the verse text excluding the leading "N " number span).
  const captureSelectionSync = React.useCallback(() => {
    const sel = window.getSelection();
    if (!sel || sel.isCollapsed || sel.rangeCount === 0) return null;
    const range = sel.getRangeAt(0);
    const startN = range.startContainer;
    const endN = range.endContainer;
    const startVerseEl = (startN.nodeType === 3 ? startN.parentElement : startN).closest('[data-verse]');
    const endVerseEl = (endN.nodeType === 3 ? endN.parentElement : endN).closest('[data-verse]');
    if (!startVerseEl || !endVerseEl) return null;
    if (!bodyRef.current || !bodyRef.current.contains(startVerseEl) || !bodyRef.current.contains(endVerseEl)) return null;
    const startVerse = parseInt(startVerseEl.getAttribute('data-verse'), 10);
    const endVerse = parseInt(endVerseEl.getAttribute('data-verse'), 10);
    // Offset within the verse's TEXT node (the `.picker-verse-text` span).
    function offsetWithinVerseText(verseEl, container, offset) {
      const textEl = verseEl.querySelector('.picker-verse-text');
      if (!textEl) return 0;
      const r = document.createRange();
      r.selectNodeContents(textEl);
      try {
        r.setEnd(container, offset);
      } catch (e) {
        // Selection endpoint sits outside the verse text (e.g. on the
        // verse-number span). Snap to 0 or verse-text length depending on
        // which side this is.
        return 0;
      }
      return r.toString().length;
    }
    let charStart = offsetWithinVerseText(startVerseEl, range.startContainer, range.startOffset);
    let charEnd = offsetWithinVerseText(endVerseEl, range.endContainer, range.endOffset);
    // Snap to word boundaries within each verse's text so trailing spaces
    // and partial words don't sneak into the excerpt.
    const startVText = (verses.find(v => v.n === startVerse) || {}).text || '';
    const endVText = (verses.find(v => v.n === endVerse) || {}).text || '';
    const snappedStart = snapRangeToWords(startVText, charStart, startVText.length).start;
    const snappedEndPos = snapRangeToWords(endVText, 0, charEnd).end;
    charStart = Math.max(0, Math.min(snappedStart, startVText.length));
    charEnd = Math.max(0, Math.min(snappedEndPos, endVText.length));
    return {
      verseStart: startVerse,
      verseEnd: endVerse,
      charStart: charStart,
      charEnd: charEnd,
      text: sel.toString()
    };
  }, [verses]);

  const captureSelection = React.useCallback(() => {
    setTimeout(function() {
      const info = captureSelectionSync();
      if (info) setSelInfo(info);
    }, 150);
  }, [captureSelectionSync]);

  const handleVerseTap = React.useCallback((vn) => {
    // Tap a verse number to quick-select the whole verse. Sets a synthetic
    // selInfo and visually selects the verse in the DOM so the user gets a
    // single-tap path that doesn't require drag-selection on mobile.
    const v = verses.find(x => x.n === vn);
    if (!v) return;
    setSelInfo({
      verseStart: vn,
      verseEnd: vn,
      charStart: 0,
      charEnd: (v.text || '').length,
      text: v.text || ''
    });
    // Clear any native selection so the visual is purely the .is-selected ring.
    try {
      const sel = window.getSelection();
      sel && sel.removeAllRanges && sel.removeAllRanges();
    } catch (e) {}
  }, [verses]);

  const confirmLink = React.useCallback(() => {
    const refinedTarget = { ...target };
    // Fall back to a fresh synchronous capture so a tap-confirm-faster-than-
    // 150ms doesn't lose the excerpt.
    const info = selInfo || captureSelectionSync();
    if (!info) { onClose(null); return; }
    const v1 = info.verseStart;
    const v2 = info.verseEnd;
    refinedTarget.verse = v1;
    if (v2 && v2 !== v1) refinedTarget.verseEnd = v2;
    const v1Obj = verses.find(v => v.n === v1) || null;
    const v2Obj = verses.find(v => v.n === v2) || null;
    const v1FullLen = v1Obj ? (v1Obj.text || '').length : 0;
    const v2FullLen = v2Obj ? (v2Obj.text || '').length : 0;
    const isPartialStart = info.charStart > 0;
    const isPartialEnd = info.charEnd < v2FullLen;
    const isPartial = isPartialStart || isPartialEnd;
    if (isPartial) {
      refinedTarget.charStart = info.charStart;
      refinedTarget.charEnd = info.charEnd;
      refinedTarget.partial = true;
    }
    // Storage key. Whole-verse spans keep the existing format (so link
    // overlays still wire up). Partial spans append a ':S-E' suffix where
    // S/E are flat-offset markers across the verse range.
    const verseFrag = v1 + (v2 && v2 !== v1 ? '-' + v2 : '');
    let baseKey;
    if (isStudy) {
      baseKey = 'study:' + target.bookId + '-' + target.chapter + ':' + verseFrag;
    } else {
      baseKey = bibleHlKey(target.bookId, target.chapter, v1) + (v2 && v2 !== v1 ? '-' + v2 : '');
    }
    refinedTarget.key = isPartial ? baseKey + ':' + info.charStart + '-' + info.charEnd : baseKey;
    const baseLabel = item.title || target.label.replace(/\s\d+(?::\d+(?:-\d+)?)?$/, '');
    refinedTarget.label = baseLabel + ' ' + target.chapter + ':' + verseFrag;
    refinedTarget.text = info.text;
    refinedTarget.preview = info.text || (v1Obj && v1Obj.text) || '';

    // Two call patterns:
    //   • Link mode (default): persist + bump hlTick + signal LinkPicker.
    //   • Journal/return mode: hand the refined target back to the caller
    //     via onClose so the Journal can create a verse-block from it.
    if (returnTargetInsteadOfLink) {
      onClose(refinedTarget);
      return;
    }
    const sourceEndpoint = buildSourceEndpoint(sourceKey, sourceLabel, sourceStart, sourceEnd, sourceText);
    const newLink = persistLink(sourceEndpoint, refinedTarget);
    if (newLink) setHlTick(t => t + 1);
    onClose(newLink || null);
  }, [selInfo, captureSelectionSync, target, item, isStudy, verses, sourceKey, sourceLabel, sourceStart, sourceEnd, sourceText, setHlTick, onClose, returnTargetInsteadOfLink]);

  if (!chapter) {
    return (
      <div className="picker-screen">
        <div className="picker-header">
          <button className="picker-back" onClick={() => onClose(null)} aria-label="Back">←</button>
          <span className="picker-title">Select Verse</span>
        </div>
        <div className="picker-empty">Chapter not found.</div>
      </div>
    );
  }

  const titleText = (item.title || target.label.replace(/\s\d+$/, '')) + ' ' + target.chapter;
  const hasSelection = !!selInfo;
  const previewText = selInfo ? (selInfo.text || '') : '';

  return (
    <div className="picker-screen">
      <div className="picker-header">
        <button className="picker-back" onClick={() => onClose(null)} aria-label="Back">←</button>
        <span className="picker-title">Select Text</span>
        <button
          className="picker-confirm"
          onClick={confirmLink}
          aria-label="Confirm"
          title={hasSelection ? "Use this excerpt" : "Use the whole chapter"}
        >
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.4" strokeLinecap="round" strokeLinejoin="round">
            <polyline points="20 6 9 17 4 12" />
          </svg>
        </button>
      </div>
      <div
        className="picker-body picker-body-letter"
        onTouchEnd={captureSelection}
        onMouseUp={captureSelection}
      >
        <div className="picker-letter-title">{titleText}</div>
        <div className="picker-letter-subtitle">{isStudy ? "Matthew Study Bible" : "Bible Chapter"}</div>
        <div
          className={"picker-selection-hint" + (hasSelection ? "" : " picker-selection-hint-empty")}
        >{hasSelection
          ? previewText
          : "Highlight any portion to link. Or tap a verse number to grab the whole verse."
        }</div>
        <div ref={bodyRef} className="picker-verses">
          {verses.map(v => (
            <p
              key={v.n}
              className="picker-verse-selectable"
              data-verse={v.n}
            >
              <span
                className="picker-verse-num"
                onClick={function(e) { e.stopPropagation(); handleVerseTap(v.n); }}
              >{v.n + " "}</span>
              <span className="picker-verse-text">{v.text}</span>
            </p>
          ))}
        </div>
      </div>
    </div>
  );
}
